-- Poems batch 103
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('5114c675-aa84-4c6e-bc8d-9e7ab263ee5a','荔支七絕 大將軍','王十朋','宋','宋诗','song-poetry','','[]','荔支名字太紛紛，所見多應不逮聞。',32,'全唐诗/poet.song.119000.json','["荔支名字太紛紛，所見多應不逮聞。", "別有深紅覇群品，郡人呼作大將軍。"]'),
('97a9fb2f-f8d4-4d98-aaac-e43d317f2e0c','荔支七絕 玉堂紅','王十朋','宋','宋诗','song-poetry','','[]','天教尤物産閩中，名字深奇日不同。',32,'全唐诗/poet.song.119000.json','["天教尤物産閩中，名字深奇日不同。", "顧我素稱田舍子，如何敢啗玉堂紅。"]'),
('3371816a-e435-4e24-92b1-53e92569c878','中山立秋','宋祁','宋','宋诗','song-poetry','','[]','峰雲曉影破孱顔，萬里風生結早寒。',64,'全唐诗/poet.song.12000.json','["峰雲曉影破孱顔，萬里風生結早寒。", "人在兜零煙外走，歲從鶗鴂口中殘。", "槽花併滴添新酎，笥月兼輪掩故紈。", "白髮光陰誠可惜，五年搔首望長安。"]'),
('36aa4d88-7793-43bb-a960-41509bbd35ae','二月十八日席上憶季長未還不同斯樂欲作詩寄之會使者來已有新章今牽連成篇拜呈上','宋祁','宋','宋诗','song-poetry','','[]','煙壓西郊雨壓津，滿城歌吹爲芳辰。',64,'全唐诗/poet.song.12000.json','["煙壓西郊雨壓津，滿城歌吹爲芳辰。", "江形左右衣留带，柳色高低麴與塵。", "暖逼園花迎望密，曉催林鳥每啼新。", "知君貪擁光華節，未有尊前共惜春。"]'),
('4af56e81-4c46-472f-ab03-f63a54808b07','閏九月九日登高有感','宋祁','宋','宋诗','song-poetry','','[]','隔霜雲葉繞天愁，閏節重來續舊遊。',64,'全唐诗/poet.song.12000.json','["隔霜雲葉繞天愁，閏節重來續舊遊。", "賦客豈辭聊暇日，楚人無奈賸悲秋。", "寒萸實老猶薰佩，晚菊香殘不占甌。", "悵憶故園歸信斷，渚鴻川鯉兩悠悠。"]'),
('7fdb5edd-3b8e-48c2-8398-c23de4de6a67','寄公序兄資政給事','宋祁','宋','宋诗','song-poetry','','[]','再分銅虎滯侯藩，別後兼聞素領繁。',64,'全唐诗/poet.song.12000.json','["再分銅虎滯侯藩，別後兼聞素領繁。", "契闊不成騑服馬，急難空念脊令原。", "壯心干鏌年年鈍，世路風波衮衮翻。", "韁鎖虛名應只爾，早同私駕老邱樊。"]'),
('9a1750aa-f842-4f14-9476-82f49f9d2762','春宴行樂家園','宋祁','宋','宋诗','song-poetry','','[]','園芿初乾小雨泥，飲壺遊屐況親携。',64,'全唐诗/poet.song.12000.json','["園芿初乾小雨泥，飲壺遊屐況親携。", "身輕早蝶千回舞，技癢新禽百種啼。", "乘暖草茵侵坐軟，畏風桃綬向林低。", "陽暉自有留人意，銜照高樓未遽西。"]'),
('e10329d8-3b4c-4347-971e-daaec2908b9f','病間答雜端龐淳之見寄','宋祁','宋','宋诗','song-poetry','','[]','廓落彌旬故眼移，居慚君粟養支離。',64,'全唐诗/poet.song.12000.json','["廓落彌旬故眼移，居慚君粟養支離。", "綾衾倦夢愁淹卧，星鬢流年報早衰。", "藥劑袪繁催月杵，茗腴供啜嗜春旗。", "迷魂復幹聞清唱，不減巫陽筮些詩。"]'),
('9ddce985-44c1-45d5-96f6-02f57fc94d0f','真定述事','宋祁','宋','宋诗','song-poetry','','[]','莫嫌屯壘是邊州，試聽河山說上游。',64,'全唐诗/poet.song.12000.json','["莫嫌屯壘是邊州，試聽河山說上游。", "帳下文書三幕府，馬前韡靺五諸侯。", "王藩故社經除國，俠窟餘風解報仇。", "四十年來民緩带，使君何事不輕裘。"]'),
('ee2bc609-1a0d-411a-9192-18b8c5d5af2f','博州駱太保','宋祁','宋','宋诗','song-poetry','','[]','關榆秋舞折膠風，坐嘯邊陴憶九重。',64,'全唐诗/poet.song.12000.json','["關榆秋舞折膠風，坐嘯邊陴憶九重。", "宴榭綠醅春沸蟻，連營清角暮吟龍。", "幕中鏤管閒陳檄，塞下兜零罷漢烽。", "計日民謠諠魏闕，褒功僊劄武泥封。"]'),
('dc678e5f-4701-47bf-8c08-54a089aa1446','春曉感別','宋祁','宋','宋诗','song-poetry','','[]','樓外疏鐘落曉河，天涯感別思煙波。',64,'全唐诗/poet.song.12000.json','["樓外疏鐘落曉河，天涯感別思煙波。", "三年客鯉傳書遠，五丈星機得素多。", "溝水東流勞想像，峽靈西去隔嵯峨。", "良辰自古難并樂，不獨驪駒送客歌。"]'),
('2fab0432-fc88-466b-8638-93269ee4f142','有懷謝炳宗先輩','宋祁','宋','宋诗','song-poetry','','[]','凄霜刮野轉蓬乾，永憶江湖旅鬢殘。',64,'全唐诗/poet.song.12000.json','["凄霜刮野轉蓬乾，永憶江湖旅鬢殘。", "身有支離求病粟，爵無公乘免旒冠。", "柴車路迥驂馿蹇，栗塢人稀溜鵲寒。", "日暮浮雲徧西北，客心悽斷向長安。"]'),
('e9dfcfb0-e26b-4a52-afda-22f14b7f62b8','有懷寄同舍','宋祁','宋','宋诗','song-poetry','','[]','不爲秋歸人未歸，淮南又見葉丹時。',64,'全唐诗/poet.song.12000.json','["不爲秋歸人未歸，淮南又見葉丹時。", "漢皇好少身今老，楚客愁醒啜始醨。", "夕棧長風驚代馬，曉天團露怨江蘺。", "夫君去我猶千里，萬慮勞勞欲語誰。"]'),
('8e64fff7-5371-41fa-88f7-3ab2abd92f3d','有懷宮保龐相公','宋祁','宋','宋诗','song-poetry','','[]','木正乘春肯告勞，併持葱鬰護神臯。',64,'全唐诗/poet.song.12000.json','["木正乘春肯告勞，併持葱鬰護神臯。", "曉風遞暖何妨細，宿雨留雲未許高。", "向密垂楊能礙箭，鬭長芳草欲爭袍。", "東城勝具應撩治，就趁尋花作宴醪。"]'),
('28fdeada-4f45-459b-b94c-cc25a2d6def4','漢南州按行江涘以詩見寄','宋祁','宋','宋诗','song-poetry','','[]','側帽風輕過大堤，水村驕馬惜障泥。',64,'全唐诗/poet.song.12000.json','["側帽風輕過大堤，水村驕馬惜障泥。", "前驅夾道旟開隼，合宴傳飧帳繞犀。", "凈練寒江供望闊，赤萍圓日對吟低。", "輕筒絡繹傳清唱，知在春煙幾曲溪。"]'),
('0f83c468-d435-41b1-835b-c37d3892be46','和丞相晨謁書所見','宋祁','宋','宋诗','song-poetry','','[]','北闕天深報漏遲，臺鸞雍鷺共逶迤。',64,'全唐诗/poet.song.12000.json','["北闕天深報漏遲，臺鸞雍鷺共逶迤。", "廷風細引趨班佩，宮日遥烘簇仗旗。", "侍史有香來洞案，直郎無奏伏丹墀。", "殊鄰競獻朝正玉，定是東風入律時。"]'),
('79b40ec5-a94f-4dca-9846-9398ce0df549','答天台梵才吉公寄茶并長句','宋祁','宋','宋诗','song-poetry','','[]','山中啼鳥報春歸，陰閬陽墟翠已滋。',64,'全唐诗/poet.song.12000.json','["山中啼鳥報春歸，陰閬陽墟翠已滋。", "初筍一槍知探候，亂花三沸記烹時。", "佛天甘露流珍遠，帝輦仙漿待汲遲。", "飫罷翛然誦清句，赤城霞外想幽期。"]'),
('d048aab9-53f0-4f77-a694-990e90390fe6','貴溪周懿文寄遺建茶偶成長句代謝','宋祁','宋','宋诗','song-poetry','','[]','茗篋緘香自武夷，陸生家果最相宜。',64,'全唐诗/poet.song.12000.json','["茗篋緘香自武夷，陸生家果最相宜。", "烹憐晝鼎花浮柵，採憶春山露滿旗。", "品絕未甘奴視酪，啜清須要玉爲瓷。", "茂陵渴肺消無幾，爭奈還書苦思遲。"]'),
('e46c1d64-0d9e-4cb2-8011-2b1895dd4c6e','春日出浣花溪','宋祁','宋','宋诗','song-poetry','','[]','側蓋天長蕩曉霏，暖風纔滿使君旗。',64,'全唐诗/poet.song.12000.json','["側蓋天長蕩曉霏，暖風纔滿使君旗。", "水通江渚容魚樂，草徧山梁報雉時。", "場雨滅塵盤馬疾，樓雲礙曲進觴遲。", "少陵宅畔吟聲歇，柳碧梅青欲向誰。"]'),
('93fc27c6-5f90-42dc-a2b0-8ba9e79a8555','送貴溪尉周懿文先輩','宋祁','宋','宋诗','song-poetry','','[]','幾日銓符給詔程，賜袍如草滯僚英。',64,'全唐诗/poet.song.12000.json','["幾日銓符給詔程，賜袍如草滯僚英。", "大言久廢三千奏，倦曲難終一再行。", "吳蟹沈波秋稻富，海魚藏穴夜潮平。", "待君削牘登文石，趣與淵雲繼頌聲。"]'),
('2f6708ca-c6a0-4b32-82b3-f6de196ac3ce','題漣水軍豹隠堂','宋祁','宋','宋诗','song-poetry','','[]','當年齋榻豫章才，自領驂驔五馬回。',64,'全唐诗/poet.song.12000.json','["當年齋榻豫章才，自領驂驔五馬回。", "庭下書筠多舊刻，檐間賀燕是重來。", "吟池墨久將成溜，坐石星殘欲徧苔。", "郡閣從今傳盛事，更留寒霧記巖隈。"]'),
('3c33bdf2-e5c5-4b34-86b3-4445404f953f','寄獻淮陽陳相公','宋祁','宋','宋诗','song-poetry','','[]','翹才閣下舊賓游，偶得魚符擁使輈。',64,'全唐诗/poet.song.12000.json','["翹才閣下舊賓游，偶得魚符擁使輈。", "本自爐鎚依大冶，敢言鎗脚是鄰州。", "頻年廢忘拋黄卷，此地優閒養白頭。", "漫引雙旌非敏政，餘波須仰富民侯。"]'),
('87e7c3cf-e968-4251-a84c-1918704402b6','游白兆山寺','宋祁','宋','宋诗','song-poetry','','[]','地枕層岑面勢斜，蔽虧原隰在烟霞。',64,'全唐诗/poet.song.12000.json','["地枕層岑面勢斜，蔽虧原隰在烟霞。", "璇題衒目三休閣，寶樹沿雲四照花。", "結社高風思惠遠，忘言真理寄毗邪。", "銅蓮漏永螟風細，不覺西陂轉若華。"]'),
('a3228b37-639f-4831-a2fc-c9dff0ed4a98','寄令狐揆二首  其一','宋祁','宋','宋诗','song-poetry','','[]','楚山千疊隠南轅，漢渚風檣箭浪翻。',64,'全唐诗/poet.song.12000.json','["楚山千疊隠南轅，漢渚風檣箭浪翻。", "流水東西俱怨別，離亭長短共銷魂。", "歌翻白雪知難和，注怯黄金故易昏。", "玉骨更羸詩筆苦，客裾猶欲曳何門。"]'),
('03853ed6-4cab-4c98-ae1e-a1041d21c185','寄令狐揆二首  其二','宋祁','宋','宋诗','song-poetry','','[]','紫漢參橫宿霧收，煙江南渡悵夷猶。',64,'全唐诗/poet.song.12000.json','["紫漢參橫宿霧收，煙江南渡悵夷猶。", "夢中未省能知路，天上何緣許寄愁。", "豈有文鱗憑遠客，枉緣香杜怨芳洲。", "遥知花艷驚郎目，幾曲新詩播郢樓。"]'),
('2e083ebf-0990-4143-87bf-6875d446821b','寄郭仲微','宋祁','宋','宋诗','song-poetry','','[]','自君入佐張蒼計，直室深扃老氏關。',64,'全唐诗/poet.song.12000.json','["自君入佐張蒼計，直室深扃老氏關。", "顧我偶陪螭陛立，無人並駕鹿車還。", "紅牙幹利資良畫，縹帙勞功積厚顔。", "幾日歸休期一笑，新醪浮白早黎殷。"]'),
('e5176653-5abd-4da0-840d-a7756ea76b60','寄河東按察待制施正臣','宋祁','宋','宋诗','song-poetry','','[]','并門迢遞駕朱輪，紫橐宮毫晦隙塵。',64,'全唐诗/poet.song.12000.json','["并門迢遞駕朱輪，紫橐宮毫晦隙塵。", "幾眼带移貪事國，半生桐老苦傷春。", "比來置酒觴何屬，自此驚秋髮恐新。", "鼇署病夫期自代，眼中徧憶未歸人。"]'),
('59462223-e29c-4b91-88da-daa4a550b7c8','寄鄭天休','宋祁','宋','宋诗','song-poetry','','[]','翹車交辟滯東南，盤蕙多年歇賜衫。',64,'全唐诗/poet.song.12000.json','["翹車交辟滯東南，盤蕙多年歇賜衫。", "千日醉醒孤共酌，一書開閉遂空函。", "怨歸定對王孫草，無恙應隨散騎帆。", "傾聽囊帷奏嘉頌，清時寧忌絳侯讒。"]'),
('98157980-8fec-4773-a45f-59406387a181','見寄','宋祁','宋','宋诗','song-poetry','','[]','雲梯叱馬賦西征，滿歲無功答盛明。',64,'全唐诗/poet.song.12000.json','["雲梯叱馬賦西征，滿歲無功答盛明。", "收得桑榆真晚計，倚爲箕斗是空名。", "瘢逢美玉終能治，曲訴幺絃久未平。", "壯思雖衰猶得在，一篇申甫爲公成。"]'),
('ead4b7d3-6a9c-446f-a3a8-693c76cbf3c7','次韵天平觀文龐相公以久留塞下見寄','宋祁','宋','宋诗','song-poetry','','[]','昔駕軺封北護邊，已慚星鬢久凋年。',64,'全唐诗/poet.song.12000.json','["昔駕軺封北護邊，已慚星鬢久凋年。", "御爐香外拋晨謁，刁斗聲中廢夜眠。", "梁雪送殘他日賦，郭舟誰共此時仙。", "思歸未敢貽公念，更辦秋懷敵露蟬。"]'),
('591152fa-8573-4780-8b0b-e2fb8b8459ff','邑外晚景','宋祁','宋','宋诗','song-poetry','','[]','林梢規日透霞鮮，滯穗纍纍徧大田。',64,'全唐诗/poet.song.12000.json','["林梢規日透霞鮮，滯穗纍纍徧大田。", "豺口祭餘開獵禁，豚蹄祝罷得逢年。", "雲容不動寒垂地，陂影無涯靜合天。", "一國似狂予獨爾，長吟饑腹伴殘蟬。"]'),
('d99febcb-367a-48d2-ac39-e57775e4f113','贈吳太博二首  其一','宋祁','宋','宋诗','song-poetry','','[]','銀兔頻年滯使麾，曲臺猶掌一王儀。',64,'全唐诗/poet.song.12000.json','["銀兔頻年滯使麾，曲臺猶掌一王儀。", "四巡奏頌推嚴筆，千牘程書入漢帷。", "駟里飛觴酣玉液，天街疊鼓候金羈。", "前期侍從丹塗地，秘殿螟風拂翠緌。"]'),
('67fb7162-216a-4c9f-a429-aff206a568d3','贈吳太博二首  其二','宋祁','宋','宋诗','song-poetry','','[]','月轉觚稜玉樹齊，通宵歸夢繞金閨。',64,'全唐诗/poet.song.12000.json','["月轉觚稜玉樹齊，通宵歸夢繞金閨。", "柔桑密映秦樓騎，溫詔香懷漢署泥。", "殺簡載書傳祖德，懷金酌水賦新題。", "丹楓七澤朝天路，丈組垂腰蕊佩低。"]'),
('35397d7e-455b-4a77-8f02-23589db46bac','送李芝還舊隠','宋祁','宋','宋诗','song-poetry','','[]','章冠慣趁舞雩春，屬疾彌年素産貧。',64,'全唐诗/poet.song.12000.json','["章冠慣趁舞雩春，屬疾彌年素産貧。", "舊隠却招三徑菊，歸裝不受九街塵。", "平時戲服歡爲綵，日後迎蒲待裹輪。", "天下書生皆皓首，牛溪休訪續經人。"]'),
('ef62d55a-e579-45c8-8676-c2726fd1c1b2','答戶部勾院王學士泊滄陵見寄','宋祁','宋','宋诗','song-poetry','','[]','峭帆風罷到淮瀕，草草停橈一問津。',64,'全唐诗/poet.song.12000.json','["峭帆風罷到淮瀕，草草停橈一問津。", "大小山前懷古地，短長亭下未歸人。", "林姿暗淡吞霞彩，浪壘光芒受月輪。", "尚憶他年故儔在，擘牋題作郢中春。"]'),
('d22fa9e8-64b4-4795-bfed-0657921b4a8e','送段秘丞同理金陵','宋祁','宋','宋诗','song-poetry','','[]','赭丹濡筆獄無冤，佐守初依鳳沼蓮。',64,'全唐诗/poet.song.12000.json','["赭丹濡筆獄無冤，佐守初依鳳沼蓮。", "南土出藩申伯寵，辟書爲首嗣宗賢。", "蟠龍運厭山圍國，燬角宵凉水際天。", "哲輔定知三入相，期君同赴渭濱畋。"]'),
('0f8d71a7-cd39-4ff0-81d0-44363f3fad34','送張清臣學士省侍金陵','宋祁','宋','宋诗','song-poetry','','[]','仙閣三休紫霧平，金門試罷得蒸青。',64,'全唐诗/poet.song.12000.json','["仙閣三休紫霧平，金門試罷得蒸青。", "同時第賦留宸幄，他日聞時戀相庭。", "逗箭夕流催檜楫，賜花春豫憶雲屏。", "吳天此夜瞻台座，併是荀家父子星。"]'),
('6aae282b-7439-4547-aa37-e2f52bf11212','送簡殿丞赴闕','宋祁','宋','宋诗','song-poetry','','[]','共治清淮北面州，何言分袂帳夷猶。',64,'全唐诗/poet.song.12000.json','["共治清淮北面州，何言分袂帳夷猶。", "君還南闕雙龍下，我駐東方千騎頭。", "未落林花延別醑，無窮隄草伴行舟。", "懷人愬月勞勞意，自此相牽更倚樓。"]'),
('fb82dd95-2cb2-4fd1-954c-5ee2acb2e87f','祗答提舉觀文丁右丞','宋祁','宋','宋诗','song-poetry','','[]','懇辭金殿得班春，藁篋相從素瀨濱。',64,'全唐诗/poet.song.12000.json','["懇辭金殿得班春，藁篋相從素瀨濱。", "坐閣仍題修史筆，去鄉猶是受經人。", "浮雲富貴心知厭，淡水交游老更新。", "三嘆來章深意在，肯容冠綬久生塵。"]'),
('2e607e81-6bde-46e8-8ca2-56bcb163907e','病告作寄武平湖內翰','宋祁','宋','宋诗','song-poetry','','[]','病擁綈袍雪領垂，當關重疊報晨暉。',64,'全唐诗/poet.song.12000.json','["病擁綈袍雪領垂，當關重疊報晨暉。", "夷吾畏事將成吃，蘧瑗增年轉悟非。", "宦路風波頻歲劇，故山薇蕨每春肥。", "餘生正似風前鷁，慚負陽秋說退飛。"]'),
('95bfc652-0f68-4a9a-96d0-0739f4882327','九日宴射','宋祁','宋','宋诗','song-poetry','','[]','佳節憑高駐綵旗，亭臯霧罷轉晨曦。',64,'全唐诗/poet.song.12000.json','["佳節憑高駐綵旗，亭臯霧罷轉晨曦。", "堋間羽集號猿後，臺外塵飛戲馬時。", "芳菊治疴爭泛蕊，丹萸解惡徧傳枝。", "明年此會知何處，醉玉頹山不用辭。"]'),
('17853dc8-821a-4546-b2f7-dd4d9317bc4d','孫集仙世領東海','宋祁','宋','宋诗','song-poetry','','[]','雲岊蒼鬰照城郛，奕葉鄉州擁使符。',64,'全唐诗/poet.song.12000.json','["雲岊蒼鬰照城郛，奕葉鄉州擁使符。", "晝繡愈知今日貴，子庭猶憶向時趨。", "故新笥綬薰相續，前後郊棠影不孤。", "絳帳諸生今史氏，炙青容補世家無。"]'),
('1d9ac9ec-259a-429d-af5e-73eedd080a0e','慶曆初召爲學士歲餘罷久之出守凡三十年還拜承旨感而成詠','宋祁','宋','宋诗','song-poetry','','[]','十八年前玷玉堂，當時綠髮此蒼蒼。',64,'全唐诗/poet.song.12000.json','["十八年前玷玉堂，當時綠髮此蒼蒼。", "傷禽縱奮愁瘡重，廄馬雖還笑齒長。", "薰罷山爐飄暗燼，漱餘銅碗冰寒漿。", "須慚清切鑾坡地，不是吾人得性場。"]'),
('e4bcdfa5-3377-4da4-ad5a-c97a7e86df6d','送荆湖北漕張職方','宋祁','宋','宋诗','song-poetry','','[]','賜對雲簾幾刻留，東南公利入牙籌。',64,'全唐诗/poet.song.12000.json','["賜對雲簾幾刻留，東南公利入牙籌。", "方船萬粟浮江下，封府三錢出地流。", "驛路塵清迎弩密，省臺薰歇護衣愁。", "不妨徧歷騷人國，金橘丹楓互占秋。"]'),
('a63577d5-4808-4f09-b80d-e6cdc6173bc9','送殿院張奎漕京東','宋祁','宋','宋诗','song-poetry','','[]','霜栢輕寒驚曙烏，使臺東道亞風旟。',64,'全唐诗/poet.song.12000.json','["霜栢輕寒驚曙烏，使臺東道亞風旟。", "人瞻御史乘驄貴，錢續司農朽貫餘。", "睢苑千門聊按節，齊官三服罷移書。", "此行須信褒恩美，新詔黄金飾佩餘。"]'),
('d60d1fd4-68de-48a2-b3eb-761ad4797ce9','淵宗郎中移利州路漕','宋祁','宋','宋诗','song-poetry','','[]','列騶傳鬨避軺車，天角橫參帳飲餘。',64,'全唐诗/poet.song.12000.json','["列騶傳鬨避軺車，天角橫參帳飲餘。", "即日前驅催負弩，幾旬論報罷移書。", "賜山故冶流錢外，燒棧新郵轉粟初。", "使選愈華身尚遠，喜榮嗟滯兩何如。"]'),
('604cef18-d44f-433c-a30a-aede3bf23684','初入蜀州閣道作','宋祁','宋','宋诗','song-poetry','','[]','緣雲棧脚轉嵯峨，使者重來叱馭過。',64,'全唐诗/poet.song.12000.json','["緣雲棧脚轉嵯峨，使者重來叱馭過。", "杜宇有冤啼夜月，女蘿憑鬼護山阿。", "巖深樹氣埋蒼霧，峽窄江形束素波。", "自問一春行役苦，带環移眼奈衰何。"]'),
('5685ce75-c97b-426b-928f-46394becfd20','早春出近郊','宋祁','宋','宋诗','song-poetry','','[]','迴望三條接上蘭，野霏山秀似堪餐。',64,'全唐诗/poet.song.12000.json','["迴望三條接上蘭，野霏山秀似堪餐。", "冰翻斷影回魚暖，雲作輕陰借雁寒。", "即席縹清宜玉斝，何人蘇合費金丸。", "風長麥淺如臯路，雉子斑斑錦羽乾。"]'),
('2ce6e5f2-dba0-4173-a2f8-48485dfa6fb0','出次近郊','宋祁','宋','宋诗','song-poetry','','[]','江練東南楚塞長，野烟寒氣共蒼茫。',64,'全唐诗/poet.song.12000.json','["江練東南楚塞長，野烟寒氣共蒼茫。", "局轅班馬思長道，攫肉饑烏下夕陽。", "旅舍樵蘇勞後爨，農家簦笠遠相望。", "坐觀民瘼無他畫，庭列貆鶉目眩觴。"]'),
('ee801565-ff2a-4263-b6e4-94b8588f0d8d','寄襄陽觀徐師','宋祁','宋','宋诗','song-poetry','','[]','日夕高陽釂羽杯，琳房岑寂外塵埃。',64,'全唐诗/poet.song.12000.json','["日夕高陽釂羽杯，琳房岑寂外塵埃。", "山庭桂老幽人住，天陸星翻處士回。", "珍樹暝猿侵戶嘯，碧潭僊菊照窗開。", "箕風動地雲羅闊，誰伴凌空禦寇來。"]'),
('f4c7c5f5-cee3-48c0-88cc-27453d2d671c','和季長學士綿漢道中作','宋祁','宋','宋诗','song-poetry','','[]','一轡澄清暫按州，却因風景獨夷猶。',64,'全唐诗/poet.song.12000.json','["一轡澄清暫按州，却因風景獨夷猶。", "弦殘漢月騶前曉，粉疊巴雲蓋外秋。", "持節頻年煩出使，富民虛日待封侯。", "省紆麗藻嗟行役，正恐才多剩四愁。"]'),
('3e8f6243-af26-4d74-99f1-54442e259ac8','得揚州書','宋祁','宋','宋诗','song-poetry','','[]','四郡連翩擁使旗，多年不聽汝南雞。',64,'全唐诗/poet.song.12000.json','["四郡連翩擁使旗，多年不聽汝南雞。", "宴開河朔千人帳，書用黎陽一襆泥。", "水曲箭波喧夜櫓，原田絲雨勸春犂。", "可嗟未預元規論，坐據胡牀送月低。"]'),
('f7dd73ff-0087-444d-9bbd-3ef7ad98f23f','送韓廷評婺州市征','宋祁','宋','宋诗','song-poetry','','[]','去程烟草妬藍袍，越絕天文寶婺高。',64,'全唐诗/poet.song.12000.json','["去程烟草妬藍袍，越絕天文寶婺高。", "五兩樵風船畫鷁，九秋犀燭鷺翻濤。", "吳鹽煮海通關賦，陸橐收金析利毫。", "仙酎油囊鱸鱠潔，未妨餘暇左持螯。"]'),
('c5712376-b98b-4f47-818a-83155924e673','楊備永嘉市征','宋祁','宋','宋诗','song-poetry','','[]','漢祀壇邊望畫衣，故人杯酒怨歌驪。',64,'全唐诗/poet.song.12000.json','["漢祀壇邊望畫衣，故人杯酒怨歌驪。", "幾枝北道梅傳信，一味南方桂補羸。", "後雨蒸青貽素業，舊塘生草繼妍辭。", "他年第頌歸何處，名應唐家十二時。"]'),
('4a05675a-24ef-4053-a971-906f22886bf6','祗答相國龐公將至并部馬上垂寄','宋祁','宋','宋诗','song-poetry','','[]','大旆前驅拂晉雲，寒天迎望靜無氛。',64,'全唐诗/poet.song.12000.json','["大旆前驅拂晉雲，寒天迎望靜無氛。", "幄中舊借留侯筯，麾下今分鄧禹軍。", "馳屬櫜鞬隨指顧，賣殘刀劍事耕耘。", "據鞍抒思真餘力，又占風騷第一勳。"]'),
('caa01304-6c21-4d1f-86ad-0ec16e18f3ec','得杭州鄭資政書','宋祁','宋','宋诗','song-poetry','','[]','誤拋荷橐別雲裘，天賜疏慵卧治州。',64,'全唐诗/poet.song.12000.json','["誤拋荷橐別雲裘，天賜疏慵卧治州。", "轅下已疲猶戀主，道邊寧死不爲鈎。", "風波路惡驚危涕，蓬葆年侵變黑頭。", "獨喜故人恩契厚，冷灰遺甑遠相求。"]'),
('2e03e9e7-fb34-4967-a491-4b94fabc98c6','予既到郡有詔仍修唐書寄局中諸僚','宋祁','宋','宋诗','song-poetry','','[]','一章通奏領州麾，詔許殘書得自隨。',64,'全唐诗/poet.song.12000.json','["一章通奏領州麾，詔許殘書得自隨。", "吾黨成章真小子，官中了事是癡兒。", "昏眸病入花爭亂，倦首搔餘雪半垂。", "所頼韋吳皆傑筆，劉生當見汗青期。"]'),
('d0ae76c4-0738-4c54-b9e5-bfabca840e65','雲夢李使者','宋祁','宋','宋诗','song-poetry','','[]','關征盤錯带南州，三見丹楓墜楚秋。',64,'全唐诗/poet.song.12000.json','["關征盤錯带南州，三見丹楓墜楚秋。", "列侍百重圍虎戟，酣歌丈八憶蛇矛。", "草生宵夢傳詩筆，梅析春酲託使郵。", "矍鑠據鞍休自歎，壁門初日待鳴騶。"]'),
('ce4a90ac-c166-479c-8bef-af48fc9782bc','西征道中寄友人','宋祁','宋','宋诗','song-poetry','','[]','賦就江亳一黯然，柳衰猶足代征鞭。',64,'全唐诗/poet.song.12000.json','["賦就江亳一黯然，柳衰猶足代征鞭。", "鮫盤恨極無餘涕，鵾瑟悲多有剩絃。", "斜日楚楓低候雁，早霜秦樹送殘蟬。", "文章滿腹真何益，深愧囊中趙壹錢。"]'),
('0aaa7173-6fca-40b6-baa5-eef7999bd716','南亭獨矚','宋祁','宋','宋诗','song-poetry','','[]','宇下雄風細細凉，客眸凝絕此回腸。',64,'全唐诗/poet.song.12000.json','["宇下雄風細細凉，客眸凝絕此回腸。", "絡頭騎過羅敷陌，畢尾烏喧女子牆。", "流水清渾迷別浦，碧雲高下送殘陽。", "懷人撫物愁何盡，試借蘭成萬斛量。"]'),
('0d607fcc-3622-438e-849d-43439e3eda27','題羅江翠望亭兼簡西游君子','宋祁','宋','宋诗','song-poetry','','[]','暫解征鞍息使郵，孤亭望斷更夷猶。',64,'全唐诗/poet.song.12000.json','["暫解征鞍息使郵，孤亭望斷更夷猶。", "山從劍北呈天險，樹徧巴西送客愁。", "拂衽風和循幌入，濯纓江好近人流。", "憑君且作剛腸憶，懷遠思歸易白頭。"]'),
('a69bedf5-2f50-4a0d-bd25-59a36d333017','自訟  其一','宋祁','宋','宋诗','song-poetry','','[]','史藁雖殘得自隨，兵符未解定堪蚩。',64,'全唐诗/poet.song.12000.json','["史藁雖殘得自隨，兵符未解定堪蚩。", "淹留正似周南老，戲劇何爭灞上兒。", "鉛筆用多毛禿落，鬢髯愁罷雪紛垂。", "十年尚滯成書奏，可驗相如屬思遲。"]'),
('dd87bf4a-ae59-4e2c-91db-5539d675670d','自訟  其二','宋祁','宋','宋诗','song-poetry','','[]','有人多病卧遥帷，誤舍寒耕失故畦。',64,'全唐诗/poet.song.12000.json','["有人多病卧遥帷，誤舍寒耕失故畦。", "每畏賓朋嘲乘雁，寧教子弟愛家雞。", "淹中學廢心都塞，轅下鳴餘耳更低。", "自顧上恩無一報，何顔歲晚望金閨。"]'),
('422aaa27-37df-4d9f-bfe5-e1ee389df53c','自訟  其三','宋祁','宋','宋诗','song-poetry','','[]','坐氈無客凍鴟愁，談樹蕭然兩見秋。',64,'全唐诗/poet.song.12000.json','["坐氈無客凍鴟愁，談樹蕭然兩見秋。", "執戟不知身寂寞，寫書猶得罪風流。", "官閒無日慚軒鶴，機盡多年謝海鷗。", "借問殿科能免否，杜陵男子有耕疇。"]'),
('9e1b0edf-078e-46f6-9aaa-b242c38fd704','欲棲烏','宋祁','宋','宋诗','song-poetry','','[]','湘竿風急未成棲，御史臺前見落暉。',64,'全唐诗/poet.song.12000.json','["湘竿風急未成棲，御史臺前見落暉。", "桂冷欲依秦氏宿，柳深先望白門歸。", "迎秋別恨填銀漢，未夜啼聲怨玉徽。", "悵望西樓珪月滿，惜君猶更向南飛。"]'),
('1dab3aaa-2717-43c7-bb6c-d275ec175fab','早發途中','宋祁','宋','宋诗','song-poetry','','[]','六幕星翻斗轉車，攬衣王粲更離家。',64,'全唐诗/poet.song.12000.json','["六幕星翻斗轉車，攬衣王粲更離家。", "孤城隨月三撾鼓，碧樹啼烟九子鴉。", "獨望殘雲愁霰雪，暫聞長笛憶京華。", "霞朝莫問離懷苦，带眼愁多只有賒。"]'),
('58a53920-6910-46c0-ae05-6649ece9653a','喜雨','宋祁','宋','宋诗','song-poetry','','[]','陰霞襲曉混層暉，雨勢連天泱泱垂。',64,'全唐诗/poet.song.12000.json','["陰霞襲曉混層暉，雨勢連天泱泱垂。", "潑火正投寒食日，催耕併及杏花時。", "波生客浦揚舲遠，潤逼宵撾作摻遲。", "把酒命賓聊一笑，吾農喜罷及吾私。"]'),
('52e194e5-fd63-4163-adc8-06d83bbe0589','晚春有感','宋祁','宋','宋诗','song-poetry','','[]','試上高臺望綠蕪，一春芳意向人疏。',64,'全唐诗/poet.song.12000.json','["試上高臺望綠蕪，一春芳意向人疏。", "殘花半落紅無幾，新笋爭長綠有餘。", "底處流霞殘別酌，即時油壁欠來車。", "不須更向昆池去，便有胡僧話劫初。"]'),
('958e8a92-82c9-47f3-9020-77932b5b617f','享廟禋郊詩 享廟八韵','宋祁','宋','宋诗','song-poetry','','[]','左廟崇清烈，前郊赴享期。',96,'全唐诗/poet.song.12000.json','["左廟崇清烈，前郊赴享期。", "瞻言七世室，並薦一元祠。", "樂變摐金備，天行步玉遲。", "香茅均奠鬯，錦冊不慚辭。", "有詔回宸輦，他宮奉母儀。", "衣冠對游月，脂澤感平時。", "俟獻庭虛次，登歌拜受禧。", "大哉王者孝，萬葉煥烝彝。"]'),
('2eecf657-0956-4905-8ad3-a876475ae950','享廟禋郊詩 禋郊十韵','宋祁','宋','宋诗','song-poetry','','[]','大駕峨千乘，長塗過百廛。',120,'全唐诗/poet.song.12000.json','["大駕峨千乘，長塗過百廛。", "塵清屬車地，雪盡幔城天。", "步輦黎明降，華燈艾夜燃。", "升琮奠黄粹，薦璧捧蒼圓。", "牲俎羣靈匝，霞觴二祖聯。", "上垓皆徹藉，小次但虛褰。", "不見纖蘿動，惟聞雜佩旋。", "回雲終樂奏，熏月上柴煙。", "日至方流慶，崧呼節獻年。", "欲知釐事畢，雞赦出樓前。"]'),
('4039ba46-9d40-450d-9855-068ab27a6566','大禮慶成','宋祁','宋','宋诗','song-poetry','','[]','上帝懷明德，圓壇展盛儀。',192,'全唐诗/poet.song.12000.json','["上帝懷明德，圓壇展盛儀。", "南城七里路，三歲一郊時。", "豫動森華蓋，乾行儷絳螭。", "山河對旒冕，辰象倚旍旗。", "爾祏前增謐，皇靈下告慈。", "密都俄奠玉，清廟徧嘗粢。", "田燭紛先置，軒營肅左移。", "禮行忘景晏，恩厚覺寒遲。", "紫宙天鴻洞，賓柴燎陸離。", "合祛聯祭秸，妥侑判純犧。", "腏食千華炬，陪祠萬翠緌。", "開天浮協氣，亙海受洪釐。", "愛日兼祥至，隨風與令馳。", "羣心樂更始，徽冊貺顓辭。", "堯舜文章煥，淵雲頌嘆疲。", "無階効論報，敢告日孜孜。"]'),
('07709c80-66ce-4455-bfef-a0bf7ff49a1e','孟冬駕狩近郊','宋祁','宋','宋诗','song-poetry','','[]','講事當農隙，于畋法健行。',240,'全唐诗/poet.song.12000.json','["講事當農隙，于畋法健行。", "百神奔漢蹕，萬騎扈軒營。", "彍弩先驅肅，彫戈後隊明。", "雲羅垂列岳，虎落壓裨瀛。", "掠野毛羣萃，搜林羽族并。", "熊羆兆中見，鵝鸛陣前程。", "疊中星弧妙，連飛月箭輕。", "雁窮書併墜，兔盡窟兼平。", "俊鶻交拳擊，寒鷹厲吻鳴。", "舞驂均耳耳，鋂犬鬭令令。", "示祝仍開網，招虞不用旌。", "纔聞大緌下，已見護車盈。", "行在移鑾仗，中塗集幔城。", "壽觴稱帝酒，恩膳徧君羹。", "霧日曈曨暖，霜原澶漫清。", "長楊卷衰葉，敦葦拉枯莖。", "羽獵何煩諷，車攻遂合賡。", "寧專乾豆薦，要閱建章兵。", "風入旂常影，天含鼓吹聲。", "九街猶未晚，堯屋已還衡。"]'),
('ad5c4080-34cb-4205-94bd-ee928d485c88','進幸南園觀刈宿麥詩','宋祁','宋','宋诗','song-poetry','','[]','農扈方迎夏，宮田首告秋。',240,'全唐诗/poet.song.12000.json','["農扈方迎夏，宮田首告秋。", "嘉生擁瑶縣，蕃穗徧天麰。", "肅雨津莖浹，薰風獵穎浮。", "登成告田畯，省斂徯王游。", "紫宙凝神暇，丹書訪道休。", "天行九五健，歲取十千求。", "洪洞開金狄，連蜷按玉虬。", "塵清屬車豹，槍密羽林騶。", "芝覆依丹旭，旌門倚綠疇。", "先驅護綿野，後騎隘長楸。", "滌圃初開地，腰鐮競勸收。", "田趨農帝耒，塍錯夏王溝。", "褒栗攢周甸，茨梁屬舜眸。", "籞長包圈虎，箱重載星牛。", "九扈開靈圃，三辰駐綵斿。", "勞農差有賜，置酒酌言酬。", "鳴爵知年稔，爲魚告夢優。", "雲雷一日澤，鐘鼓萬人謳。", "帝醉鈞天闋，仙歸紫氣留。", "明馨資寢廟，足食煥緹油。"]'),
('bc8c0fe6-9659-4e38-b73c-6fa6ceee1595','觀太學釋奠','宋祁','宋','宋诗','song-poetry','','[]','鄉盛菁莪選，邦崇奠菜儀。',72,'全唐诗/poet.song.12000.json','["鄉盛菁莪選，邦崇奠菜儀。", "涓辰大昕鼓，持節少牢祠。", "粉衮瞻凝睟，銀袍豫攝齊。", "芼羹紛澗沚，鬰齊泛尊彝。", "璧水回寒影，經槐墮曉枝。", "幸觀三獻罷，共荷百朋時。"]'),
('f9b21ba4-879a-4123-9a1b-4969d4e4b344','大酺紀事十四韵','宋祁','宋','宋诗','song-poetry','','[]','太極登徽冊，鴻恩潤慶圖。',168,'全唐诗/poet.song.12000.json','["太極登徽冊，鴻恩潤慶圖。", "三秋少皡月，五日漢家酺。", "碩惠東西暨，高年左右趨。", "雲雷方霈澤，酒食更成需。", "慈宴周綿宇，宸嬉極上都。", "風飛迎沛筑，尊滿列堯衢。", "鼉伐漁陽鼓，龍吟北里竽。", "激波呈曼衍，跳索戲都盧。", "虎瑟修旃映，鴟夷後乘俱。", "瑞烟浮玉戟，靈旭射金鋪。", "篚帛侔王鎬，童冠盛舞雩。", "歌忘齊國味，辱免絳人塗。", "紫宙纖羅廓，層穹協氣敷。", "萬靈酣飫賜，朝野正多娛。"]'),
('3a9f9b78-46b9-4100-b523-1d57e8bbbfb1','奉和御製後苑賞花詩','宋祁','宋','宋诗','song-poetry','','[]','詔蹕迴清籞，宸旒駐紫烟。',72,'全唐诗/poet.song.12000.json','["詔蹕迴清籞，宸旒駐紫烟。", "矞雲霏漢幄，法曲度文絃。", "獵翠雄風度，凝香甲帳褰。", "仙葩浮羽葆，藻衛縟芝廛。", "式宴千鍾酒，迷魂七日天。", "宸章紆寶思，休詠掩樓船。"]'),
('ff10e145-5f34-47b2-9ab2-3a52878c9fdd','代賦後苑賞花釣魚  其一','宋祁','宋','宋诗','song-poetry','','[]','黄屋宸襟豫，靈琨苑制雄。',72,'全唐诗/poet.song.12000.json','["黄屋宸襟豫，靈琨苑制雄。", "鈞天回帝所，太液近唐中。", "瑞旭摇卿靄，丹葩雜紺叢。", "王魚多在藻，君鵠鎮迎弓。", "式宴晞陽露，徒歌屬大風。", "此時慈惠洽，共樂夏渠豐。"]'),
('1295df1e-93f9-46f8-977c-6ebd3f2ebce7','代賦後苑賞花釣魚  其二','宋祁','宋','宋诗','song-poetry','','[]','春豫凝蒼陸，天旋駐翠華。',72,'全唐诗/poet.song.12000.json','["春豫凝蒼陸，天旋駐翠華。", "黄圖包漢制，靈沼象周家。", "風助千人唱，神移萬品花。", "韶音清感鳳，騶節妙論豝。", "宴露晞心藿，需天灧酒霞。", "侍臣均式燕，羲馭重西斜。"]'),
('76310fd7-d2cf-4582-82a3-e3aa03073890','慈聖閣秋橙結實上召宗室同觀','宋祁','宋','宋诗','song-poetry','','[]','昔預穰侯貢，今移漢掖旁。',120,'全唐诗/poet.song.12000.json','["昔預穰侯貢，今移漢掖旁。", "帝憐秋實茂，天許本根强。", "媚葉童童密，幽花裛裛香。", "苞垂列星緯，味變九霞漿。", "薰軫分風近，仙盤餉露凉。", "和羹並梅䕩，連葉讓芝房。", "舜日晨烘霧，堯雲夕護霜。", "不隨江北化，思助廟中嘗。", "盧橘非同種，安榴肯羣芳。", "榮觀聳麟族，賦筆助荷囊。"]'),
('2e923699-a92a-444e-aff8-8ceee95ee79e','被召觀三聖御書詩','宋祁','宋','宋诗','song-poetry','','[]','列聖多能備，俱留乙夜勤。',72,'全唐诗/poet.song.12000.json','["列聖多能備，俱留乙夜勤。", "出圖天與畫，觀跡帝成文。", "露灑紛仙液，鸞回雜瑞羣。", "毫均五色麗，書對十行分。", "玉軸羅新帙，芝泥儼舊薰。", "嗣皇尊世哲，金匱冠攸聞。"]'),
('677aa96e-a312-4c86-9817-28456e797be9','題承詔亭','宋祁','宋','宋诗','song-poetry','','[]','地占高明適，亭兼仁智居。',96,'全唐诗/poet.song.12000.json','["地占高明適，亭兼仁智居。", "竹林茲置酒，栗里近回輿。", "山對盤龍外，濤觀濯鷺餘。", "落霞霏迥宇，升月凈凉疏。", "園甃悟陰合，窗風桂籟徐。", "巖芳曼空逕，野綠冒前除。", "宴厦仍喧雀，賓庖已饜魚。", "落成嚴詔下，猿鵠怨軺車。"]'),
('b72a7c00-be70-408f-be61-bf68f084eea3','車駕出獵和丁學士','宋祁','宋','宋诗','song-poetry','','[]','九扈聊清野，三驅比出畋。',120,'全唐诗/poet.song.12000.json','["九扈聊清野，三驅比出畋。", "紫雲華蓋上，玉斗帝車前。", "藻衛羅長薄，星槍落晚廛。", "旗開龍對舞，驂合雁相聯。", "魚貫圍中隊，風毛仗裏天。", "寒熊批怒掌，饑鶻下蒼拳。", "困獸開仁網，良禽獻廟鮮。", "賜庖飛騎促，勞飲釂烽傳。", "歷覽黄圖迥，裴回翠帽旋。", "邇臣將盛美，吉日繼王篇。"]'),
('ea7f505f-9c4d-4393-968a-534f779eafde','紀聖詩','宋祁','宋','宋诗','song-poetry','','[]','沙麓披祥牒，金刀襲裔昆。',288,'全唐诗/poet.song.12000.json','["沙麓披祥牒，金刀襲裔昆。", "嬪虞冠媯汭，生子首姜嫄。", "自昔儀椒壺，乘時正翟軒。", "褘褕躬象服，黄老好名言。", "慈蔭天同廣，柔風律並暄。", "露光流月姊，祕緯應星黿。", "嗣統開橫兆，遵遺奉壽原。", "愛親周道始，加太漢儀尊。", "參務絲言慎，臨朝玉色溫。", "從容携日月，指顧靖乾坤。", "盡散脂田邑，親繰繭舍盆。", "紀功彤管史，貽訓濯龍門。", "寶稼興東戶，佳兵戢左鞬。", "萬靈翔氣辨，五始匝春元。", "夜隕西方雨，神清積石源。", "良時標歷鳳，延祝動廷鴛。", "繅玉虹光射，絲囊露采翻。", "齋科蕊珠館，供會佛家園。", "薦壽超千劫，同寅望九閽。", "南風來助曲，北斗下臨罇。", "瑞鑑紅摇旭，香罌碧裊昏。", "欽承子道至，奉養母儀敦。", "雉翣橫霏霧，仙盤灧瑞暾。", "紫雲回幄影，銀蒜動鈎痕。"]'),
('f3ead936-06bc-44ce-86b1-b4c22ca8d6aa','九日侍宴太清樓','宋祁','宋','宋诗','song-poetry','','[]','薦九標佳節，中天駐翠輿。',144,'全唐诗/poet.song.12000.json','["薦九標佳節，中天駐翠輿。", "晨光清複道，秋色徧儲胥。", "畦稻霜成後，宮橙露飽初。", "省收行步玉，拜賜儼華裾。", "曼衍來長樂，鴟夷下屬車。", "帝韶儀瑞鶠，王藻躍恩魚。", "霽霧供披拂，凉風助掃除。", "高楊穿葉外，仙菊泛花餘。", "寒入弓聲厲，歡留酒算徐。", "神池原不浪，溫樹未曾疏。", "帝眷憑秋稼，臣心仰夏渠。", "承平將樂事，併入史臣書。"]'),
('3088ea95-8148-4b77-bda8-c7185d413b52','十日宴江瀆亭','宋祁','宋','宋诗','song-poetry','','[]','節去歡猶在，賓來賞更延。',72,'全唐诗/poet.song.12000.json','["節去歡猶在，賓來賞更延。", "悠揚初短日，凄緊乍寒天。", "霽沼元非漲，秋花自少妍。", "蟻留新獻酎，蕙續不殘烟。", "戲鰋衝餘藻，游龜避折蓮。", "流芳真可惜，從此遂凋年。"]'),
('f18f643c-32ae-4eba-bdfe-acad56f6859e','尹學士自濠梁移倅秦州','宋祁','宋','宋诗','song-poetry','','[]','于役三年遠，論兵兩鬢斑。',72,'全唐诗/poet.song.12000.json','["于役三年遠，論兵兩鬢斑。", "不辭征戍苦，要作破羌還。", "楯墨應圜熟，兜烽報永閒。", "浮舠背淮服，盤馬入秦關。", "遂閣讎書筆，仍餘聚米山。", "憶君他夕恨，遥向隴雲間。"]'),
('51fb3894-c287-434c-8341-ed43e926719a','初除直講獻內閣馮學士孫侍郎','宋祁','宋','宋诗','song-poetry','','[]','圓海崇遺教，中陵育茂材。',144,'全唐诗/poet.song.12000.json','["圓海崇遺教，中陵育茂材。", "霧從仙市合，風向舞雩來。", "寶篆侔東壁，儒篇訪曲臺。", "泮芹參上俎，燕篲擁輕埃。", "鼓篋華冠聚，丘山縹帙開。", "蟲形浮墨沼，鼠耳綻經槐。", "有客緣承乏，無庸愧濫陪。", "難重漢家席，易眩魯門杯。", "學困青箱廣，書愁皓首催。", "空塵博士議，不稱洛陽才。", "高閣連雲景，層城枕斗魁。", "惟應仲尼冶，未惜鑄顔回。"]'),
('66ed0788-8eed-4adc-9a31-3c7ca4c853f4','和石學士直舍晨興','宋祁','宋','宋诗','song-poetry','','[]','高閣休殘暝，層梁逼早暾。',144,'全唐诗/poet.song.12000.json','["高閣休殘暝，層梁逼早暾。", "芳風萬年樹，殘月九重閽。", "枕歇淵魚夢，裘貪睡貉溫。", "星杓壓城角，天漢落河源。", "肅唱千廬寂，傳聞萬戶喧。", "烟浮紫藜觀，春著翠梧園。", "有客方岑寂，紬書滯討論。", "新年居右席，此地到西崑。", "硯瀉含毫滴，刀餘削柿痕。", "談高白馬度，頌罷碧雞翻。", "幸接雌黄几，同歡清白樽。", "不因窺麗句，誰刮翳瞳昏。"]'),
('9ce9b671-7254-4a66-9807-df16a082db71','再到國子監感昔有懷','宋祁','宋','宋诗','song-poetry','','[]','十載虞庠路，依然目所存。',72,'全唐诗/poet.song.12000.json','["十載虞庠路，依然目所存。", "高槐記經市，秋水識橋門。", "迥閣珍圖秘，長廊審像昏。", "舊徒皆突弁，故友即塵根。", "昔在衣成緇，今還祿有軒。", "范雲身寖老，何術謝君恩。"]'),
('457aaf7d-ebb5-4149-826a-3eaf09d07b5e','上元觀燈紀事','宋祁','宋','宋诗','song-poetry','','[]','泛膏聞舊典，秉燭嗣芳辰。',96,'全唐诗/poet.song.12000.json','["泛膏聞舊典，秉燭嗣芳辰。", "霞破初迎月，林寒即讓春。", "鈞天移帝樂，北斗下城闉。", "匝地沈香燎，浮空羅襪塵。", "並珂馳寶鉸，分幰鶩彫輪。", "忽去騰夷路，還來競要津。", "酒胡矜酎美，梅額衒妝新。", "誰見甘泉畤，昏祠遂至晨。"]'),
('001e984b-3ea8-4f56-bae9-79457288f03a','玉堂北欄叢竹','宋祁','宋','宋诗','song-poetry','','[]','玉署凝嚴處，朱欄封殖恩。',144,'全唐诗/poet.song.12000.json','["玉署凝嚴處，朱欄封殖恩。", "其誰賞高節，祗自保孤根。", "密幹青杠矗，危梢翠纛翻。", "故林茲地隔，新實幾時繁。", "細籟供風枕，斜陰疊月軒。", "雀驚衝葉墮，蟬靜抱枝喧。", "戴氏當年譜，梁王自古園。", "對容金馬客，深在玉堂門。", "本以蕭蕭擢，還由冉冉存。", "烟能留暝色，粉解記春痕。", "拾籜題吟墨，披叢爽醉魂。", "愛君同省樹，不敢爲人言。"]'),
('8de7ee6a-d21b-4755-b807-3980814e5369','九日','宋祁','宋','宋诗','song-poetry','','[]','帝京蒙福近，相國偃藩初。',72,'全唐诗/poet.song.12000.json','["帝京蒙福近，相國偃藩初。", "甕熟中齋酒，厨鮮上客魚。", "高懷日蕭散，外物久驅除。", "犀首無妨飲，宣尼或飯疏。", "林凋疑野闊，荷罷似池虛。", "此樂憑誰辨，須煩藻思餘。"]'),
('da0408c4-0d26-4989-ac55-a097cfe5d7c5','會聖宮','宋祁','宋','宋诗','song-poetry','','[]','寶地披重岫，瓌宮庇萬榱。',240,'全唐诗/poet.song.12000.json','["寶地披重岫，瓌宮庇萬榱。", "人瞻鼎湖駕，天護玉簫祠。", "列聖聯絺衮，千宮擁翠緌。", "陰森殿中傘，曶熣羽林旗。", "白日窺晨幌，明河宿曙帷。", "露盤金突兀，甲帳繡葳蕤。", "馴象春耕外，遊冠月出時。", "洛湍縈禁籞，嵩岳倚罘罳。", "早晏嚴薰燎，春秋達信辭。", "樽醅綠葉桂，齋饌紫房芝。", "璧带華燈錯，銀牀露綆垂。", "奇葩萬品秀，珍木五衢滋。", "碧柱峨翔鳳，璇璫舞暗螭。", "園金布爲地，泉玉漱成池。", "劫石聊容拂，仙花自不萎。", "樓含太虛近，鐘到下方遲。", "賜服鄉三老，歌風沛小兒。", "奉承紛有次，過謁儼多儀。", "此路真姑射，前峰即具茨。", "何當紆詔蹕，原廟慰時思。"]'),
('0c4ef16f-d286-40c0-acda-9cd8bc4d5f09','和道卿舍人承祀出郊過西苑馬上有作','宋祁','宋','宋诗','song-poetry','','[]','西郊一超忽，祠節暫踟躕。',144,'全唐诗/poet.song.12000.json','["西郊一超忽，祠節暫踟躕。", "天迥欹臨野，河長側貫都。", "飛廉披苑路，南斗抱城隅。", "填塹時休獵，棲糧戶免租。", "虎歸仍習圈，鳳下稍依梧。", "池岸斜聯籞，宮楹上集胡。", "慎齋雖有屬，勝踐未云孤。", "霧裏過仙市，輪邊認佛圖。", "檉楊閒對偃，鶬鴰靜相呼。", "牧罷林將暝，樵歸徑自紆。", "有懷摛鏤管，何苦促驪駒。", "壯思飄然發，知君顔謝徒。"]'),
('05aedca7-79e3-4b84-9013-3bdaacf34dcf','三月二十一日集海雲鴻慶院','宋祁','宋','宋诗','song-poetry','','[]','地勝祠仍古，春餘物徧華。',72,'全唐诗/poet.song.12000.json','["地勝祠仍古，春餘物徧華。", "山雲時抱石，佛雨不萎花。", "嶺挾樓梯峻，巖牽殿墄斜。", "淙谿雜環佩，怪蔓走龍蛇。", "供坐僧飛鉢，香園客戲沙。", "吾游真草草，深意負青霞。"]'),
('0ddf0ee2-5e3f-4cf3-86c7-2daecc6f7309','喜同朱舅秀才小飲','宋祁','宋','宋诗','song-poetry','','[]','隠几劇端憂，良辰喜嘯儔。',96,'全唐诗/poet.song.12000.json','["隠几劇端憂，良辰喜嘯儔。", "掞天鸚鵡筆，換酒鷫鸘裘。", "談麈真同色，賓壺喜順投。", "雪雲低北戶，棋墅接西州。", "露葉燕蘭老，霜津鄧橘秋。", "二豪休作頌，五白自成牟。", "平日欣交呂，前期即召鄒。", "彫觴莫辭醉，溝水易分流。"]'),
('d245700e-cb08-4936-bac3-7c4d2f335f95','將東歸留別楊宗禮十韵','宋祁','宋','宋诗','song-poetry','','[]','清白舊家聲，論交得寧馨。',120,'全唐诗/poet.song.12000.json','["清白舊家聲，論交得寧馨。", "摛華吐鳳賦，聞禮墮鱣庭。", "潘夏叨連璧，荀陳更聚星。", "膠投思固漆，渭濁許過涇。", "合坐懷妍唱，分詩寫素屏。", "情深方柏悅，性懶自榆暝。", "短羽偏驚月，羈游劇泛萍。", "北梁催稅鞅，南郡阻繙經。", "曉色三竿日，離歌十里亭。", "期君促西上，相遇在神坰。"]'),
('d39b1f26-e775-4db3-a6e8-cbab0d914477','漢州房公湖','宋祁','宋','宋诗','song-poetry','','[]','丞相于藩日，疏湖訟閣西。',72,'全唐诗/poet.song.12000.json','["丞相于藩日，疏湖訟閣西。", "疑從濟川地，寫出釣璜溪。", "流淺初無浪，源清不貯泥。", "月爲宵幌燭，雲作曙樓梯。", "礙馬汀篁密，縈船浦蔓低。", "人亡桃李在，脈脈尚成蹊。"]'),
('ddd0197c-bd44-46d3-aece-1c0282e59ad8','得故人楊備書','宋祁','宋','宋诗','song-poetry','','[]','款款南雲信，相存安穩不。',288,'全唐诗/poet.song.12000.json','["款款南雲信，相存安穩不。", "比年常屬疾，茲地幸爲州。", "浩蕩親知隔，奔騰日月遒。", "暴公初有刺，孫叔竟無謀。", "黑白蠅間變，嫌疑李下求。", "側身忘夙夜，回首得沈浮。", "士節何嘗屈，君恩叵計酬。", "洴封共龜手，知罪一春秋。", "言命由來罕，逢辭敢辯廋。", "紛吾常用拙，焉往不離憂。", "重詛勞三物，揚芬避十蕕。", "虛弦落驚雁，真月喘疲牛。", "谷口輸誰隠，周南愧自留。", "尪殘千騎長，形勝二山流。", "寡術驅秦盜，彌旬錄楚囚。", "巫風那肯化，祠鼓詎曾休。", "安敢龔黄最，真堪趙魏優。", "闊然宣布曲，直爾伴牢愁。", "今子身東望，思同智北游。", "攄懷弄杯杓，對帙理墳丘。", "眷眷餘青眼，蕭蕭共白頭。", "姑縈裘與葛，隨度臘和膢。", "樠櫟人寧顧，遺簪上或收。", "狂言非所恧，君乃惠施儔。"]'),
('e3b22abd-d1e7-43b7-96f4-7dc9916d9689','內閣孫侍郎生辰紀德','宋祁','宋','宋诗','song-poetry','','[]','鳳琯凝姑律，奎鉤誕佐臣。',120,'全唐诗/poet.song.12000.json','["鳳琯凝姑律，奎鉤誕佐臣。", "祥標六蓬矢，家盛十朱輪。", "變道齊成魯，端朝甫及申。", "禁中朝夕誨，帝右老成人。", "徧讀蘭圖字，多陪豹尾塵。", "桓榮師自許，石建謹無倫。", "振鷺飛逾潔，緇衣久更新。", "鑄賢今是冶，播物晚爲鈞。", "胡廣潭留菊，蒙莊樹有椿。", "奉公爲壽禱，山立輔昌辰。"]'),
('831717a8-c94f-461d-8107-374de98c0ffa','郭仲微見過問疾','宋祁','宋','宋诗','song-poetry','','[]','薄宦真何補，居然滯拙艱。',198,'全唐诗/poet.song.12000.json','["薄宦真何補，居然滯拙艱。", "無心圖作佛，有疾願藏山。", "臂率愁肌減，毛驚暮領斑。", "未能吳客問，誰恨越人彎。", "學倦書刀廢，呼慵博雉閒。", "寧慚局轅下，爲恥醉墦間。", "直道胡論枉，空言分合刪。", "蒼蠅徒擾擾，狂猘自{口顔}{口顔}。", "上客迂飛蓋，窮閻問閉關。", "餘光照徒壁，高辯破連環。", "感激排非聖，棲遲觸怒頑。", "十年休賦蜀，二始欲睎顔。", "昔有彈冠進，今將襆被還。", "春休晴絮白，日入暝霞殷。", "舊産平臺側，新田潁水灣。", "吾游如不遂，巖樾試重攀。"]'),
('7d3293a0-d1e2-4e6b-a9fb-5457a23464f6','和晏相公九日郡筵','宋祁','宋','宋诗','song-poetry','','[]','令序凝秋籥，歡游駐使軒。',72,'全唐诗/poet.song.12000.json','["令序凝秋籥，歡游駐使軒。", "行觴酒籌密，踏節舞韡翻。", "榴熟丹房解，萸香紫粒繁。", "風頭臘輕慘，日脚送斜喧。", "鏤管新篇逸，吹花舊俗存。", "請爲丞相壽，長久慶調元。"]'),
('b76273a0-e765-4058-89be-ca4b5cfcf2f3','早夏集公會亭餞金華道卿內翰守澶淵得符字','宋祁','宋','宋诗','song-poetry','','[]','早夏乘休沐，離襟屬餞壺。',72,'全唐诗/poet.song.12000.json','["早夏乘休沐，離襟屬餞壺。", "欣同佩荷橐，恨及唱驪駒。", "感戀陪雲筑，翻飛別帝梧。", "騰裝照魚服，行帳繞犀株。", "慚去班中詔，寧容滯左符。", "惟應九里潤，蒙福在京都。"]'),
('0991347e-fb8c-45da-b8b3-0c6bdcd2c69a','鹿鳴筵餞諸秀才赴舉','宋祁','宋','宋诗','song-poetry','','[]','今日真良宴，歡持鳴鹿杯。',72,'全唐诗/poet.song.12000.json','["今日真良宴，歡持鳴鹿杯。", "初飛禰衡表，共識子虛才。", "龍沼雲鱗動，鵬溟浪翅開。", "危言切晁董，祕思屬鄒枚。", "經市騰裝早，封軺續食催。", "應須戒驅弩，翹待駟車回。"]'),
('9e47f0ca-35ff-4bf0-b5af-bd0a3e315ac9','送承制劉兼濟知原州','宋祁','宋','宋诗','song-poetry','','[]','假節分州郡，掄才出將門。',96,'全唐诗/poet.song.12000.json','["假節分州郡，掄才出將門。", "還提射聲旅，并破護羌屯。", "尺詔方臨遣，新書得細論。", "旃酋陪獵帳，戍校接歡罇。", "後伍鞬櫜密，前驅鼓吹喧。", "隴笳梅落怨，邊陣月殘奔。", "赤白猶傳警，先零久負恩。", "行期雪家恥，三捷奏天閽。"]'),
('0c3595d1-ba0f-4dca-9616-58682a390b0c','早春雨中因呈邑大夫','宋祁','宋','宋诗','song-poetry','','[]','瑞澍霑春陸，膚雲壓暝臺。',96,'全唐诗/poet.song.12000.json','["瑞澍霑春陸，膚雲壓暝臺。", "霰寒休雜下，風好即東來。", "遠岫吞將盡，陰霞照暫開。", "徧滋畦下麥，併濕隴頭梅。", "灑罶南魚躍，漂蘆北雁哀。", "蓬乾釣師卧，庌冷牧騶回。", "天發千驍電，人同百里雷。", "我私欣遂及，頌扈九農催。"]'),
('fee70674-c590-4726-8f57-3cb3c188b0a8','送范希文','宋祁','宋','宋诗','song-poetry','','[]','日夕朋簪遠，空成咄咄嗟。',120,'全唐诗/poet.song.12000.json','["日夕朋簪遠，空成咄咄嗟。", "危言猶在口，飛語已磨牙。", "室救鴟鴞毀，庭喧獬豸邪。", "青蒲空頓首，白簡遂爲瑕。", "身歷千金險，頭經一夕華。", "便應過楚澤，何異向長沙。", "簣土障河拙，園葵望日賒。", "盡焚溫室草，尚得使君車。", "勝壤堪懷古，扁舟復載家。", "此時能痛飲，努力詠餘霞。"]'),
('7c68d5de-8971-4a87-9ede-6a309e2f98c3','喜有秋','宋祁','宋','宋诗','song-poetry','','[]','順氣綿區廣，嘉生告稔初。',72,'全唐诗/poet.song.12000.json','["順氣綿區廣，嘉生告稔初。", "人驚萬箱入，天賜九年儲。", "絕塞元休馬，吾農先夢魚。", "牛應賣刀後，酒是乞漿餘。", "祀續田神鼓，郵喧粟尉車。", "是年名大有，敢告史臣書。"]'),
('77ba876e-5f83-4b49-bc48-d57bb3215c22','荷花','宋祁','宋','宋诗','song-poetry','','[]','別岸香風起，橫塘夕霧開。',120,'全唐诗/poet.song.12000.json','["別岸香風起，橫塘夕霧開。", "歌須靜婉至，步憶貴妃來。", "折藕冰絲剩，翻荷孔蓋回。", "曾經佛圖咒，解厭柏梁災。", "盛府開爲幕，騷人借作媒。", "謝才方麗句，卓寡比愁腮。", "有薏緣誰苦，名蓮固自猜。", "簪形侵寶髻，燭柄近宮煤。", "游羨龜巢密，看防漏葉催。", "使君迷已久，落晚且徘徊。"]'),
('999f7bf4-b85d-4447-b2c0-bce8d5327ec6','早濟江步','宋祁','宋','宋诗','song-poetry','','[]','南浦招招子，中途靡靡心。',96,'全唐诗/poet.song.12000.json','["南浦招招子，中途靡靡心。", "歸舟一葉小，秋水兩厓深。", "露鶴凄仍斷，風蜩細欲沈。", "桂華翻落月，榆影送橫參。", "壯志兼時晚，勞愁已日侵。", "霜摧過江枳，鐘眩避風禽。", "薄宦真蓬累，歸期問藁砧。", "惟餘摇落意，天宇共登臨。"]'),
('1ac7f036-0d5b-4a11-ba61-25bc16b40611','龐祕校掾九江兼歸汝南迎侍','宋祁','宋','宋诗','song-poetry','','[]','長停愁不淺，征袂拂殘梅。',72,'全唐诗/poet.song.12000.json','["長停愁不淺，征袂拂殘梅。", "潘御家園近，毛欣府檄來。", "晨羞魚尾潔，春溜鴨頭催。", "拄頰談無對，參卿掾有才。", "城隅山疊映，樓戶月弦開。", "廨樹藏環感，因君寄九迴。"]'),
('d3e01dc3-e0ae-4868-8e79-ab03240977f1','送次饒趙職方罷成德軍通判還朝','宋祁','宋','宋诗','song-poetry','','[]','倅乘淹榮序，封軺促覲期。',72,'全唐诗/poet.song.12000.json','["倅乘淹榮序，封軺促覲期。", "文章二臺妙，昆弟五常眉。", "樹隠征郵密，花留祖蓋遲。", "秋毫供握處，春草見歸時。", "書笏人思對，垂櫜客愴離。", "羨君如彩鳳，先集翠梧枝。"]'),
('87069ad4-dc92-4034-b4bc-473792df705d','泌陽王介夫','宋祁','宋','宋诗','song-poetry','','[]','上笏蘭臺彥，能文江漢靈。',120,'全唐诗/poet.song.12000.json','["上笏蘭臺彥，能文江漢靈。", "貪持御史劾，不顧大夫醒。", "詆毀真銷骨，嫌疑畏殺青。", "投冠集烏署，解紱墮鳶溟。", "毛脫荷囊筆，塵昏寶带釘。", "書空寧咄咄，避弋更冥冥。", "校尉貪厨釀，臨川集貝經。", "光華覆盆日，哆侈譖人星。", "生計依江芷，年芳老砌蓂。", "無人舉幡救，揮涕望明庭。"]'),
('4f53e2c7-2331-4b76-b3d5-44dd4ac1a425','還都有感','宋祁','宋','宋诗','song-poetry','','[]','去國已十載，召還今見收。',168,'全唐诗/poet.song.12000.json','["去國已十載，召還今見收。", "初無潁川最，真忝茂陵求。", "物色多新識，寒溫減舊游。", "宮毫與塵晦，省樹向人秋。", "奏乏三千敏，恩難萬一酬。", "重尋紫荷橐，却侍翠雲裘。", "建禮文書少，湯官餠餌優。", "屏營趨虎殿，子細認奎鉤。", "晚節誠知止，吾生況若浮。", "身來雖魏闕，病免合滄洲。", "淺醉貽樽恥，衰容作鑑羞。", "歸年非雁後，破月是刀頭。", "依聖讒方弭，逃陰景自休。", "乞骸從此近，終計返林丘。"]'),
('87e7feda-2490-439c-aae7-eeaeaaa9e574','歲周移書課版','宋祁','宋','宋诗','song-poetry','','[]','漢史傳循吏，唐家秩省郎。',96,'全唐诗/poet.song.12000.json','["漢史傳循吏，唐家秩省郎。", "海禽驚廟樂，池鶩費君粱。", "巾禿聊蓬首，帷閒即偃牀。", "案杯過永晝，寺鼓報殘陽。", "束帙雲籤冷，窺園李樹僵。", "後車常擊轂，猥酒不空腸。", "未易矜刀筆，徒煩裹服章。", "歲周無吏最，天極正包荒。"]'),
('fafcc998-a8d9-4ce9-a304-37bc81e03efe','舅氏自壽陽由京師歸安陸','宋祁','宋','宋诗','song-poetry','','[]','道舊欣來駕，銷魂遽遠離。',72,'全唐诗/poet.song.12000.json','["道舊欣來駕，銷魂遽遠離。", "顛毛同白日，俗眼暫青時。", "客飯稽留數，齋醪酪酊遲。", "風波須畏險，老大共餘悲。", "楚莽先春動，梁雲向雪垂。", "還家存別墅，他會看圍棋。"]'),
('516829c0-7d86-41c6-964a-ac3c9a70998f','仲微相過把酒有感','宋祁','宋','宋诗','song-poetry','','[]','故人當止酒，今夕喜銜盃。',72,'全唐诗/poet.song.12000.json','["故人當止酒，今夕喜銜盃。", "事與朱顔改，年將素領來。", "鹿車君偃蹇，鶴祿我裴回。", "紬史餘三擿，爲郎愧一臺。", "洛吟真可效，傖賦久成咍。", "平日雱風瑟，塵襓爲試開。"]'),
('5b8894d7-0399-4430-b05c-58aaf26f22e8','送樞直梅學士守并州','宋祁','宋','宋诗','song-poetry','','[]','素領登朝舊，黄樞遞直新。',96,'全唐诗/poet.song.12000.json','["素領登朝舊，黄樞遞直新。", "還持漢家節，坐福晉墟民。", "旆羽凌霜曉，袍花犯雪春。", "連雲祖壇幄，隘道舞驂塵。", "檄楯邊書息，羹羊府宴均。", "唐詩存雅俗，亥字訪遺人。", "緣飾資良守，都俞重老臣。", "莫爲朞月調，行此冠華紳。"]'),
('3c924c3d-8f3e-471a-8cc6-a1552c155000','上春晦日到西湖呈轉運叔文學士','宋祁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春徧西湖上，湖漪綠勝醅。',120,'全唐诗/poet.song.12000.json','["春徧西湖上，湖漪綠勝醅。", "驚魚迎瀨躍，鬭鴨擁波來。", "柳已緣烟重，花仍赴暖開。", "側汀烟媚篠，卧石水銜苔。", "岸轉橫杠度，川窮飲舫回。", "暗浮蟲聿役，閒立鷺毰毸。", "野畔平如界，林蹊潤不埃。", "光浮好雲日，影倒靜樓臺。", "山色乘晴露，霞容著暝催。", "溪行凡幾曲，恨乏昔人才。"]'),
('5fcc5b0f-9b70-4672-906c-c32a25c41733','硤石乘舟晚歸','宋祁','宋','宋诗','song-poetry','','[]','晚棹乘餘興，平川不駛流。',72,'全唐诗/poet.song.12000.json','["晚棹乘餘興，平川不駛流。", "山來疑逼岸，林度省移洲。", "郭迥花仍繞，巖寒桂自留。", "鼓聲風處疊，帆影浪間浮。", "候吏緣溪彴，迎旗駭浦鷗。", "嚮時天際遠，還有望歸不。"]'),
('9a9ca1b2-3556-4e11-a484-5446b8f6fa4e','中秋望夕不見月','宋祁','宋','宋诗','song-poetry','','[]','異時凉月好，常爾惜嚴更。',96,'全唐诗/poet.song.12000.json','["異時凉月好，常爾惜嚴更。", "此夜浮雲惡，胡然溷太清。", "心孤王粲牘，案對景山鎗。", "海蚌猶能滿，城烏更不驚。", "裴回循北牖，黯淡倚西楹。", "蛩杼逢時急，釭花得闇明。", "桂高應自秀，蟾遠太無情。", "坐想瑶輪轉，孤懷悵未平。"]'),
('5a53b2bc-f5d8-46b6-8097-833c342dc89b','清明值雨','宋祁','宋','宋诗','song-poetry','','[]','有渰興芳序，餘寒惜慘悽。',96,'全唐诗/poet.song.12000.json','["有渰興芳序，餘寒惜慘悽。", "遠山沈向盡，雜樹望先迷。", "天闊都成暝，雲昏本自低。", "漂灰禁餘火，浮棗祓殘溪。", "檻篠風爭亞，汀鳬夜不棲。", "篷聲攢釣渚，蓑滴擁烟畦。", "積潤侵重構，長嚴壓曉鼙。", "游人盤馬路，獨漉逐春泥。"]'),
('3690cc76-742c-4760-b700-339be20f0d86','瑞荷同幹','宋祁','宋','宋诗','song-poetry','','[]','協氣凝清籞，嘉祥擢鈿荷。',72,'全唐诗/poet.song.12000.json','["協氣凝清籞，嘉祥擢鈿荷。", "共茄含瑞液，分蒂蓋文波。", "魚戲浮香併，龜游得地多。", "房芝助連葉，宮樹讓交柯。", "柄合千絲剩，盤差五兩過。", "正須裁紫橐，回入從臣歌。"]'),
('fb974373-ae12-435f-814a-4615304896e2','愁吟','宋祁','宋','宋诗','song-poetry','','[]','夜雨平階滴，寒燈照幔孤。',72,'全唐诗/poet.song.12000.json','["夜雨平階滴，寒燈照幔孤。", "未生靈運草，先據惠施梧。", "千里徒傷目，三年欲變儒。", "回腸啼絡緯，遠恨送襜褕。", "怨曲傳繁瑟，悲歌缺唾壺。", "此中如借問，掩鼻願操觚。"]'),
('265914d7-41aa-48d7-af7a-6bb40cc9d611','偶書','宋祁','宋','宋诗','song-poetry','','[]','遠作分符守，猶爲持橐官。',192,'全唐诗/poet.song.12000.json','["遠作分符守，猶爲持橐官。", "易漂非待煦，自栗不須寒。", "髮變他年素，心餘即日丹。", "過門休骯髒，逢路定汍瀾。", "忌刻殊忠告，蘧施足面謾。", "直緣蜚語入，正恨飲章難。", "墜後仍加石，驚初更避丸。", "讒箕元有舌，僞玉嚮無瘢。", "任拔終傾藿，雖憎亦佩蘭。", "隴雲平莽莽，林露夜團團。", "且欲排孤憤，還應覓暫歡。", "兩岐行處帢，五醆食時盤。", "地善人差逸，天高網寖寬。", "戀軒嗟棄馬，巢閣羨歸鸞。", "楚嶂橫朝塞，淮波潄夕灘。", "空將西望眼，隨日到長安。"]'),
('50e0907b-ebc2-434e-b6e2-64826a199893','柳佐乾德尉','宋祁','宋','宋诗','song-poetry','','[]','塗會森璋罷，唐銓結綬初。',72,'全唐诗/poet.song.12000.json','["塗會森璋罷，唐銓結綬初。", "家聲蘭倚玉，祖德鸛銜魚。", "周粟思馨膳，京塵惜弊裾。", "垂腰青采綬，薰帙翠芸書。", "鶴怨空山帳，雞棲外舍車。", "日期優政洽，公啟達儲胥。"]'),
('dea8a55d-9f51-4d91-8baf-9658df587368','懷古眺望','宋祁','宋','宋诗','song-poetry','','[]','城闉聊屬眺，千古恨悠悠。',96,'全唐诗/poet.song.12000.json','["城闉聊屬眺，千古恨悠悠。", "夏享空臺毀，韓亡故社留。", "廟祠旌潁鳳，溪水識巢牛。", "春色依林動，晨煙傍戍浮。", "庌騶閒自集，田鶴叫相求。", "町篠沿緣密，川葭靃靡柔。", "櫟墟迷鄭鄙，騩路隔軒游。", "感昔如吾輩，曾經幾斛愁。"]'),
('f73df301-3e88-4019-8177-1ba671c9daa3','海棠','宋祁','宋','宋诗','song-poetry','','[]','西域流根遠，中都屬賞偏。',120,'全唐诗/poet.song.12000.json','["西域流根遠，中都屬賞偏。", "初無可並色，竟不許勝妍。", "薄暝霞烘爛，平明露濯鮮。", "長衾繡作地，密帳錦爲天。", "淺影纔欹檻，橫柯欲照筵。", "愁心隨落處，醉眼著繁邊。", "的的誇妝靚，番番恃笑嫣。", "何嘗見蘭媚，要是掩櫻然。", "艷足非他譽，香輕且近傳。", "所嗟名後出，遺載楚臣篇。"]'),
('10361776-ab18-42f2-a635-028d0afc9646','滁州趙學士重修懷嵩樓','宋祁','宋','宋诗','song-poetry','','[]','丞相懷嵩罷，因之名郡樓。',96,'全唐诗/poet.song.12000.json','["丞相懷嵩罷，因之名郡樓。", "使君嗟久廢，華棟鬰重修。", "人世興衰換，山川處所留。", "落成今日宴，感舊向來愁。", "西北天根遠，東南地脈浮。", "雲生蘭葉橑，月近蒜條鉤。", "樹雜猿呼暝，風長雁送秋。", "此時如極目，歸思恐難收。"]'),
('eaa546db-7654-44a1-86e4-6c838cd9b2ca','開元寺塔偶成題十韵','宋祁','宋','宋诗','song-poetry','','[]','集福仁祠舊，雄成寶塔新。',120,'全唐诗/poet.song.12000.json','["集福仁祠舊，雄成寶塔新。", "經營一甲子，高下幾由旬。", "屹立通無礙，支持固有神。", "雲妨垂處翼，月礙過時輪。", "頂日珠先現，絛風鐸自振。", "沙分千界遠，花散四天春。", "億載如如地，三休上上人。", "堆螺俯常碣，繚带視河津。", "陶甓勤爭運，園金施未貧。", "誰紆簡棲筆，爲我誌琳珉。"]'),
('7eea9619-264a-4859-a98b-67bb9d333916','季春八日喜雨答李都官','宋祁','宋','宋诗','song-poetry','','[]','夜魄離星舍，春膏浹大田。',120,'全唐诗/poet.song.12000.json','["夜魄離星舍，春膏浹大田。", "乍迷榆塞樹，徐暗柳營天。", "沼滴銀波蕩，階鳴玉綆聯。", "餘萌催沃土，殘魃趣沈淵。", "迥濕來鶑外，斜寒去雁邊。", "莓莓滋野秀，纂纂濯花妍。", "戴響饒農笠，眠聲羨釣船。", "罅雲時露日，迷岫旋埋烟。", "酌酒聊相勞，斯倉竚有年。", "勞君歌閔雨，予志謝先賢。"]'),
('af908a92-49ba-4b06-b103-cddf7ea7e380','賦得敗荷','宋祁','宋','宋诗','song-poetry','','[]','爲結秋荷恨，因來溝水西。',72,'全唐诗/poet.song.12000.json','["爲結秋荷恨，因來溝水西。", "魚驚一蓋缺，龜落半巢低。", "細暗嬋娟渚，香乾㪍窣隄。", "莖枯縈繭緒，盤側漏鮫啼。", "自此空瑶席，他年問濁泥。", "那堪塘上雨，點點共凄迷。"]'),
('862251c5-4233-4705-9697-b09fad0f51bf','小荷','宋祁','宋','宋诗','song-poetry','','[]','濯雨拳紅展，擎烟側鈿微。',72,'全唐诗/poet.song.12000.json','["濯雨拳紅展，擎烟側鈿微。", "纔勝漢臣橐，未辦楚人衣。", "矗矗閒攢沼，差差靜隠磯。", "游防靈蔡重，戲怯孺魚肥。", "莖弱從風靡，珠成恐浪揮。", "文鴛不肯去，始得蔽斜暉。"]'),
('56f50c3b-7191-4b20-9801-2466bab9d906','馬上逢雪','宋祁','宋','宋诗','song-poetry','','[]','馬上逢飛雪，都城觸望新。',96,'全唐诗/poet.song.12000.json','["馬上逢飛雪，都城觸望新。", "天如不擬暝，樹欲頓成春。", "霰急初鳴瓦，塗輕自壓塵。", "灑逵先映璐，飄闕欲藏銀。", "宛轉呈歌麗，裴回逼舞真。", "散鹽拂波亂，飛莢點星勻。", "密影俄飛蓋，乾花看鈿輪。", "無煩濕潘鬢，今是二毛人。"]'),
('cce47297-12e9-4214-9c7a-90077617dd2f','南方未臘梅花已開北土雖春未有秀者因懷昔時賞玩成憶梅詠','宋祁','宋','宋诗','song-poetry','','[]','江南寒意薄，未臘見梅芳。',144,'全唐诗/poet.song.12000.json','["江南寒意薄，未臘見梅芳。", "爲有輕盈態，都無淺俗香。", "倚風斜夕臉，呵雪噤晨妝。", "刀尺憑鮫杼，比鄰託粉牆。", "高枝籠遠驛，側影照回塘。", "曠望黄昏月，嫶妍半夜霜。", "一身來上國，三載別炎方。", "不見南枝早，方驚北道長。", "當時猶引領，此際故回腸。", "淚盡羌人笛，魂銷越使鄉。", "危樓難極目，恨酒怯盈觴。", "未到盧家第，終虛白玉堂。"]'),
('d9501390-d9a7-468d-9c76-563c556439ff','李少傅逸老亭','宋祁','宋','宋诗','song-poetry','','[]','逸駕歡迎養，飛軒適所宜。',96,'全唐诗/poet.song.12000.json','["逸駕歡迎養，飛軒適所宜。", "營菟茲寓老，趨鯉即聞詩。", "地勝心逾放，人閒趣自奇。", "嵩雲來冒棟，滎溜下通池。", "靜偶惟黄卷，僊謠雜紫芝。", "窗風伴披衽，簷月對支頤。", "相筆留齊榜，邦侯慶壽巵。", "美哉翬棘詠，兼記掛冠時。"]'),
('098a9ad6-6f74-4e76-8382-fb7672de08fe','答朱彭州惠茶長句','宋祁','宋','宋诗','song-poetry','','[]','芳茗標圖舊，靈芽薦味新。',144,'全唐诗/poet.song.12000.json','["芳茗標圖舊，靈芽薦味新。", "摘侵雲崦曉，收盡露腴春。", "焙煖烘蒼爪，羅香弄縹塵。", "鐺浮湯目徧，甌漲乳花勻。", "和要瓊爲屑，烹須月取津。", "飲萸聞藥錄，奴酪笑傖人。", "雪沫清吟肺，冰甆爽醉唇。", "嗅香殊太觕，瘠氣定非真。", "坐憶丹丘伴，堂思陸納賓。", "由來撤膩鼎，詎合燎勞薪。", "得句班條暇，分甘捉麈晨。", "二珍同一餉，嘉惠愧良鄰。"]'),
('b4465de1-32d0-42a0-991c-f2b1bd1b88a0','答朱彭州喜雪','宋祁','宋','宋诗','song-poetry','','[]','雪集先何所，天彭關內州。',144,'全唐诗/poet.song.12000.json','["雪集先何所，天彭關內州。", "雲澌結河漢，風礫灑林丘。", "眩晃三霄接，繽紛一氣浮。", "光逢晨晛薄，花得冥寒稠。", "拂樹瓊爭動，縈牆粉暫留。", "縮毛驚莋馬，埋目憚吳牛。", "客至蘭矜曲，仙歸鶴擁裘。", "鹽邊混熬素，玉處亂方流。", "併響鳴巖竹，分滋浹壟麰。", "印沙鴻雁喜，蔽葉鷓鴣愁。", "蒙福沾餘潤，稱觴隔並游。", "錦官才涷雨，賡和負妍謳。"]'),
('c534b5de-08c1-4c15-bc7b-b1974116cb41','訪李生野墅','宋祁','宋','宋诗','song-poetry','','[]','風物澹蕭辰，陵阿訪隠淪。',72,'全唐诗/poet.song.12000.json','["風物澹蕭辰，陵阿訪隠淪。", "野杠裁度馬，溪路劣生塵。", "認菊知陶宅，觀禾識魯囷。", "林臯偏樂我，魚鳥似留人。", "山霽羣妍露，林虛衆籟新。", "長沮亟相語，非敢問迷津。"]'),
('6c7d2e54-960a-436c-999b-645819c87d25','書懷寄郭正','宋祁','宋','宋诗','song-poetry','','[]','僑籍依三輔，愁顛徧二毛。',96,'全唐诗/poet.song.12000.json','["僑籍依三輔，愁顛徧二毛。", "星灰對遒盡，淚卷掩劬勞。", "併歎絲兼路，都捐筆與刀。", "思旌初不定，離緒僅堪繰。", "醜是流離子，材真樸遬曹。", "未成虞弁進，旋似郭竽逃。", "邑聚巑岏合，都城鬰律高。", "惟餘故人意，戀戀劇綈袍。"]'),
('a9477bde-350d-4a68-bd77-40f392a9ce2f','螢','宋祁','宋','宋诗','song-poetry','','[]','腐化何微眇，孤光只自求。',72,'全唐诗/poet.song.12000.json','["腐化何微眇，孤光只自求。", "單飛一金躍，羣散數星流。", "廢苑蒼茫夜，離宮窈窕秋。", "戍埤同燼落，客幔共燈愁。", "明滅風前亂，裴回葉處留。", "人間厭白鳥，不爲盡餘羞。"]'),
('7fa61736-8c81-4f16-a2fe-25976f9ed48f','和梅侍讀給事秋雪','宋祁','宋','宋诗','song-poetry','','[]','朔氣迎秋晏，因成糅雪飄。',72,'全唐诗/poet.song.12000.json','["朔氣迎秋晏，因成糅雪飄。", "園賓驚早賦，郢曲愛新調。", "雜霰鳴寒蘀，紛花混晚苕。", "光含闕邊鳳，溫借省中貂。", "縞頃纔供望，鹽波已屢銷。", "今年屬清思，旻宇其寥寥。"]'),
('64963b24-e962-4314-9700-cd54879c870b','立春前二日獲雪','宋祁','宋','宋诗','song-poetry','','[]','佳雪春前降，層陰臘外留。',192,'全唐诗/poet.song.12000.json','["佳雪春前降，層陰臘外留。", "日昏霏霰集，風定舞花稠。", "浩氣皚皚徧，繁光衮衮流。", "灑林初亂塢，拂瓦暗平溝。", "洞矗三雲仗，山迎萬玉侯。", "客車羊作駕，仙氅鶴供裘。", "只有歌堪和，都無色可侔。", "險堆憐傍砌，斜濕愛侵幬。", "面旋成遲落，繽紛不頓休。", "粉塘連北渚，縞頃接西疇。", "興往惟思戴，賓來但憶鄒。", "絮痕侵柳動，鹽影著波浮。", "宿莽攢瑶草，長隄卧素虯。", "正緣先畢雨，併欲潤天麰。", "應禱驅民癠，呈祥溢里謳。", "長人蒙帝力，歡酌任言醻。"]'),
('5e7c9b3a-44d1-4b94-b605-77ee73677174','小雪','宋祁','宋','宋诗','song-poetry','','[]','低雲淡河界，零霰集天涯。',96,'全唐诗/poet.song.12000.json','["低雲淡河界，零霰集天涯。", "樹亂三眠絮，叢迷五出花。", "舞風都擬重，入隙故成斜。", "密瓦平將半，前山暝欲遮。", "漸堪迷凈練，併欲誤疏麻。", "粉出房陵水，鹽飛海岸沙。", "舟來戴逵宅，客過李王家。", "此日長安酒，旗高未易賒。"]'),
('b1321dcf-a6b7-42eb-bba8-6ddbb886a442','感懷','宋祁','宋','宋诗','song-poetry','','[]','天與疏慵地，人無榮進心。',72,'全唐诗/poet.song.12000.json','["天與疏慵地，人無榮進心。", "死灰差免溺，棄杖即成林。", "主諾固多暇，避賢懷所欽。", "難邀潁川鳳，敢望漢臺金。", "倚酒狂雖在，荷蓑歲已侵。", "恭聞容考績，緣此未投簪。"]'),
('a9ed3023-50b8-42e0-8504-5edd53e423c4','新筍成竹','宋祁','宋','宋诗','song-poetry','','[]','雨町犀株突，陽臯錦槊攢。',96,'全唐诗/poet.song.12000.json','["雨町犀株突，陽臯錦槊攢。", "竅均軒世律，皮解漢廷冠。", "冉冉生能直，蕭蕭意自寒。", "翠雲舒作葉，碧血染爲竿。", "梢弱烟方定，筠浮粉未乾。", "拋陰照流水，迸節犯朱欄。", "會待翔鵷集，非緣戲馬殘。", "林間誰共賞，坐想七賢歡。"]'),
('6e3a489c-19e1-4b62-943f-ff9aa09da1bb','送馬軍范太尉','宋祁','宋','宋诗','song-poetry','','[]','平狄方開府，鎸羌舊著名。',120,'全唐诗/poet.song.12000.json','["平狄方開府，鎸羌舊著名。", "新提建章騎，入領羽林兵。", "賜橐千金重，留車兩印榮。", "已封頭尚黑，休戰髀還生。", "大旆前驅影，鳴鐃後隊聲。", "軷壇勝算爵，客飯飫侯鯖。", "山背迷榆塞，雲披認薊城。", "介圭朝漢幄，釦仗侍軒營。", "悵別疏華恨，勤歸杕杜情。", "君看畫像處，麟閣近西清。"]'),
('ba98317f-d1d9-4d7a-8b20-8770e8f46569','喜連君錫過郡','宋祁','宋','宋诗','song-poetry','','[]','稍稍客引去，依依君見過。',96,'全唐诗/poet.song.12000.json','["稍稍客引去，依依君見過。", "胡爲困重趼，正欲問無他。", "甑黍驚方熟，犀談省舊訛。", "感餘祗惝怳，衰罷有蹉跎。", "直取憂襟解，聊從醉弁俄。", "緩行清白酒，隨意短長歌。", "臯壤星霜宴，纓瓖塵垢多。", "且應留從僕，同賞二山阿。"]'),
('f659366d-8ccb-4442-98bf-2c68b940dfb5','送聞大夫遊西天','宋祁','宋','宋诗','song-poetry','','[]','五竺能仁里，重游路不迷。',96,'全唐诗/poet.song.12000.json','["五竺能仁里，重游路不迷。", "詔辭丹鳳北，身到白龍西。", "野凈榴花早，林暄貝葉齊。", "暮雲程次闊，斜月笠前低。", "燕嶺長銜霧，金河不貯泥。", "梵王分供食，戍校接征鼙。", "窣堵方增飾，祇園得徧躋。", "無容带歸錫，秦蹕待新題。"]'),
('d602a8e5-a55c-42ae-a85c-5ea78ffb0939','覽中丞尚書譙陳二郡新詩','宋祁','宋','宋诗','song-poetry','','[]','自頃辭台路，陪京擁使珂。',120,'全唐诗/poet.song.12000.json','["自頃辭台路，陪京擁使珂。", "遺音追正始，新韵徧中和。", "贈答劉公數，登臨叔子多。", "腸迴初有感，耳熱遂成歌。", "驚夢春塘草，歡顔雪席酏。", "拍殘吳子夜，唱殺楚陽阿。", "勝氣籠雲沆，清懷貯月波。", "無妨爍顔謝，莫獨與羊何。", "譙里鳴騶入，陳郊露冕過。", "二邦留雅咏，棠樹共婆娑。"]'),
('379ef167-17a3-4e48-ba74-b00e374beeb5','感事寄子明中丞','宋祁','宋','宋诗','song-poetry','','[]','久玷三雲從，仍叨千石榮。',288,'全唐诗/poet.song.12000.json','["久玷三雲從，仍叨千石榮。", "羸軀付多病，怯計會無成。", "出守非嚴助，何年召郤萌。", "風摧向陽藿，霜變度江橙。", "畫閣勤聽訟，春疇力勸耕。", "遂慚循吏術，姑促縣官征。", "害馬直宜去，勞魚實恐赬。", "人心久忘戰，朝議近論兵。", "戍鎖關南數，邊烽隴右明。", "將機猶嚄唶，賊膽尚縱橫。", "說士爭操牘，謀臣屈請纓。", "已聞疲轉粟，安得但嬰城。", "且許和戎利，重尋撓酒盟。", "安危繫公等，指授盡時英。", "幸有千金募，須容八陣精。", "待衰曹劌鼓，長揖亞夫營。", "刷憤宜修德，時巡況作京。", "矢方射嶓冢，力欲斬長鯨。", "憲紙言常屢，王塗日以清。", "悉心前席重，直指佞人驚。", "仗下霜餘凜，班回佩倚鳴。", "早調黄鉉鼎，催獻惡梟羹。", "顧我罹飛語，于茲類倒行。", "鬼神慚賈誼，唇舌避君卿。"]'),
('17b2ec3a-84e8-4d21-b568-9e3ba2ef609d','寄題外門亭園','宋祁','宋','宋诗','song-poetry','','[]','外家真大隠，亭圃枕城闉。',96,'全唐诗/poet.song.12000.json','["外家真大隠，亭圃枕城闉。", "談樹能留客，飛鷗不畏人。", "白雲仙嶺曙，脩竹禊堂春。", "溪遠尋難盡，林幽趣旋新。", "愛山仍作屐，裁縠便爲巾。", "僧赴禺中飯，樵歸落照鄰。", "宅成翻忝相，里舊況依仁。", "千騎過從數，連章刻翠珉。"]'),
('31561076-9aef-4edd-a9f5-535375217706','喜刁從事見過','宋祁','宋','宋诗','song-poetry','','[]','窮閻久藏疾，有客獨迴輪。',72,'全唐诗/poet.song.12000.json','["窮閻久藏疾，有客獨迴輪。", "密契瞻松茂，羈懷慰蓼辛。", "猶龍八才子，嗅雉一畸人。", "藜藋仍開逕，樵蘇頼庶貧。", "吾僚青眼舊，今世白頭新。", "尚倚王陽仕，終彈屋幘塵。"]'),
('9282426b-1405-4fb4-ab21-d51d170eb698','楊都官知隨陽君自蜀守爲計倅既而出郡','宋祁','宋','宋诗','song-poetry','','[]','棧道迴忠馭，牢盆幹計貲。',72,'全唐诗/poet.song.12000.json','["棧道迴忠馭，牢盆幹計貲。", "文書三署草，兄弟五常眉。", "遽爾分符竹，欣然捧詔芝。", "疾驅關外傳，奉引漢東旗。", "夕月同離恨，春膏徧我私。", "他年五君詠，應記阮咸麾。"]'),
('7c31f1f5-3e3d-40ee-af37-fb1ba26cdc29','和龐丞相','宋祁','宋','宋诗','song-poetry','','[]','顧我支離甚，惟公念不才。',240,'全唐诗/poet.song.12000.json','["顧我支離甚，惟公念不才。", "朱顔爲列郡，白髮入中臺。", "閣道通天祿，宮門拂斗魁。", "論班元後鄭，作賦或延枚。", "病肘垂楊老，危心一櫓摧。", "根愁江北變，葉喜洛陽來。", "自昔邊州重，當年蜀馭催。", "燒烽看朔漠，捫井歷崔嵬。", "粗可繙前史，何能調禁財。", "流光成浩蕩，孤宦易嫌猜。", "曲外悲絃剩，機頭謗錦開。", "無功慚遠志，有吏笑然灰。", "左轄真虛忝，仙曹復濫陪。", "門鶋愁眩轉，軒鶴老毰毸。", "傾否知攸往，成章恧所裁。", "賈生空問卜，楚客但勞媒。", "特召依明主，生還揖上台。", "緹油觀冊府，巾履記翹材。", "長跪懷人句，徐傳道舊杯。", "今茲宣父冶，終得鑄顔回。"]'),
('44dc82a1-6170-45a9-8021-7a2a9700d1fd','送常熟尉錢訪','宋祁','宋','宋诗','song-poetry','','[]','雋譽高鄉品，仙姿並國游。',72,'全唐诗/poet.song.12000.json','["雋譽高鄉品，仙姿並國游。", "新恩紺綸綬，遺社酎金侯。", "賦閣諸傖筆，塵緇倦客裘。", "平明催沖鷁，幾信候潮濬。", "下鼓蓴縈箸，持螯酒溢甌。", "江南三月草，爲子剩離憂。"]'),
('fd162acf-1007-4938-b4dc-c0404822e94e','寄王崇','宋祁','宋','宋诗','song-poetry','','[]','築室占層峰，高眠商嶺東。',72,'全唐诗/poet.song.12000.json','["築室占層峰，高眠商嶺東。", "鉢薰諸佛飯，窗占上皇風。", "餌桂將成父，搴芝固有童。", "驚猿參唳鶴，伸鳥雜經熊。", "客有希何點，人多拜德公。", "春雲不持寄，誰欲問山中。"]'),
('ac69d230-bb2e-435c-be5e-ec1108afa85a','詠史','宋祁','宋','宋诗','song-poetry','','[]','古有容容福，人譏齪齪員。',120,'全唐诗/poet.song.12000.json','["古有容容福，人譏齪齪員。", "生能巧非奏，死戒直如弦。", "欲重高門地，非論媚竈天。", "詩書大儒冢，絲竹後堂旃。", "東閣翻芻馬，西園竊富錢。", "道謀誰執咎，戶選不因賢。", "朱鼓成妖日，羌鶡入賀年。", "須防反室詔，終取闔門憐。", "異日讒成錦，先時默似蟬。", "空貽後人嘆，流涕掩青編。"]'),
('839a096a-510d-42ea-a7d8-b094d5f3ec2b','贈通教大士善升','宋祁','宋','宋诗','song-poetry','','[]','此心通妙法，他劫侍尊顔。',72,'全唐诗/poet.song.12000.json','["此心通妙法，他劫侍尊顔。", "水月何嘗動，煙雲相與閒。", "香浮經葉暗，霜點頷髭班。", "施寶上人往，銜花谷鳥還。", "梵潮鳴夜浦，天柱落秋山。", "句偈聊持贈，非緣文字間。"]'),
('eec89229-8773-49c0-8a1c-3d4a44ee7fab','奉和長兄歲晏抒懷','宋祁','宋','宋诗','song-poetry','','[]','天暮雪雲繁，相將客兔園。',72,'全唐诗/poet.song.12000.json','["天暮雪雲繁，相將客兔園。", "老從星髮見，歲伴日車翻。", "別葉晴猶舞，征鴻暝更軒。", "事君纔寸祿，知我是空言。", "競進家爭璧，同聲伯有塤。", "重吟探懷句，更代一狐溫。"]'),
('db3cfea0-b986-4d26-8f64-f6c05ecddc41','寄天休學士','宋祁','宋','宋诗','song-poetry','','[]','春暝蓬山直，知君思緒多。',96,'全唐诗/poet.song.12000.json','["春暝蓬山直，知君思緒多。", "玉蟾吟瀉滴，朱幕卧生波。", "談麈飄無幾，書刀削久訛。", "魚沈江上夢，雞唱汝南歌。", "落蔕燈煤暗，雙盤露蘂和。", "烟浮溫室樹，雲澹客星河。", "牟首傳清𢧕，章溝疊迥鼉。", "子雲惟寂寞，尚自奈嘲何。"]'),
('9a9d8494-26ef-49c0-b3f5-d4968a2905a9','夏日舊疢間發','宋祁','宋','宋诗','song-poetry','','[]','老至非無素，憂來詎一源。',96,'全唐诗/poet.song.12000.json','["老至非無素，憂來詎一源。", "河魚真得疾，牀蟻誤成喧。", "㕮咀供晨匕，蹣跚逼夕軒。", "何宜忝蓬觀，祗合令文園。", "霜挫顛毛禿，雲添眼膜昏。", "問天寧有禱，依佛即忘言。", "燕麥摇風砌，蚌苔壓雨垣。", "冒榮難自效，三宿戀君恩。"]'),
('bd2a3003-5761-4410-aa8b-ed5765f490d5','蘭皋亭','宋祁','宋','宋诗','song-poetry','','[]','信美蘭臯地，疏椽構迥軒。',72,'全唐诗/poet.song.12000.json','["信美蘭臯地，疏椽構迥軒。", "山林閒處樂，溪瀨靜中喧。", "春桂開前塢，秋菘接後園。", "舟來無盡曲，客到不空罇。", "夕月生帷鑒，晴雲抱棟痕。", "主人貪紬績，未暇答驚猿。"]'),
('53dae435-7462-4be7-8919-3cd5e9b97de8','送胡學士赴益州漕','宋祁','宋','宋诗','song-poetry','','[]','帝念西南重，頻年輟俊翹。',120,'全唐诗/poet.song.12000.json','["帝念西南重，頻年輟俊翹。", "還臨二星野，催駕一封軺。", "地出褒中險，梯連劍外遥。", "蹲鴟蔽川沃，流馬餉軍饒。", "檄去方移蜀，書成遂薦譙。", "客橙薰露夕，官錦濯霞朝。", "卓市醪華美，渝僮舞勢趫。", "省蘭聊罷幄，亭柳重攀條。", "煩使資游刃，歸懷極本朝。", "前知宣布曲，即日徧歡謠。"]'),
('354fcaa0-a4b0-48eb-bc8d-2acff8a5f12c','羸疾益間呈聶長孺學士','宋祁','宋','宋诗','song-poetry','','[]','病緒蹇騷騷，彌旬曠坐曹。',120,'全唐诗/poet.song.12000.json','["病緒蹇騷騷，彌旬曠坐曹。", "緣憂初得損，非巧亦成勞。", "計月銷雙臂，驚年變二毛。", "隙塵間日滿，鐺藥晬時熬。", "顧此逢熙盛，紛吾異俊髦。", "濫趨華雉省，清舐翠螭毫。", "數米仍能飽，搶榆不顧高。", "聊尋秘方枕，更繕養生刀。", "夕穗含風月，秋禽企露臯。", "比來差勝晤，有意伴持螯。"]'),
('deb19421-9d0d-4763-8b76-48eb51121ecf','予昔游雲臺觀謁希夷先生陳摶祠堂緬想其人今追作此詩','宋祁','宋','宋诗','song-poetry','','[]','仙館三峰下，年華百歲中。',72,'全唐诗/poet.song.12000.json','["仙館三峰下，年華百歲中。", "夢休孤蝶往，蛻在一蟬空。", "蕊笈微言秘，霄晨浩氣通。", "丹遺舐後鼎，林遣御餘風。", "市霧沈荒白，餐霞委暗紅。", "峨眉有歸約，飛步與誰同。"]'),
('cc3e7e45-83dd-4cdd-956a-091e5d13096c','還鄉','宋祁','宋','宋诗','song-poetry','','[]','自昔去先閈，乃今還故廬。',96,'全唐诗/poet.song.12000.json','["自昔去先閈，乃今還故廬。", "隴桑濡露外，巖桂遣風餘。", "稍識烏衣巷，相過栗里輿。", "感存橫涕數，道舊愬杯徐。", "水涸溪容耗，林殘野氣疏。", "鳥喧晴處陌，烟宿暝時墟。", "彭澤期歸去，臨邛喜第如。", "擊鮮無久慁，趨局畏官書。"]'),
('3ea77a2d-65dd-47c5-80d8-c63b7a1496f1','憶浣花泛舟','宋祁','宋','宋诗','song-poetry','','[]','早夏清和在，晴江沿泝時。',72,'全唐诗/poet.song.12000.json','["早夏清和在，晴江沿泝時。", "岸風摇鼓吹，波日亂旌旗。", "醉帟牽緗蔓，游鬟撲絳蕤。", "樹來驚浦近，山失悟舟移。", "雅俗西南盛，歸軺東北馳。", "此歡那復得，拋恨寄天淮。"]'),
('82e6143b-5c72-4c66-81fa-35ab57e6092d','大像閣','宋祁','宋','宋诗','song-poetry','','[]','追碧被層顛，靈姿映大千。',72,'全唐诗/poet.song.12000.json','["追碧被層顛，靈姿映大千。", "天光白毫際，山色鈿螺邊。", "海客供鬘貝，江神捧坐蓮。", "銜花馴鹿往，投鉢毒龍眠。", "影壓中流浪，香飄萬里船。", "慈威濟終古，何止一長川。"]'),
('f8c37676-db7b-409b-ad95-08298b2ff337','覽蜀宮故城作','宋祁','宋','宋诗','song-poetry','','[]','國破江山老，人亡岸谷摧。',96,'全唐诗/poet.song.12000.json','["國破江山老，人亡岸谷摧。", "鴛飛今日瓦，鹿聚向時臺。", "故苑猶霏雪，荒池但劫灰。", "赬遺糊處壤，闔記數殘枚。", "恨月窺林下，悲風覓隴來。", "依城狐獨速，失厦燕裴回。", "廢社纔存柳，陰垣自上苔。", "有情惟杜宇，長爲故王哀。"]'),
('b47269e1-82f9-459d-b882-2f225fc3967d','早夏出城書所見成篇','宋祁','宋','宋诗','song-poetry','','[]','肅駕來墟落，悠然矚霽氛。',72,'全唐诗/poet.song.12000.json','["肅駕來墟落，悠然矚霽氛。", "飛花缺林影，驚鷺破洲羣。", "牧徑尋還失，蕘歌斷更聞。", "平蕪與天遠，孤日带霞曛。", "梁雉今誰嗅，城狐古不熏。", "楚人矜節物，腰艾鬭蘭芬。"]'),
('bcd0e4b7-f830-4b64-86cb-f3518d4f9f46','詠石','宋祁','宋','宋诗','song-poetry','','[]','勝具論終古，尋幽屬政成。',120,'全唐诗/poet.song.12000.json','["勝具論終古，尋幽屬政成。", "待時藏磊落，得地鬭崢嶸。", "錦駁苔文露，虹浮玉氣明。", "夢池分到影，窗岫讓吟情。", "乍恐翻湘燕，真疑刻漢鯨。", "滴秋湖溜入，觸曉寺雲生。", "紫漢仙機遠，西陵客棹輕。", "映花雕檻接，礙竹翠鞭橫。", "扣鼓非臨岸，傳書異穀城。", "願將侯鵲瑞，旦暮奉承平。"]'),
('101d05ed-6090-4f0d-ba16-9c481043dfeb','春雪','宋祁','宋','宋诗','song-poetry','','[]','遲旭收天宇，層陰糅雪英。',72,'全唐诗/poet.song.12000.json','["遲旭收天宇，層陰糅雪英。", "傍階聊積玉，妝樹旋消瓊。", "越驛兼梅墜，章臺代絮縈。", "風回飛自急，池暖白猶輕。", "曉溜承隅滴，寒澌逼沼生。", "持杯一相勞，膏脈趁春耕。"]'),
('a02152fd-5925-4152-8524-bc6e2fd8a427','書局梅聖俞劉仲更二學士訃問繼至潸然有感','宋祁','宋','宋诗','song-poetry','','[]','二子繼淪閼，惜哉難具論。',77,'全唐诗/poet.song.12000.json','["二子繼淪閼，惜哉難具論。", "麈毛如昨語，墨藁未乾痕。", "翣霧迷歸柩，{流氵=忄}風慘葬原。", "風流盡逝水，日月促陳根。", "從古死皆有，由來命罕言。", "病夫長慟罷，翻幸巋然存。"]'),
('1a5cea5d-581d-424f-b042-bea4220aa41a','思歸','宋祁','宋','宋诗','song-poetry','','[]','心悸真摧櫓，年衰逼異糧。',216,'全唐诗/poet.song.12000.json','["心悸真摧櫓，年衰逼異糧。", "西征何日賦，東走向來狂。", "遂隔承明謁，虛稱建禮郎。", "去都魂黯黯，思幄淚浪浪。", "見䓞慚紆綬，逢荷誤索囊。", "醒無次公酒，老畏侍中香。", "前席初延問，煩言已中傷。", "翕眉爭恃笑，繞指詎容鋼。", "事隠或投杼，根危因拔楊。", "陰收主父草，幾落黨人章。", "霧露淮天惡，亭臯楚塞長。", "平時猶有感，爾日固迴腸。", "溪漲淹蒲牒，洲風挫葯房。", "芿區晴外遠，山疊暝前蒼。", "毒虺寒猶蠚，饑豺晝不藏。", "若爲貪坐閣，自此戒垂堂。", "淪骨深恩在，雕蟲緒業荒。", "身孤惟夕夢，時到黼帷傍。"]'),
('5774f1d0-4b8f-4edc-b076-bddedc9c4cc9','硤石寺','宋祁','宋','宋诗','song-poetry','','[]','衮衮上層巔，飛空寶構聯。',72,'全唐诗/poet.song.12000.json','["衮衮上層巔，飛空寶構聯。", "山林楚遺塞，樓閣佛諸天。", "午剎中峰影，晨香衆壑烟。", "奫淪一水注，開闢二崖穿。", "旭日生巖罅，歸雲宿橑邊。", "吾游常草草，暫對社師蓮。"]'),
('27fae0e1-d9c9-4696-9874-6e0fa185309b','哭中山公三十韵','宋祁','宋','宋诗','song-poetry','','[]','天欲鳴文鐸，公先露上珍。',288,'全唐诗/poet.song.12000.json','["天欲鳴文鐸，公先露上珍。", "談鋒貫千載，文緯補三辰。", "海浪扶鵬徙，雝朝簉鷺振。", "盪邪初奏雅，闢路近還淳。", "汗竹刊譌徧，仙蔾遞宿勤。", "漢家方授記，趙世本多神。", "稍上窔遼禪，親逢堀吻巡。", "每篇稱陸賈，四頌識崔駰。", "接晝來詞禁，軒霞切睿宸。", "金聲兼振玉，絲緒遂成綸。", "預讀蘭圖字，時參豹尾塵。", "批成五色詔，乞守兩朱輪。", "虎幄思賢數，鼇山召節新。", "請聞裨帝采，有意靖宮鄰。", "畀虎潜興譖，猶龍詎肯馴。", "符魚貪六六，國猘避狺狺。", "東震重光啟，南箕哆焰淪。", "觸邪觀豸久，斂手避驄頻。", "勇退寧無謂，斜飛故有因。", "終承紫芝召，還返碧桃春。", "丁直何嘗屈，蘭幽止自紉。", "歌成接輿鳳，書止太初麟。", "竟遂東平樂，非憂宣子貧。", "蒙莊祥止止，尼父誨循循。"]'),
('8a0efb29-401e-451c-87cb-9abd5971be49','三泉縣龍洞洞門深數十步呀然復明皆自然而成','宋祁','宋','宋诗','song-poetry','','[]','虬洞閟靈峰，緣虛一線通。',72,'全唐诗/poet.song.12000.json','["虬洞閟靈峰，緣虛一線通。", "雲披雙壁敞，樹補半巖空。", "穊竹森烟纛，飛泉曳玉虹。", "重蘿不肯晝，陰壑自然風。", "嶺斷天斜碧，崖傾日倒紅。", "浮邱邈難遇，留恨翠微中。"]'),
('c370d800-3859-4e05-8dd9-de543801f850','次韵和李長學士正月二十八日出郊見寄之作','宋祁','宋','宋诗','song-poetry','','[]','雅俗傳祠日，年華重宴辰。',72,'全唐诗/poet.song.12000.json','["雅俗傳祠日，年華重宴辰。", "初陽澹江霧，小雨破街塵。", "客蓋浮輕吹，齋刀儼後陳。", "林芳催兔目，原色換龍鱗。", "壤路歌聲雜，褠倡舞疊新。", "持杯徧酬客，惟欠眼中人。"]'),
('764060cf-7b53-47f8-b8b7-6ff46f95a23e','紀贈致政燕侍郎','宋祁','宋','宋诗','song-poetry','','[]','中朝鵠髮俊，得謝寵安車。',96,'全唐诗/poet.song.12000.json','["中朝鵠髮俊，得謝寵安車。", "碧落超新秩，承明別舊廬。", "叔時今老矣，司寇此歸歟。", "畫有封厨秘，詩多乙牘餘。", "雲情元自遠，舟意本常虛。", "酌酒朋三壽，揮金輩二疏。", "深恩仍給俸，令子復將輿。", "幾日西清對，留光惇史書。"]'),
('9d2a86fe-ec76-4c28-99c2-b954ecc23c07','答程職方冬至前一日江上觀魚','宋祁','宋','宋诗','song-poetry','','[]','歲晏修漁事，邀賓俯碧流。',72,'全唐诗/poet.song.12000.json','["歲晏修漁事，邀賓俯碧流。", "鳴榔截橫浦，叢糝聚寒洲。", "舴艋爭離合，鸕鷀巧泛浮。", "魴來比河上，鯿出似槎頭。", "雪膾供庖俎，梅齏促宴甌。", "言詩知有意，不爲百金求。"]'),
('15ac2c11-2f22-46e4-ad4e-01ccb9fce157','抒懷呈同舍','宋祁','宋','宋诗','song-poetry','','[]','本自草茆賤，非貪箕斗名。',96,'全唐诗/poet.song.12000.json','["本自草茆賤，非貪箕斗名。", "客心摧似櫓，官謗沸如羹。", "晝役迴腸數，秋扶病體輕。", "長年書轉忘，多露涕先橫。", "已分嘲揚吃，頻遭詈楚傖。", "矜毗兩蝸角，榮辱一棋枰。", "越蟹丹螯美，吳蓴紫線縈。", "他年五斗米，猶足代寒耕。"]'),
('739a0b48-9a04-4cc9-a286-65a0b123b33c','自詠','宋祁','宋','宋诗','song-poetry','','[]','客舍張羅靜，流年激箭過。',72,'全唐诗/poet.song.12000.json','["客舍張羅靜，流年激箭過。", "愁餘驚斛滿，淚盡覺珠多。", "鶗鴂悲秋極，芎藭奈疾何。", "振纓清濁水，持酒短長歌。", "潘岳傷憀慄，蘇生困揣摩。", "經綸誰一問，薖軸老中阿。"]'),
('d5aefbfc-3451-431f-ab7c-a24049579320','蜀地海棠繁媚有思加膩幹豐條苒弱可愛北方所未見諸公作詩流播西人余素好玩不能自默然所道皆在前人陳迹中如國風申章亦無愧云','宋祁','宋','宋诗','song-poetry','','[]','蜀道天餘煦，珍葩地所宜。',168,'全唐诗/poet.song.12000.json','["蜀道天餘煦，珍葩地所宜。", "濃芳不隠葉，併艷欲然枝。", "襞綵分羣萼，均霞點萬蕤。", "迴文錦成後，夾煎燎烘時。", "蜂蕊迎銜密，鶑梢向坐危。", "淺深雙絕態，啼笑兩妍姿。", "絳節排煙竦，丹釭落带垂。", "童容鄣畏薄，便面到憂遲。", "媚日能徐照，暄風肯遽吹。", "惜觀當晼晚，留恨付離披。", "麗極都無比，繁多僅自持。", "損香饒麝柏，照影欠瑶池。", "畫要精侔色，歌須巧騁辭。", "舉尊頻語客，細摘玩芳期。"]'),
('92ae94d4-2dfd-4a5d-a8d6-2f7af1c0f93b','送趙御史仲禮之任南臺并柬兼善達公經歷元載王公用道孔公二御史','宋祁','宋','宋诗','song-poetry','','[]','天子龍沙拜法官，議郎親戴辟邪冠。',160,'全唐诗/poet.song.12000.json','["天子龍沙拜法官，議郎親戴辟邪冠。", "曉辭漠北冰霜重，秋到江南草樹寒。", "諫疏頻煩明主聽，題詩長共故人看。", "應憐閭里誅求急，尚布朝廷禮意寬。", "幕下風清鳴一鶚，臺端雪霽見雙鸞。", "寥寥渡海三冬翮，翽翽凌空五色翰。", "晉代新亭蒼蘚合，梁朝舊地土花殘。", "石城慷慨悲袁粲，別墅風流憶謝安。", "千里憑高麾綉斧，幾回攬轡並銀鞍。", "諍臣事業須公等，努力明時匪素餐。"]'),
('49985982-254b-43be-a378-cbc74be626a5','去年十月赴淮陽今實周一歲歲中三遷遂直內禁作詩記其出處','宋祁','宋','宋诗','song-poetry','','[]','去年詔赴淮陽郡，手合魚符擁使輈。',96,'全唐诗/poet.song.12000.json','["去年詔赴淮陽郡，手合魚符擁使輈。", "今歲恩叨玉堂署，頭簪鳳筆從宸游。", "孤蓬逐吹無時定，倦鳥逢林只自休。", "暗隙遂容私照日，奔湍信有不沈舟。", "身歸詎敢夸三組，目眩何能讀九丘。", "白髮紛垂文思軋，此生榮遇若爲酬。"]'),
('11ea9331-1aed-49ca-9e5a-61c148f01100','南郊祠所上章攝事二首  其一','宋祁','宋','宋诗','song-poetry','','[]','七里城南路，齋祠宿下房。',24,'全唐诗/poet.song.12000.json','["七里城南路，齋祠宿下房。", "遠烟晨燎地，斜日夕牲場。"]'),
('386b5d2e-2fa6-4078-bfac-3691820cf8ba','南郊祠所上章攝事二首  其二','宋祁','宋','宋诗','song-poetry','','[]','上辛茲攝事，瑞祝本通天。',24,'全唐诗/poet.song.12000.json','["上辛茲攝事，瑞祝本通天。", "自此春秋筆，還書大有年。"]'),
