('64546f95-e5f6-4aa6-adef-6be6ae10b8c1','荼蕊花','宋祁','宋','宋诗','song-poetry','','[]','媚叢無奈密，柔蔓不勝長。',36,'全唐诗/poet.song.12000.json','["媚叢無奈密，柔蔓不勝長。", "非鄰粉自白，似俠骨中香。", "不分櫻桃豔，名先播樂章。"]'),
('b2dd1880-3450-49c6-b135-b1261c093431','祗役道中二首  其一','宋祁','宋','宋诗','song-poetry','','[]','濩落無容物，嶔碕可笑人。',48,'全唐诗/poet.song.12000.json','["濩落無容物，嶔碕可笑人。", "唯當荷農笠，不稱薦華紳。", "宦味真韁鎖，生涯累水薪。", "窮途計安出，祗是有沾巾。"]'),
('bb244a26-f7e6-4039-94c7-3fe68483982f','祗役道中二首  其二','宋祁','宋','宋诗','song-poetry','','[]','絮亂東風急，花飛雜樹稠。',48,'全唐诗/poet.song.12000.json','["絮亂東風急，花飛雜樹稠。", "離家王粲恨，贈婦彥先愁。", "樵浦連檣度，旗亭數蓋留。", "癡人了官事，歸釣誤楂頭。"]'),
('e88e73fe-ca3a-4f01-bd68-953f4961e95e','題僧惠昇壁','宋祁','宋','宋诗','song-poetry','','[]','何年飛虎錫，此地鎖鷹房。',48,'全唐诗/poet.song.12000.json','["何年飛虎錫，此地鎖鷹房。", "水入禪心定，花飄供裓香。", "高談犀飾麈，清啜茗成槍。", "千騎嘗留此，籠紗照屋梁。"]'),
('2e129008-7fde-49c3-8037-9e476b979441','溪亭','宋祁','宋','宋诗','song-poetry','','[]','規日平空晚，澄波極望鮮。',48,'全唐诗/poet.song.12000.json','["規日平空晚，澄波極望鮮。", "簾飛古陶瓦，梁負會稽椽。", "戰綠低寒杜，漂紅泊晚蓮。", "黄昏無限意，江月對娟娟。"]'),
('12ea130c-3a10-49e4-b0c2-b02a8698cf22','同年譚綜掾江陵','宋祁','宋','宋诗','song-poetry','','[]','鄉樹湘雲外，行轅楚塞東。',48,'全唐诗/poet.song.12000.json','["鄉樹湘雲外，行轅楚塞東。", "不辭淹拔萃，聊欲辨無同。", "暝紫生寒岫，疏丹點暮楓。", "登樓有歸訊，爲附北歸鴻。"]'),
('edd38629-785c-41fa-93fb-a5514bd11318','黄泌昆仲歸江西','宋祁','宋','宋诗','song-poetry','','[]','爨樵殫楚桂，裘掖厭京塵。',48,'全唐诗/poet.song.12000.json','["爨樵殫楚桂，裘掖厭京塵。", "別路雙黄鵠，還家兩玉人。", "書園飄竹粉，鄉樹老梨津。", "電韵盈歸褚，中州賞有真。"]'),
('8f62c571-3b79-42f6-99c0-cea03e873832','家居','宋祁','宋','宋诗','song-poetry','','[]','賃廡接中林，迷途感慨深。',48,'全唐诗/poet.song.12000.json','["賃廡接中林，迷途感慨深。", "窮年不材木，提月退飛禽。", "官宇昏投版，私囊利挫針。", "病呻無用怪，不是顯時吟。"]'),
('ea6be5d0-f30d-447e-a16e-7c7c69076db5','晴雲','宋祁','宋','宋诗','song-poetry','','[]','春空無際碧，雲意靜悠悠。',48,'全唐诗/poet.song.12000.json','["春空無際碧，雲意靜悠悠。", "盡日隨風馭，迎昏抱月鉤。", "正宜銜迥隴，强欲蔽層樓。", "宋野何須問，鴻濛正掉頭。"]'),
('f2dc2d9e-9a77-446d-a4af-1ce95b2edcd6','道中見問津者','宋祁','宋','宋诗','song-poetry','','[]','欲問迷津意，都緣別徑多。',48,'全唐诗/poet.song.12000.json','["欲問迷津意，都緣別徑多。", "亡羊曾自此，老馬欲如何。", "旁午晨車邁，間關夕蓋過。", "不須貪遠客，危恨寄風波。"]'),
('814cfc93-8791-4f72-a83e-5300f70cfa0a','抒歎','宋祁','宋','宋诗','song-poetry','','[]','寒日不我駐，歲陰生事微。',48,'全唐诗/poet.song.12000.json','["寒日不我駐，歲陰生事微。", "孤懷百感萃，雙鬢二毛稀。", "樵突沉殘桂，塵編擁故幃。", "況無安邑累，身託故山薇。"]'),
('a2f9de48-e383-4a3a-a031-2b5876680525','和王君貺禁中寓直','宋祁','宋','宋诗','song-poetry','','[]','長樂疏鐘斷，昆池夕照收。',48,'全唐诗/poet.song.12000.json','["長樂疏鐘斷，昆池夕照收。", "晚風生似雨，仙霧爽如秋。", "鈞曲來深殿，宮花出御溝。", "雲天正如畫，璧月在西樓。"]'),
('674d6785-224b-43d3-843e-33b0e6345651','李國博齋中小山作','宋祁','宋','宋诗','song-poetry','','[]','觀閣幽期勝，窗扉列岫連。',48,'全唐诗/poet.song.12000.json','["觀閣幽期勝，窗扉列岫連。", "千巖狀稽嶺，一石記平泉。", "迥□仙湖境，低圍醉幕天。", "休論真假意，同是到忘筌。"]'),
('51b857d0-12cc-4ec9-93cb-e29c2fd69872','晚歸僦廡','宋祁','宋','宋诗','song-poetry','','[]','驅車廣陌陰，極望散煩襟。',48,'全唐诗/poet.song.12000.json','["驅車廣陌陰，極望散煩襟。", "霞破天逾凈，煙生樹始深。", "摻喧侵暝鼓，練急向寒砧。", "却入顔生巷，窮棲似故林。"]'),
('6d7df88f-f9e4-4c0c-b01f-fc35580ad3f0','晚秋客廡','宋祁','宋','宋诗','song-poetry','','[]','凉葉日幡幡，西風振旅魂。',48,'全唐诗/poet.song.12000.json','["凉葉日幡幡，西風振旅魂。", "客來聊解榻，童小未應門。", "蟬噪專林響，蝸移亂壁痕。", "缺然禽鹿性，持底報君恩。"]'),
('dbbd8bb4-cf0e-4388-bb00-9bb15de7a39d','傷和靖林先生君復二首  其一','宋祁','宋','宋诗','song-poetry','','[]','清瀨嚴生國，良田仲子居。',48,'全唐诗/poet.song.12000.json','["清瀨嚴生國，良田仲子居。", "姬姜生不娶，封禪死無書。", "竈冷丹何去，厨封畫已虛。", "詔函加美謚，不及裹輪車。"]'),
('5de7b3fc-8f96-487b-abae-21e41f8297d9','傷和靖林先生君復二首  其二','宋祁','宋','宋诗','song-poetry','','[]','筆精傳禊帖，句賞儷汀蘋。',48,'全唐诗/poet.song.12000.json','["筆精傳禊帖，句賞儷汀蘋。", "道勝吾忘我，賢嗟歲在辰。", "風愁青桂暝，露泣紫芝春。", "一束生芻贈，門無雜弔賓。"]'),
('171cc075-bc65-4dd8-82b3-3ce8a6b3414b','春夕','宋祁','宋','宋诗','song-poetry','','[]','捲幔星河近，嚴城鐘漏遲。',48,'全唐诗/poet.song.12000.json','["捲幔星河近，嚴城鐘漏遲。", "飛蟲集暗牖，棲鵲忌明枝。", "弱柳兼風困，高花戰露危。", "回腸正無頼，仍此卧遥帷。"]'),
('1b17c398-5696-490c-bb3c-6195c0ce9456','送丁殿直郴陽監軍','宋祁','宋','宋诗','song-poetry','','[]','渠浪撼殘星，飄然颺彩舲。',48,'全唐诗/poet.song.12000.json','["渠浪撼殘星，飄然颺彩舲。", "懷人送歸客，短候續長亭。", "望寺□垂組，還書待殺青。", "無妨軍壘隙，壺柘侑賓醽。"]'),
('68345899-2d47-46c6-ae30-30e4684d1655','西齋冬夕','宋祁','宋','宋诗','song-poetry','','[]','西海共摇落，居然彫歲深。',48,'全唐诗/poet.song.12000.json','["西海共摇落，居然彫歲深。", "林疏縱風怒，天慘趣雲陰。", "冰沼留寒鶩，燈簷射宿禽。", "懷人感衰鬢，自此不勝簪。"]'),
('3a1becc1-9595-4320-85ef-62709dd9d741','崔氏逍遥堂','宋祁','宋','宋诗','song-poetry','','[]','戚里封侯舊，家園締宇初。',48,'全唐诗/poet.song.12000.json','["戚里封侯舊，家園締宇初。", "據梧人化蝶，坐石客焚魚。", "砌草交垂带，窗筠就刻書。", "欲知真趣盛，長者數回車。"]'),
('4d61874d-3d02-4179-92c8-59ab09cd58c2','寒夜與伯氏晏坐','宋祁','宋','宋诗','song-poetry','','[]','對擁圓爐坐，蕭然念變衰。',48,'全唐诗/poet.song.12000.json','["對擁圓爐坐，蕭然念變衰。", "樹鳴餘葉亂，燈戰暗花危。", "罇酒伯仲雅，園荆兄弟枝。", "陶陶且相樂，低月半遥帷。"]'),
('12488716-9035-4be3-92be-c9e134fc62f0','僑屋睹燕葺舊巢因贈','宋祁','宋','宋诗','song-poetry','','[]','窮檐雙越燕，一再共年華。',48,'全唐诗/poet.song.12000.json','["窮檐雙越燕，一再共年華。", "巢戶差眠尾，泥痕燥哺花。", "惜無文杏庇，猶免翠簾遮。", "所頼同雞德，新豐遂識家。"]'),
('99063861-9fda-4376-b0c3-2bf57697cf67','楊太尉後園假山','宋祁','宋','宋诗','song-poetry','','[]','韜戟嚴中府，磓星寫翠岑。',48,'全唐诗/poet.song.12000.json','["韜戟嚴中府，磓星寫翠岑。", "嵐分一軒翠，雲護半庭陰。", "谷響迎壺柘，巖光射廡金。", "時平非聚米，緩带恣幽尋。"]'),
('98f6054e-38e9-4a42-8231-d80ec5d71637','送四舅朱掾赴英州','宋祁','宋','宋诗','song-poetry','','[]','拗柳亭皋晚，攀梅嶺路長。',48,'全唐诗/poet.song.12000.json','["拗柳亭皋晚，攀梅嶺路長。", "北辭鳷鵲月，南冒鷓鴣霜。", "越蠹催征候，珍鮭奉慶觴。", "片言民訟息，歸計竚林光。"]'),
('5a95f7d5-4a23-422d-b3e5-424ec077eed8','送徐秀才','宋祁','宋','宋诗','song-poetry','','[]','風鶂摧高羽，雲鵾慘別弦。',48,'全唐诗/poet.song.12000.json','["風鶂摧高羽，雲鵾慘別弦。", "倦隨東郭履，歸養豫樟年。", "客信憑梅隴，鄉歈伴月舷。", "君謀適不用，虛贈繞朝鞭。"]'),
('612ce1aa-1bf0-45d8-86e6-21856216ed88','送萬池秀才','宋祁','宋','宋诗','song-poetry','','[]','有客柅征輪，羈懷慰蓼辛。',48,'全唐诗/poet.song.12000.json','["有客柅征輪，羈懷慰蓼辛。", "來乘訪戴雪，歸趁浴沂春。", "酒所留飛蓋，談餘換爨薪。", "異時更月品，知冠汝南人。"]'),
('ccd2e9b0-4e86-44e6-8e50-b79273fdc257','僑廡','宋祁','宋','宋诗','song-poetry','','[]','瞿曇少病否，司寇正歸歟。',48,'全唐诗/poet.song.12000.json','["瞿曇少病否，司寇正歸歟。", "不鑿牆坯遁，猶煩里旅居。", "飯舂霜稜粟，羹糝雪畦蔬。", "願受爲氓籍，閒披種樹書。"]'),
('efb40b7c-0fde-411a-819d-d9b6b63f0cfe','雪夕','宋祁','宋','宋诗','song-poetry','','[]','恩華綿帝宇，花出瑞王年。',48,'全唐诗/poet.song.12000.json','["恩華綿帝宇，花出瑞王年。", "陰魄交光地，風霙雜下天。", "鹽波熬巨浸，縞頃界中田。", "有客方愁卧，先時履欲穿。"]'),
('04497406-c927-413d-9391-550e8f09af98','林鴉','宋祁','宋','宋诗','song-poetry','','[]','林鴉泊泊飛，剩欲送斜規。',48,'全唐诗/poet.song.12000.json','["林鴉泊泊飛，剩欲送斜規。", "城頭八九子，月中三帀枝。", "嚮晨常自警，鄰暝不應移。", "王孫無巧彈，此夜正羈雌。"]'),
('00c59950-4f4b-4fd4-9f5c-2bae30faa460','春晚寫望','宋祁','宋','宋诗','song-poetry','','[]','不覺春芳晏，翻成客望勞。',48,'全唐诗/poet.song.12000.json','["不覺春芳晏，翻成客望勞。", "草平天一色，風暖燕雙高。", "擊轊爭輕幰，書旗衒縹醪。", "隨宜歌白紵，都士半雲袍。"]'),
('52f71936-53e9-4616-871d-4191d7e7bf42','偶作二首  其一','宋祁','宋','宋诗','song-poetry','','[]','去國日云久，寥寥雙鬢衰。',48,'全唐诗/poet.song.12000.json','["去國日云久，寥寥雙鬢衰。", "長安舉頭近，漳浦竄身危。", "沫竢窮鰓喣，春非墜葉知。", "一廛先畝在，扶耒有歸期。"]'),
('a5a593ad-7d21-41a8-8c88-625a6a986f10','偶作二首  其二','宋祁','宋','宋诗','song-poetry','','[]','衰翁好藏密，移病此僑居。',48,'全唐诗/poet.song.12000.json','["衰翁好藏密，移病此僑居。", "白眼慵迎客，青泥倦襆書。", "風侵殘晝網，煙鎖蔽春樗。", "惟有伊蒲士，相從樂飯蔬。"]'),
('84671241-6567-4107-b5c7-9020b5ff97ef','題阮步兵祠二首  其一','宋祁','宋','宋诗','song-poetry','','[]','濟世非無策，迷邦詎可求。',48,'全唐诗/poet.song.12000.json','["濟世非無策，迷邦詎可求。", "昏酣酒壚卧，蕭散竹林遊。", "俗眼嗟人廢，窮途逐涕流。", "何公真禮法，甯免疾如讎。"]'),
('ff5faf3e-3fd7-4a31-a0d0-6fb09316c547','題阮步兵祠二首  其二','宋祁','宋','宋诗','song-poetry','','[]','幽懷八十首，鬰鬰寄蓬池。',48,'全唐诗/poet.song.12000.json','["幽懷八十首，鬰鬰寄蓬池。", "屋壁留南巷，鄉人奉種祠。", "乘馿非宦巧，逃蝨厭流卑。", "三沃椒漿酹，誰論飲過差。"]'),
('75371991-7891-4bc2-851e-54056b777097','家居','宋祁','宋','宋诗','song-poetry','','[]','鬰鬰行何適，肩肩體寖臞。',48,'全唐诗/poet.song.12000.json','["鬰鬰行何適，肩肩體寖臞。", "安人非善宦，甯子是真愚。", "北化隨江枳，東遊謝海桴。", "何須命私駕，危涕避窮途。"]'),
('ade843b2-ceb5-40dc-ac5c-f375d43000af','寒夜','宋祁','宋','宋诗','song-poetry','','[]','孤客傷時晏，遥帷對夜分。',48,'全唐诗/poet.song.12000.json','["孤客傷時晏，遥帷對夜分。", "虛輪抱初月，側陣捲歸雲。", "霜蕙披寒穎，陂鳬叫暝羣。", "村砧與營杵，不寐最先聞。"]'),
('48d21ea3-b6a8-4c66-ac96-6bddd7f847df','過朱亥墓','宋祁','宋','宋诗','song-poetry','','[]','屠門遺舊隠，鎚袖凜餘風。',48,'全唐诗/poet.song.12000.json','["屠門遺舊隠，鎚袖凜餘風。", "兵下邯鄲壁，軀捐嚄唶公。", "種祠羣望亞，樵禁九原中。", "異世同樗墓，東西夾漢宮。"]'),
('6cdb75cc-dda0-4280-9f72-0c427689431e','蓬池寫望','宋祁','宋','宋诗','song-poetry','','[]','曠望蓬池上，池平失素波。',48,'全唐诗/poet.song.12000.json','["曠望蓬池上，池平失素波。", "鴟鳶貌閒暇，樗櫟意婆娑。", "霧日垂金彗，煙峰晦鈿螺。", "回瞻百常闕，非爲五噫歌。"]'),
('48cf4d16-8eb0-4000-8c55-a4c2acfd0944','野望','宋祁','宋','宋诗','song-poetry','','[]','臯壤一摇落，年華此向闌。',48,'全唐诗/poet.song.12000.json','["臯壤一摇落，年華此向闌。", "雪雲從北暝，霜日带西寒。", "漿酒喧神鼓，風毛送獵鞍。", "去邦猶未遠，差認漢宮盤。"]'),
('ac8102b0-563a-43b5-b84d-2d7367c84c89','結課','宋祁','宋','宋诗','song-poetry','','[]','結課天官啟，悲秋騎省孫。',48,'全唐诗/poet.song.12000.json','["結課天官啟，悲秋騎省孫。", "崢嶸遒歲籥，骯髒別都門。", "餞蓋紛寒野，征檣拂曉暾。", "縣齋豐醉秫，無厭數持樽。"]'),
('2dbb2244-5c44-4621-bfdf-7812c39a02f1','早發','宋祁','宋','宋诗','song-poetry','','[]','征客懷周道，飄然望日畿。',48,'全唐诗/poet.song.12000.json','["征客懷周道，飄然望日畿。", "天開閶闔近，星隠建章微。", "王囿芻蕘往，駉原騋牝歸。", "詎能同野鳥，朝夕向臺飛。"]'),
('fb828aba-bc64-4126-bec5-9efa6ce9fc72','有感','宋祁','宋','宋诗','song-poetry','','[]','力守高皇約，祈還司隸章。',48,'全唐诗/poet.song.12000.json','["力守高皇約，祈還司隸章。", "翻身去殿檻，忍死出縑囊。", "豕突埋輪路，豺驕擇肉場。", "霜毫墨猶溼，迢遞竄遐方。"]'),
('0686045c-7e62-419f-a74e-aad038bc7d0a','莊懿皇太后哀挽應制二首  其一','宋祁','宋','宋诗','song-poetry','','[]','國啟重雍祚，天推太極尊。',48,'全唐诗/poet.song.12000.json','["國啟重雍祚，天推太極尊。", "夏祠今化石，堯母舊題門。", "不待寒泉養，空流渭水恩。", "烝哉王者孝，別廟奉姜嫄。"]'),
('fbf8a955-fd93-40ff-8813-49f52b21095e','莊懿皇太后哀挽應制二首  其二','宋祁','宋','宋诗','song-poetry','','[]','遺饌行將徹，哀笳咽不前。',48,'全唐诗/poet.song.12000.json','["遺饌行將徹，哀笳咽不前。", "風驚長樂樹，月苦鮒隅天。", "恤典褘章備，神塗騩駕聯。", "故奩脂澤具，留待上陵年。"]'),
('e06c1e1e-9e86-4777-b370-60f1d4e09faf','偶成','宋祁','宋','宋诗','song-poetry','','[]','不用真如鼠，胡瞻亦有鶉。',48,'全唐诗/poet.song.12000.json','["不用真如鼠，胡瞻亦有鶉。", "田園未歸客，天地一畸人。", "京邑風霜苦，江鄉薇蕨春。", "可能迷鬼笑，長送左朱輪。"]'),
('a1083792-a0c4-4378-a37f-18f3494683e2','送魚太傅通判漢州','宋祁','宋','宋诗','song-poetry','','[]','綿野喜相依，長亭亟解携。',48,'全唐诗/poet.song.12000.json','["綿野喜相依，長亭亟解携。", "寒銷雲棧北，春徧錦城西。", "邛醤傳芳蒟，巖祠頌縹雞。", "時平通守貴，千騎鬭鄣泥。"]'),
('122c64ed-97de-45ab-ad08-c8c9549b2772','偶作','宋祁','宋','宋诗','song-poetry','','[]','人遠言都廢，身閒道轉迂。',48,'全唐诗/poet.song.12000.json','["人遠言都廢，身閒道轉迂。", "是非纔一馬，多少但雙鳬。", "學稼慚農老，還山笑客逋。", "嘶蟬何所謂，相伴據庭梧。"]'),
('a67259fa-0f80-40a2-ab32-1abe3436a016','馬比部赴兩浙提刑','宋祁','宋','宋诗','song-poetry','','[]','兩漢爲郎選，南方奉使材。',48,'全唐诗/poet.song.12000.json','["兩漢爲郎選，南方奉使材。", "書隨星火落，帆拂斗牛開。", "月破濤收鷺，天低雨暗梅。", "却緣持節重，無客對銜杯。"]'),
('966e133d-a673-4ea2-9df4-1048dbdbed6c','鄭天休舍人言中丞晏尚書西園見憶','宋祁','宋','宋诗','song-poetry','','[]','聞道青雲友，曾過廣武廬。',48,'全唐诗/poet.song.12000.json','["聞道青雲友，曾過廣武廬。", "中園玩蕭寂，嘉樹日扶疏。", "塢靜蟬鳴急，花翻鳥集餘。", "賦成誰見憶，唯是沈尚書。"]'),
('854f918e-5784-433e-abf5-5c3599f72d8f','當直偶題所見','宋祁','宋','宋诗','song-poetry','','[]','凜序閑緹籥，輕寒著黼帷。',48,'全唐诗/poet.song.12000.json','["凜序閑緹籥，輕寒著黼帷。", "仙盤迎日早，溫樹得霜遲。", "風觸趨朝珮，霞纏放仗旗。", "殿廊聊暴背，誰訝子雲衰。"]'),
('442fca42-7601-4226-8d33-6f1dae9c6915','出城寫望','宋祁','宋','宋诗','song-poetry','','[]','驅車南陌道，物色喜春還。',48,'全唐诗/poet.song.12000.json','["驅車南陌道，物色喜春還。", "水暖初成浦，雲晴不抱山。", "原姿平澶漫，禽哢巧間關。", "此適非謀野，祠官只在閑。"]'),
('c232a32a-cc3a-4b33-97a3-d4ff452043af','元會詩五首  其一','宋祁','宋','宋诗','song-poetry','','[]','享運樂斯逢，多儀粲云展。',48,'全唐诗/poet.song.12000.json','["享運樂斯逢，多儀粲云展。", "雜襲置蘿圖，禺卬瞻邃冕。", "沿磩履行進，分墀珮聲轉。", "夤極自成恭，歡餘還作抃。"]'),
('5dae6315-4b9b-4b03-afec-d30bb0aa6d0f','元會詩五首  其二','宋祁','宋','宋诗','song-poetry','','[]','惟新茲首祚，傾祝乃祈年。',48,'全唐诗/poet.song.12000.json','["惟新茲首祚，傾祝乃祈年。", "光華無輟旦，先後不違天。", "賀牘紛陳几，祥圖靄奏篇。", "南金照廡麗，塗玉截肪鮮。"]'),
('83e42ce8-15e1-4fdd-a85b-496b09608104','元會詩五首  其三','宋祁','宋','宋诗','song-poetry','','[]','穆穆集華蕤，煌煌開燕席。',48,'全唐诗/poet.song.12000.json','["穆穆集華蕤，煌煌開燕席。", "壽薦萬年觴，音諧四廂石。", "右秉矗文羽，左軒揚武戚。", "再飯人屬厭，三行酒溫克。"]'),
('5b1ee95d-d34f-4d15-a3f6-7a1ffd731987','元會詩五首  其四','宋祁','宋','宋诗','song-poetry','','[]','陽秋履端月，象魏布和辰。',48,'全唐诗/poet.song.12000.json','["陽秋履端月，象魏布和辰。", "解辮穹廬使，吹笙萍野賓。", "帝暉仍接晝，皇澤共成春。", "盛禮年年睹，祥祺日日新。"]'),
('99c713ae-5bfd-4cc9-9e45-7928424a1b81','元會詩五首  其五','宋祁','宋','宋诗','song-poetry','','[]','自昔君無勞，有言朝不夕。',48,'全唐诗/poet.song.12000.json','["自昔君無勞，有言朝不夕。", "遥聞索扇上，已見歸輿飭。", "千門詔解嚴，萬官均詠德。", "愧以斐然章，無裨從臣職。"]'),
('7d4fbcd4-0ed5-4f5f-8fe3-339900e4fbc0','和宮師陳相公','宋祁','宋','宋诗','song-poetry','','[]','公辭四輔貴，纔營三畝園。',48,'全唐诗/poet.song.12000.json','["公辭四輔貴，纔營三畝園。", "此地山林樂，當年廊廟尊。", "庭蘤有新複，郊禽無近翻。", "孰喻治窮僻，乃符蕭相言。"]'),
('624acf2b-17c2-43e9-a9c3-f28786652956','送福州通判陳鑄','宋祁','宋','宋诗','song-poetry','','[]','州閣紆新綬，鄉枌歷故廛。',48,'全唐诗/poet.song.12000.json','["州閣紆新綬，鄉枌歷故廛。", "先驅長卿貴，隨子大家賢。", "桂蠹閩君貢，刀耕越俗田。", "春郵有歸信，正待早梅傳。"]'),
('b3544cb2-5555-418a-9345-3a682d527b8c','和晏太尉晚夏','宋祁','宋','宋诗','song-poetry','','[]','炎威不可度，永晝坐南軒。',48,'全唐诗/poet.song.12000.json','["炎威不可度，永晝坐南軒。", "蟻過閒占雨，蠅來自厭樊。", "林披衆果熟，池靜數荷翻。", "早晚鞲鷹習，乘秋擊迥原。"]'),
('4fe60250-c84f-4f58-a38a-cb81d9b87d70','比日','宋祁','宋','宋诗','song-poetry','','[]','比日投簪隠，盂峰列舍椽。',48,'全唐诗/poet.song.12000.json','["比日投簪隠，盂峰列舍椽。", "值巖因作牖，仍磵即疏泉。", "斧爛仙棋路，花飛佛雨天。", "諫帷他夜夢，猶在翠微巔。"]'),
('e9162eed-ca32-4751-a86d-fb6545fbf4ce','和晏太尉早夏','宋祁','宋','宋诗','song-poetry','','[]','寂寥春蘤盡，岑蔚夏陰稠。',48,'全唐诗/poet.song.12000.json','["寂寥春蘤盡，岑蔚夏陰稠。", "舌反禽稀弄，頭昂麥併秋。", "直宜處臺榭，稍欲厭巾㡚。", "可待蒲葵直，思從謝傅游。"]'),
('5f75034c-ecdf-4c59-b6cd-b9f928b80e66','淮祠謝雨','宋祁','宋','宋诗','song-poetry','','[]','雨罷天披霧，杓回夜向晨。',48,'全唐诗/poet.song.12000.json','["雨罷天披霧，杓回夜向晨。", "煙蕪出郊路，燈火侍祠人。", "破月斜銜桂，傾河淡掃銀。", "三時此修報，慚負駕崧輪。"]'),
('94fcb80c-f260-4b99-8bf1-904d127d685c','讀史','宋祁','宋','宋诗','song-poetry','','[]','昔事堪追咎，斯人亦寡謀。',48,'全唐诗/poet.song.12000.json','["昔事堪追咎，斯人亦寡謀。", "臧倉君側毀，趙孟死前偷。", "直筆空料理，忠臣遂隠憂。", "只應貽後世，三歎廢緹油。"]'),
('e953b39c-7fe9-40d8-b159-0c307a4a0950','詠懷二首  其一','宋祁','宋','宋诗','song-poetry','','[]','榮願日云暮，安論輕且肥。',48,'全唐诗/poet.song.12000.json','["榮願日云暮，安論輕且肥。", "嵇慵元抱病，蘧晚況知非。", "餌落愁魚齅，巢成羨鳥歸。", "吾生江海志，終不與心違。"]'),
('ec868b6a-8180-40cd-88de-d7b62018d007','詠懷二首  其二','宋祁','宋','宋诗','song-poetry','','[]','盡信書奚信，難言命敢言。',48,'全唐诗/poet.song.12000.json','["盡信書奚信，難言命敢言。", "竟誰成簡冊，無客問乾坤。", "值狩麟猶泣，遭君鶴乃軒。", "滔滔千古事，惟有付芳樽。"]'),
('90b3f723-06f1-4167-a3d1-40df0e2238c7','西園','宋祁','宋','宋诗','song-poetry','','[]','日涉中園路，昌昌春意深。',48,'全唐诗/poet.song.12000.json','["日涉中園路，昌昌春意深。", "鳥新無罷囀，雲暖不常陰。", "秀色平連野，芳姿細著林。", "歡言挈齋酒，值興即徐斟。"]'),
('da877c7f-a49d-46a4-bbd2-b4ea27b08142','西園三月十一日','宋祁','宋','宋诗','song-poetry','','[]','春園來繼日，疊葉暗東西。',48,'全唐诗/poet.song.12000.json','["春園來繼日，疊葉暗東西。", "蔭樹都成幄，尋花旋作蹊。", "沼魚銜尾戲，林鳥合聲啼。", "寧暇并州問，山公醉自迷。"]'),
('ef93e3c3-cc96-45d8-9d91-9b6b511c3719','小酌感春邀坐客並賦','宋祁','宋','宋诗','song-poetry','','[]','林下復池邊，其如春暮天。',48,'全唐诗/poet.song.12000.json','["林下復池邊，其如春暮天。", "花仍無數落，柳亦第三眠。", "强飲非能劇，狂歌不取妍。", "流芳何與事，只是自怊然。"]'),
('80c9beff-078e-4c25-85e6-a9e3381213b4','去州三宿八公山宛然在望','宋祁','宋','宋诗','song-poetry','','[]','山長如不去，三宿趁行舟。',48,'全唐诗/poet.song.12000.json','["山長如不去，三宿趁行舟。", "未必緣人意，祗能攪客愁。", "倦程方浩蕩，回首更夷猶。", "獨有相思恨，因之東北流。"]'),
('ab637775-e164-4ee6-b289-11887a187c58','道中二首  其一','宋祁','宋','宋诗','song-poetry','','[]','故歲南趨壽，今茲北向陳。',48,'全唐诗/poet.song.12000.json','["故歲南趨壽，今茲北向陳。", "淹留桂枝客，還入玉關人。", "鬢髮都成葆，纓瓖幸濯塵。", "心知來往數，不敢問迷津。"]'),
('fcd6b23b-f667-4f32-b6ad-039600dd0fa0','道中二首  其二','宋祁','宋','宋诗','song-poetry','','[]','檥船清潁岸，岸豁見高原。',48,'全唐诗/poet.song.12000.json','["檥船清潁岸，岸豁見高原。", "桑柘寒煙路，牛羊落日村。", "扣舷魚艇集，爭食渚鳬喧。", "去去風波事，逢人未易言。"]'),
('a178c15b-b525-4211-83a1-fd115d66ad93','按務東橋駐望','宋祁','宋','宋诗','song-poetry','','[]','岸峻雙旌駐，橋橫一水長。',48,'全唐诗/poet.song.12000.json','["岸峻雙旌駐，橋橫一水長。", "凍舟真欲住，低雁正成行。", "發發天含籟，稜稜野雨霜。", "停驂重回首，直北是吾鄉。"]'),
('718383ff-a016-4254-bfc7-f8ec4a1258e7','晚秋集晏太尉西園  其一','宋祁','宋','宋诗','song-poetry','','[]','邂逅翹材客，乘秋共涉園。',48,'全唐诗/poet.song.12000.json','["邂逅翹材客，乘秋共涉園。", "淺葩歡所媚，寒日醉中暄。", "目遠鴻堪送，林深鵲自翻。", "長年無所嗜，惟有不空罇。"]'),
('2f0b7578-96fa-4da8-bc70-ce85ae0d3953','晚秋集晏太尉西園  其二','宋祁','宋','宋诗','song-poetry','','[]','造適銜杯醑，情來念物華。',48,'全唐诗/poet.song.12000.json','["造適銜杯醑，情來念物華。", "喬柯寒自籟，荒菊晚猶花。", "滾滾飄談麈，焞焞下日車。", "歸騶侵暝鼓，無復避堤沙。"]'),
('71aaf55b-4695-4d89-9c08-855b81452a2f','官舍二首  其一','宋祁','宋','宋诗','song-poetry','','[]','南榮坐炙野人暄，官謗心知鶴有軒。',64,'全唐诗/poet.song.12000.json','["南榮坐炙野人暄，官謗心知鶴有軒。", "畫餠竊名真不食，銜枚邀寵更無言。", "嵇齋書簏吹塵度，蔣徑賓綦暈蘚班。", "事國愛君精未已，此生疏蹻負邱園。"]'),
('be2edcfa-2bc1-471b-a753-354a9f52cc10','官舍二首  其二','宋祁','宋','宋诗','song-poetry','','[]','病骨支離釜粟豐，卧看暾采照牆東。',64,'全唐诗/poet.song.12000.json','["病骨支離釜粟豐，卧看暾采照牆東。", "不材天與山中養，飽食人嗤柱下工。", "大府翩翩慚奏記，閑齋咄咄厭書空。", "翛然慵態知難畫，手按鳴弦目送鴻。"]'),
('9ae4fde9-c554-4ad4-8c31-cc37919cf697','樹柳','宋祁','宋','宋诗','song-poetry','','[]','爲愛當年濯濯姿，動春摇霧不勝垂。',64,'全唐诗/poet.song.12000.json','["爲愛當年濯濯姿，動春摇霧不勝垂。", "條供越絕千絲網，葉鬭章臺半額眉。", "肯共桑榆悲日晚，寧同枳橘過江移。", "待君合抱相看歲，定是金城灑涕時。"]'),
('c8cd0773-4fbb-497e-bff5-0e5e5203a6b9','俊上人遊山','宋祁','宋','宋诗','song-poetry','','[]','股錫飄然指上方，翠微巖腹掩膺房。',64,'全唐诗/poet.song.12000.json','["股錫飄然指上方，翠微巖腹掩膺房。", "江山極睇才多助，竿木投機戲有場。", "麝墨洗餘池溜變，玉瓷清極茗華香。", "秋風莫負重來約，凈社霜蓮徧碧塘。"]'),
('78786152-c828-4a5a-ad1b-f649a655f6a5','兵部學士移鎮昭潭','宋祁','宋','宋诗','song-poetry','','[]','檣拂南雲艤帛蘭，再麾湖外嘆違顔。',64,'全唐诗/poet.song.12000.json','["檣拂南雲艤帛蘭，再麾湖外嘆違顔。", "封君比籍千頭橘，瑞祝標祠九向山。", "迎吏出郊驅駑箙，齊兵下席掩刀環。", "漢條緩布褒書降，後乘蒸青幾兩還。"]'),
('630ee54a-80ee-4a2d-bdb3-ba1ede640820','夏日','宋祁','宋','宋诗','song-poetry','','[]','六幕風輕晝刻長，地形卑溼近南方。',64,'全唐诗/poet.song.12000.json','["六幕風輕晝刻長，地形卑溼近南方。", "人揮羽翣依林樾，綆續金瓶下井牀。", "雲路飛鳶愁跕跕，玉徽流水怨湯湯。", "尸官盛府中乾甚，久飲臺冰未覺凉。"]'),
('e1bef3b1-6f32-46b8-b2b2-d663f22e7176','晚春至自襄陽','宋祁','宋','宋诗','song-poetry','','[]','刀頭歸約月殘時，棐几流塵滿兔枝。',64,'全唐诗/poet.song.12000.json','["刀頭歸約月殘時，棐几流塵滿兔枝。", "陰地雨蛙欺鼓吹，後園煙茗老槍旗。", "風回曲榭花英聚，泉噴坳堂蘚暈移。", "卧看屋梁周粟飽，不嫌五管號支離。"]'),
('c2fa36ee-4dd6-4e89-bfc2-39640423cc66','州將按行隄上','宋祁','宋','宋诗','song-poetry','','[]','十萬隄封限迅流，騰裝清曉徑春疇。',64,'全唐诗/poet.song.12000.json','["十萬隄封限迅流，騰裝清曉徑春疇。", "駐車楚老漿盈野，勸築睢陽杵有謳。", "梅暖晚香薰宿館，雪天零霰犯輕裘。", "桑郊剋日迎歸旆，遥認驪駒最上頭。"]'),
('5db511ce-3acd-4eea-89df-9b47aaccbb53','楊初歸九江','宋祁','宋','宋诗','song-poetry','','[]','方領思歸集鸛庭，樵風千里漾舟舲。',64,'全唐诗/poet.song.12000.json','["方領思歸集鸛庭，樵風千里漾舟舲。", "歌翻桃岸雙飛鵠，夢繞天鄣九疊屏。", "上苑昔游賦飄雪，故林良友望賢星。", "遲聞乙奏藂雲幄，紫桂窅窊襲袂馨。"]'),
('f352474a-53de-4ee8-8c73-ef56fa00f57d','送楊偕太傅知淮陽軍','宋祁','宋','宋诗','song-poetry','','[]','下拜親膺一札書，隋河風柂送行艫。',64,'全唐诗/poet.song.12000.json','["下拜親膺一札書，隋河風柂送行艫。", "曉辭漢署茅留蕝，暮聽廉歌袴換襦。", "方志貢珍傳磬錯，客庖羞品盛魚腴。", "雙旌引入柔桑陌，少駐驂驔捋美鬚。"]'),
('d5f1998c-c7d6-43a4-8959-b0c11cd456e2','送楊子奇赴辟潭淵','宋祁','宋','宋诗','song-poetry','','[]','老避嘲師晝不眠，喜聞書辟冠初筵。',64,'全唐诗/poet.song.12000.json','["老避嘲師晝不眠，喜聞書辟冠初筵。", "車陪魏館鳴笳路，食對何侯下箸錢。", "使驛馬歸催露檄，學帷鱣墮晦餘編。", "知君此舉伸知己，寧似他人有一天。"]'),
('e620b267-e2cc-4193-9f5b-bd77fee158f9','龍圖蔡學士鎮高密','宋祁','宋','宋诗','song-poetry','','[]','厭直坡鑾引郡章，玉虬移刻對清廂。',64,'全唐诗/poet.song.12000.json','["厭直坡鑾引郡章，玉虬移刻對清廂。", "留符懇避離宮籥，懷綬貪過白晝鄉。", "書閣迥巢雙鳳羽，詔泥殘和五芝房。", "追鋒只恐歸期迫，胥蟹腴魚計早嘗。"]'),
('f16a99e0-acb9-4eac-b7ef-fa0a6545688f','中山公鎮淝上','宋祁','宋','宋诗','song-poetry','','[]','長鬣生氂滿帳前，甘棠載憩示優賢。',64,'全唐诗/poet.song.12000.json','["長鬣生氂滿帳前，甘棠載憩示優賢。", "簜函握節中軍府，奎字成鉤寶閣天。", "丹匕去尋鴻苑錄，佛花來供凈名禪。", "朝家入有三公拜，未信東山得久眠。"]'),
('9540c3f7-05e6-4767-8095-5481097ba806','邑居','宋祁','宋','宋诗','song-poetry','','[]','暖褫貂裘病骨輕，茨簷窮伏廢將迎。',64,'全唐诗/poet.song.12000.json','["暖褫貂裘病骨輕，茨簷窮伏廢將迎。", "庖人投刃喧羊肆，溪子擎牙近禁營。", "雲破日痕絙巘道，雨殘煙脚媚荑英。", "傳聞內史輕租契，私約吾農對耦耕。"]'),
('f791cfbe-c2d4-4602-8cbf-18dd8ffa3536','歲晚家居自勉','宋祁','宋','宋诗','song-poetry','','[]','朝陽濃澹雪雲垂，湯沐餘閒似標枝。',64,'全唐诗/poet.song.12000.json','["朝陽濃澹雪雲垂，湯沐餘閒似標枝。", "藥有不龜聊擊絮，管無窺豹任□碁。", "垣陰剝紫迷寒蘚，池溜含光結晚澌。", "飲取醇醪作佳士，莫因蒿目强憂時。"]'),
('0e16f1f3-f21b-4d6a-97da-4397ac553e0d','張伯起自蜀還臺簾對既訖以有司奉祠蜡方既即齋復引入升太常爲博士','宋祁','宋','宋诗','song-poetry','','[]','殿墄塗丹九齒長，珠簾伏奏近天香。',64,'全唐诗/poet.song.12000.json','["殿墄塗丹九齒長，珠簾伏奏近天香。", "已傳樂職來西蜀，更就清齋得太常。", "夕燎烘庭思結佩，曉蘭薰俗滯華陽。", "心傾五日歸來路，共舉鮭珍釂賀觴。"]'),
('91fc515a-7694-4162-bc37-6dd83118ef73','晝寢','宋祁','宋','宋诗','song-poetry','','[]','靜拂藜牀藉蠹書，曲肱聊與古爲徒。',64,'全唐诗/poet.song.12000.json','["靜拂藜牀藉蠹書，曲肱聊與古爲徒。", "夢柯尚費論榮辱，訟鹿何煩競有無。", "庭下細光風泛蕙，隙中斜影日低梧。", "宰牆不塓嵇胞轉，寧覺人間有畏途。"]'),
('628d7fe9-f224-43cc-9fef-9ee3f90f20c6','喜楊德華見過感舊成詠','宋祁','宋','宋诗','song-poetry','','[]','曾見烏衣賭佩囊，再逢何遽二毛郎。',64,'全唐诗/poet.song.12000.json','["曾見烏衣賭佩囊，再逢何遽二毛郎。", "病姿故有靈光在，牡齒翻隨屈産長。", "河裏笛聲頻感慨，江南花樹剩凄凉。", "酒壚便有生平隔，已濯華纓未易狂。"]'),
('0b5164dd-2b63-4ef1-94b5-5b56ae7b05f0','送齊殿丞監縉雲軍','宋祁','宋','宋诗','song-poetry','','[]','幾信南風轉曙烏，殿欄歸思結丹塗。',64,'全唐诗/poet.song.12000.json','["幾信南風轉曙烏，殿欄歸思結丹塗。", "曳朱恩借魚須笏，假節人同虎刻符。", "裳綵親闈稱雅壽，弩蘭鄉縣壯前驅。", "飛霜郡閣遺文麗，更得韓陵共語無。"]'),
('28c35c4a-809d-48fa-aed0-2e5bbe3d4b06','送楊告虞部知池陽','宋祁','宋','宋诗','song-poetry','','[]','新年卧錦直南宮，露紱歸來使寄雄。',64,'全唐诗/poet.song.12000.json','["新年卧錦直南宮，露紱歸來使寄雄。", "祕地鏘鑾辭夜燎，離亭贈扇有仁風。", "梅根大冶兼金富，楊葉芳洲雜蘤紅。", "傖楚俗移恩詔美，班春聊隠軾前熊。"]'),
('9074b42a-be5c-4c0a-a7c0-d4c21f50f0f7','遊小圃','宋祁','宋','宋诗','song-poetry','','[]','初陽未爇樹陰輕，中圃留連底有情。',64,'全唐诗/poet.song.12000.json','["初陽未爇樹陰輕，中圃留連底有情。", "春草抽心終不死，夏禽反舌已無聲。", "轆轤半上畦泉逗，襫襏初休隴雨晴。", "紫蓼青葵正堪掇，於陵何必是逃名。"]'),
('49824f3f-443b-4973-893a-cdcda2737f68','盛諫議赴維揚','宋祁','宋','宋诗','song-poetry','','[]','漢家規地徧青蒲，繡扆恩深拜命初。',64,'全唐诗/poet.song.12000.json','["漢家規地徧青蒲，繡扆恩深拜命初。", "朱畫車轓頻出守，仙移院額別修書。", "貢圖星橘兼苞柚，宴筯金齏和鱠魚。", "奉計不應三滿歲，荷囊法許從雕輿。"]'),
('1c4e5c44-0efa-404e-a3ee-7b1cb722be87','葉道卿監太平州','宋祁','宋','宋诗','song-poetry','','[]','堵波題墨素塵昏，犀棹橫江重黯魂。',67,'全唐诗/poet.song.12000.json','["堵波題墨素塵昏，犀棹橫江重黯魂。", "束帙乍拋三鐵㰅，將軍兼映兩朱輪。", "淋漓鷺下秋濤闊，蹀{⻊習}檛狂宴鼓喧。", "速報政成歸待詔，鑄金雙夾魯班門。"]'),
('7fafb23a-d2c4-4999-9138-650864b38efc','王君瑞秘丞同理青社','宋祁','宋','宋诗','song-poetry','','[]','詔押平明出未央，便隨公府汎牙檣。',64,'全唐诗/poet.song.12000.json','["詔押平明出未央，便隨公府汎牙檣。", "即時趨坐多留幘，幾夕登樓共踞牀。", "勝國遺官沉雪霧，從軍舊沼認蓮房。", "翹材宴隙還家早，紫葉叢萱映壽觴。"]'),
('de41a531-96c9-402c-a6c6-92ea19e475f3','劉立德同年赴淝州幕','宋祁','宋','宋诗','song-poetry','','[]','春榜連題千佛經，兩藩交辟滯弓旌。',64,'全唐诗/poet.song.12000.json','["春榜連題千佛經，兩藩交辟滯弓旌。", "幕中仍是紅蓮客，門下今爲玉筍生。", "林逗楚風披醉衽，浪摇淮月漬離纓。", "歸來上賦趨行在，足繼西豪舊弟兄。"]'),
('01ca9d6d-7126-4398-8687-d2ddb4273842','鄰亭真','宋祁','宋','宋诗','song-poetry','','[]','蕊館何年記舊封，宴亭此日駐憑熊。',64,'全唐诗/poet.song.12000.json','["蕊館何年記舊封，宴亭此日駐憑熊。", "佛螺近作臨窗岫，仙馭遥添拂衽風。", "談樹憩棠交結蔭，飛翬賀雀併翻空。", "使君邀勝留千騎，可在秦樓更向東。"]'),
('4c20483e-4330-480b-9bff-761a3b8e133e','送梅摯廷評宰上元','宋祁','宋','宋诗','song-poetry','','[]','子虛誦入漢皇帷，給筆當年掞藻奇。',64,'全唐诗/poet.song.12000.json','["子虛誦入漢皇帷，給筆當年掞藻奇。", "賜罷春袍兼彩服，對餘崑玉照林枝。", "即時酒所歌驪闋，幾日江南瑞雉隨。", "建業清溪無盡曲，爲賡妍唱繞遺詞。"]'),
('a91e7fc8-4485-4db2-9efe-7d0cc587bd22','送葉蘇州','宋祁','宋','宋诗','song-poetry','','[]','卧錦潜郎種種絲，爲邦獨愛阮咸麾。',64,'全唐诗/poet.song.12000.json','["卧錦潜郎種種絲，爲邦獨愛阮咸麾。", "中臺給契魚初剖，外闥升車雉尚隨。", "風汴雜花飄夕棹，雨吳芳樹隠春旗。", "爲尋劉白高吟地，酒熟螯香左右持。"]'),
('382e2031-0b3c-4338-9dbf-5f8e9d09a345','九日','宋祁','宋','宋诗','song-poetry','','[]','商館馮高爽氣濃，露萸千穗亞枝紅。',64,'全唐诗/poet.song.12000.json','["商館馮高爽氣濃，露萸千穗亞枝紅。", "餠餐交遺嘉籩上，蕊菊爭吹壽斝中。", "擊隼厲威平隰闊，戲驂沈響故臺空。", "何人盛繼龍山集，醉帽須防穀鬰風。"]'),
('70f4a21d-bc98-434b-b772-a7a1b099c007','送惟正歸錢塘','宋祁','宋','宋诗','song-poetry','','[]','客艑高檣冒楚霏，月巖叢桂老春枝。',64,'全唐诗/poet.song.12000.json','["客艑高檣冒楚霏，月巖叢桂老春枝。", "一杯來應伊蒲供，八法歸刊斗藪碑。", "鰌岸風生凉汐滿，蜃天霞破暝樓危。", "學該內外皆圓法，却要聲聞是總持。"]'),
('4095498c-cd7a-4479-88a4-5f3256eff907','直舍','宋祁','宋','宋诗','song-poetry','','[]','南榮曝腹飫黄粱，卧看春暉上縹牆。',64,'全唐诗/poet.song.12000.json','["南榮曝腹飫黄粱，卧看春暉上縹牆。", "有位乘軒慚野鶴，出錢邀沐羨山郎。", "神交自愛蘧蘧適，怪事非論咄咄狂。", "瓠竅不穿樗質散，只應何用是吾鄉。"]'),
('e7f0c2fc-3cd5-4cdf-a241-993f97ad731c','送澶淵李太傅','宋祁','宋','宋诗','song-poetry','','[]','左契銅魚照綬囊，上頭車騎冠東方。',64,'全唐诗/poet.song.12000.json','["左契銅魚照綬囊，上頭車騎冠東方。", "三交薦技中軍戲，一割牛心右客嘗。", "烽靜塞垣宵燐滅，橋橫河曲暮虹長。", "歸來競病喧笳鼓，不畏休文賦韵彊。"]'),
('4aff9bfc-c11d-4bb7-9b51-fd4d696682e6','天街縱轡晚望','宋祁','宋','宋诗','song-poetry','','[]','夾道宮槐鼠耳長，碧簷千步對飛廊。',64,'全唐诗/poet.song.12000.json','["夾道宮槐鼠耳長，碧簷千步對飛廊。", "虹橋不礙天河水，虎落遥遮禁苑牆。", "柳密試應勝暖吹，樓高都擬爲殘陽。", "塵輕霧重黄昏恨，半屬翩翩馬上郎。"]'),
('64b5f901-474f-4ee2-8760-16d45ca976fd','有感','宋祁','宋','宋诗','song-poetry','','[]','車轍無聲巷次閒，畸人愁卧鬢毛班。',64,'全唐诗/poet.song.12000.json','["車轍無聲巷次閒，畸人愁卧鬢毛班。", "月囊罷食侏儒米，歲計深依嵔壘山。", "風薄迴林秋蔕老，天圍荒堞暝烏還。", "舉頭却望長安日，已在浮雲沆漭閒。"]'),
('c960072e-2845-491d-9d03-d5cf472aec93','晚秋月夕','宋祁','宋','宋诗','song-poetry','','[]','萬里冰輪轉斗城，薄帷開望暝寒輕。',64,'全唐诗/poet.song.12000.json','["萬里冰輪轉斗城，薄帷開望暝寒輕。", "金從佛國初移地，玉與仙家便作京。", "乾鵲繞枝經下苑，漢刀持夜發連營。", "謝郎莫惱修然意，欲把纖雲點太清。"]'),
('450d43e0-ed25-4bb8-ae03-3b1b36da722d','送梁著作宰興平','宋祁','宋','宋诗','song-poetry','','[]','班馬蕭蕭祖帳闌，曉參橫影送征鞍。',64,'全唐诗/poet.song.12000.json','["班馬蕭蕭祖帳闌，曉參橫影送征鞍。", "春歸花樹排初薺，天廢關泥落舊丸。", "乳雉羣飛郊柘密，祕魚雙合省芸乾。", "霸陵草色無深淺，試爲南登一望看。"]'),
('7bb5b580-4578-44c6-9cbe-844a13a24f90','送張元安肅知軍','宋祁','宋','宋诗','song-poetry','','[]','星闈幾罷日薰衣，萬里題封換使麾。',64,'全唐诗/poet.song.12000.json','["星闈幾罷日薰衣，萬里題封換使麾。", "都外鴟夷催軷酒，塞南楊柳望春旗。", "中軍尺檄閒飛羽，前隊鳴採列素支。", "競病不須貪賦韵，路人笳鼓記歸時。"]'),
('4e778a6c-a54a-47c6-88c9-f21e5cd63b6d','館中即事呈郭仲微','宋祁','宋','宋诗','song-poetry','','[]','仙山對敞直廬扉，繙徧緹油素領垂。',64,'全唐诗/poet.song.12000.json','["仙山對敞直廬扉，繙徧緹油素領垂。", "駑乘空陪天驥尾，羈禽不集帝梧枝。", "雲連帝閣朝暾早，花咽宮渠夕溜遲。", "何事夫君弄刀筆，五年猶似雁門踦。"]'),
('58db2250-1a40-4d0c-bd35-9f6ca1b780ee','病興早朝','宋祁','宋','宋诗','song-poetry','','[]','萬轡冬瓏鳳闕西，病興重喜趁朝閨。',64,'全唐诗/poet.song.12000.json','["萬轡冬瓏鳳闕西，病興重喜趁朝閨。", "初霞稍上巖廊戟，落月催傳衛士雞。", "溫樹未凋風力薄，仙杯已滿露華低。", "明光一對清光罷，昏目猶慚眩轉迷。"]'),
('392ce83d-d2c4-484d-8031-4399d25a0f8c','蜡祠宿太常院聞翰林兄長內當','宋祁','宋','宋诗','song-poetry','','[]','碧天霜氣夜稜稜，人在鼇山第幾層。',64,'全唐诗/poet.song.12000.json','["碧天霜氣夜稜稜，人在鼇山第幾層。", "靜極禁關聞下鍵，暝深連閣見通燈。", "蕙薰浮篆才餘火，酒滴供研自不冰。", "無奈此時懷共被，各分臺署擁青綾。"]'),
('a28a80b8-c62d-4add-9e54-108e0f57b975','乾元節錫慶院燕','宋祁','宋','宋诗','song-poetry','','[]','盛節推慈洽宴觴，千官不拜儼分行。',64,'全唐诗/poet.song.12000.json','["盛節推慈洽宴觴，千官不拜儼分行。", "搊彈併給黎園部，曼衍爭趨角觝場。", "傳炙濯罍紛絡繹，神仙綵樹互低昂。", "名酋面內千胥樂，歡譯遥通戴斗香。"]'),
('0695182f-9b0e-4219-b9f2-5b49e4db410d','下直','宋祁','宋','宋诗','song-poetry','','[]','殿樓傳鼓報歸鞍，槐道逶迤出九關。',64,'全唐诗/poet.song.12000.json','["殿樓傳鼓報歸鞍，槐道逶迤出九關。", "雨罷浮雲留北闕，朝來爽氣徧西山。", "倏逢行幰排輈度，稍見晴鴉接翅還。", "癡計未容官事了，只驚潘鬢颯然斑。"]'),
('0ac8bddd-4127-49c7-bc03-b150b55f5a96','和三司晏尚書西園暇日','宋祁','宋','宋诗','song-poetry','','[]','陰陰嘉樹雜花殘，下畹行吟靜更歡。',64,'全唐诗/poet.song.12000.json','["陰陰嘉樹雜花殘，下畹行吟靜更歡。", "草葉參差聊藉带，竹皮紛墮即爲冠。", "餘杯更辨浮冰酎，小衽初思御月紈。", "公有吾廬無限愛，海圖周傳不同看。"]'),
('89224093-950d-4a21-a465-3c209ef7d5ae','禁中垂柳','宋祁','宋','宋诗','song-poetry','','[]','曼線長枝不自收，天姿濯濯與風流。',64,'全唐诗/poet.song.12000.json','["曼線長枝不自收，天姿濯濯與風流。", "已隨曉珮拖三綬，更伴春旗亞九斿。", "盡日舞殘芳吹在，此時眠熟暝煙留。", "宮中二月多行樂，爲掃清塵待翠虯。"]'),
('8c949470-f77c-464d-b8a0-617b2cff50eb','和晏太尉懷寄燕侍郎','宋祁','宋','宋诗','song-poetry','','[]','賜車高掛得長閑，猶寄南宮事下官。',64,'全唐诗/poet.song.12000.json','["賜車高掛得長閑，猶寄南宮事下官。", "招隠新君無怨鶴，趨朝舊路記翔鸞。", "滄浪濯罷垂纓懶，礧磈澆餘著酒寬。", "行到昔人知足地，羨君容膝易爲安。"]'),
('edbd55a9-590b-4f14-a4b1-3f52c768c7e1','喜仲微學士直右史','宋祁','宋','宋诗','song-poetry','','[]','殿棟洪紛冒紫霏，新聞再拜上丹墀。',64,'全唐诗/poet.song.12000.json','["殿棟洪紛冒紫霏，新聞再拜上丹墀。", "日高中禁仙香馥，輦度橫街赭傘移。", "寶校對呈天廄馬，輕兵看閱羽林兒。", "因君此際磨坳墨，偏憶當年第二螭。"]'),
('d32facab-4940-4785-8c86-8769bb964e26','宿直','宋祁','宋','宋诗','song-poetry','','[]','三重仙閣道家山，寓直由來恧素餐。',64,'全唐诗/poet.song.12000.json','["三重仙閣道家山，寓直由來恧素餐。", "漏近章溝先報暝，樹連溫省未知寒。", "蘭釭靜對朱花結，芒帙間披白蠹乾。", "前膝正宜無夜召，賈生衰鬢僅勝冠。"]'),
('70ca094c-6b22-4c77-a8c6-c3cb98247263','一百五日官舍作','宋祁','宋','宋诗','song-poetry','','[]','晉歌本自傳幽憤，楚俗緣何作勝游。',64,'全唐诗/poet.song.12000.json','["晉歌本自傳幽憤，楚俗緣何作勝游。", "宴豆雕文誇瀹卵，俠場星影鬭飛毬。", "光翻蘋吹都無力，暖著花煙不肯流。", "擣杏沃餳紛節物，更慚多病怯寒甌。"]'),
('10a46700-fada-457b-b9ac-adf8cf18b994','晚夏高齋看雨','宋祁','宋','宋诗','song-poetry','','[]','雲族窮天雨足垂，繁聲凉陣挫炎威。',64,'全唐诗/poet.song.12000.json','["雲族窮天雨足垂，繁聲凉陣挫炎威。", "圓荷萬蓋翻珠琲，綠稻千畦灑佛衣。", "迎浪孺魚銜藻擲，迎風雛燕入樓飛。", "原田潤浹吾農樂，籉笠紛紛晚未歸。"]'),
('c1739d84-31c9-4ba6-84ca-c993bf659993','奉和宮師相公流杯亭詩并太傅相公樞密太尉和章次韵','宋祁','宋','宋诗','song-poetry','','[]','築巖春脈下飛泉，林閣留賓敞慶筵。',64,'全唐诗/poet.song.12000.json','["築巖春脈下飛泉，林閣留賓敞慶筵。", "流水環階智者樂，醇醪飲吏相君權。", "和歌遠屬鈞樞舊，禊帖間存爵里賢。", "此地勝游誰復見，醉波深映六符天。"]'),
('33553e4c-d5f7-4bf1-9dba-8c58ec49b78b','冬日城樓駐望','宋祁','宋','宋诗','song-poetry','','[]','城上危欄徙倚頻，由來荆楚歲時新。',64,'全唐诗/poet.song.12000.json','["城上危欄徙倚頻，由來荆楚歲時新。", "寒塘酒幟能留客，晴塢梅花解笑人。", "客雁參差仍向渚，貪魚撥剌不容緡。", "憑高更盡三吹角，坐見霞霏仄半輪。"]'),
('b3a2cfd1-d366-4216-bd24-aded6569d05c','齊雲亭憑高有感','宋祁','宋','宋诗','song-poetry','','[]','憑高極目意茫然，坐對淮南摇落天。',64,'全唐诗/poet.song.12000.json','["憑高極目意茫然，坐對淮南摇落天。", "空把歸心同客雁，遂將緘口伴寒蟬。", "一罇醒醉黄花外，萬事蕭條白髮前。", "誰取長弓射鳥翼，休教西日送凋年。"]'),
('be0e32a1-885a-47f3-a1d1-064d48ce5969','春晚官舍呈幕中','宋祁','宋','宋诗','song-poetry','','[]','萬點飛花拂路塵，行春罷後惜殘春。',64,'全唐诗/poet.song.12000.json','["萬點飛花拂路塵，行春罷後惜殘春。", "雨催菖葉全成甲，風播榆錢不算緡。", "多病已慚官綬束，長年惟共酒杯親。", "坐題吏諾君何怪，只是漣漪素食人。"]'),
('b1f79220-67b3-4b51-a903-cfcef909d9ec','奉和聖製清明','宋祁','宋','宋诗','song-poetry','','[]','解律調元品彙春，青陽右个啟初辰。',64,'全唐诗/poet.song.12000.json','["解律調元品彙春，青陽右个啟初辰。", "庖煙息禁農耕盛，蠶器增修歲務新。", "遲日東門催柳色，微寒南陌歛車塵。", "柏梁侍從瞻天什，拜手賡歌軋思頻。"]'),
('e7daba0f-f4ec-4cc1-b6f8-53d5c95ed081','公齋植竹','宋祁','宋','宋诗','song-poetry','','[]','對植同奇樹，扶疏對近軒。',72,'全唐诗/poet.song.12000.json','["對植同奇樹，扶疏對近軒。", "舊經梁苑賦，初結太山根。", "就簡供書刻，乘秋爽些魂。", "鳶風朝作籟，鶴露夜留痕。", "招隠宜先桂，忘憂可並萱。", "會當充鳳食，薦實帝家園。"]'),
('74bbcd6d-62ba-4e0c-abfc-5a14af2f6d07','郡界閔雨州將率官屬禳禬','宋祁','宋','宋诗','song-poetry','','[]','劭農方狎野，熯旱嘆焦原。',72,'全唐诗/poet.song.12000.json','["劭農方狎野，熯旱嘆焦原。", "六幕沈雲族，千箱害稼孫。", "都人望天漢，國相閉陽門。", "盛怒風生穴，汙邪祝有豚。", "征徒休道樾，汲缶涸中園。", "米價高何許，癡人遂不言。"]'),
('b64e3b0b-52bd-43f3-bd4e-4200cf3d9f63','皇帝邇英閣講畢五經','宋祁','宋','宋诗','song-poetry','','[]','太極洪樞暇，西清祕閣開。',120,'全唐诗/poet.song.12000.json','["太極洪樞暇，西清祕閣開。", "文從壁府降，輦自殿中來。", "捧帙諸儒進，繙經寶思該。", "書留孔子宅，禮識漢家臺。", "詁傳風兼頌，陽秋富竝裁。", "觀圖龍夭矯，啟柙鳳毰毸。", "遂使民胥效，咸知上育材。", "星鉤參婉曲，天漢助昭回。", "章甫慚無狀，華光信濫陪。", "願因稽古日，拜手頌明哉。"]'),
('aa2cb096-9edc-4326-95b3-048478557f30','金陵相公赴鎮二首  其一','宋祁','宋','宋诗','song-poetry','','[]','代邸橫庚佐，商巖夢弼才。',120,'全唐诗/poet.song.12000.json','["代邸橫庚佐，商巖夢弼才。", "蕭公左右手，軒老上中台。", "利見攀龍後，重明捧日來。", "聊持樞柄族，旋運一陶坯。", "師石兼爲礪，形鹽本和梅。", "樹容他語答，車問少陽回。", "丕績推時乃，宸歌續喜哉。", "陳平安注意，鄧禹退無猜。", "燾社南邦重，輕裘太府開。", "舍裝寧晚計，行復坐公槐。"]'),
('d0b6a47e-7ae1-4619-a05d-76a086a2d8e0','金陵相公赴鎮二首  其二','宋祁','宋','宋诗','song-poetry','','[]','慈宸念方國，上宰輟謨明。',120,'全唐诗/poet.song.12000.json','["慈宸念方國，上宰輟謨明。", "即拜三公府，還爲萬里城。", "松姿終自直，鼎意未嘗輕。", "戀結雲簾對，恩頒玉節榮。", "一經傳令子，雙璧聘材卿。", "鷁汎江南棹，犀羅帳下兵。", "台轓凝畫繞，仙袂赤松迎。", "粟脫賓筵飯，羊均宴豆羹。", "吳農觀耨水，蕪壤嘆糊赬。", "此日東山詠，惟公繼頌聲。"]'),
('2174779f-727a-4f5f-aa09-d038a1e78bbc','僦舍西齋小圃竹樹森植秋日摇落對之翛然因作長句盡道所見','宋祁','宋','宋诗','song-poetry','','[]','避事長卿志，閒居郎將流。',168,'全唐诗/poet.song.12000.json','["避事長卿志，閒居郎將流。", "無心嬰外物，有興爲高秋。", "僦舍餘三畝，畸人代一邱。", "園空樹色至，日淡暝煙浮。", "紺葉繁江蓼，丹鬚亞海榴。", "青松七鬣嫩，黄菊萬釘稠。", "露泫梨津熟，風乾芰扇愁。", "小池圓寫鏡，卧石側盤虯。", "愛竹惟慚賦，逢萱即忘憂。", "信非吾土美，聊並小山留。", "勝託三餘暇，幽尋五日休。", "沼蛙觀聿役，簷雀聽啁啾。", "心有冥鴻伴，歌煩警鶴酬。", "茲焉爲樂地，時事判悠悠。"]'),
('92c5192d-ea3c-41e1-bf32-756b2cbe8a7f','送高記室廣州幕','宋祁','宋','宋诗','song-poetry','','[]','楚國王孫後，梁臺賦客賢。',72,'全唐诗/poet.song.12000.json','["楚國王孫後，梁臺賦客賢。", "貪磨盾鼻檄，重冠玳簪筵。", "去路南溟地，離魂北斗天。", "庾鮭三種嫩，虞璧一雙鮮。", "颶影風爭怒，珠胎月對圓。", "慎持齋疾意，密啟佇詳延。"]'),
('732f45f4-9dac-4ad6-894a-67ff70d36f86','僧園牡丹','宋祁','宋','宋诗','song-poetry','','[]','朽壤真非託，奇葩惜見捐。',120,'全唐诗/poet.song.12000.json','["朽壤真非託，奇葩惜見捐。", "根深惟自庇，香酷索誰憐。", "晚蘤仍晞日，斜柯但倚煙。", "有人同寂寞，無地與回旋。", "不預甘棠愛，羞將惡木連。", "數奇飛將恨，形槁屈生賢。", "已失南梅早，仍憂北枳遷。", "蔭雲今讓棘，生淤此饒蓮。", "鈿轂排朝露，雕欄悵夜天。", "馱金會見斸，無事苦憔妍。"]'),
('2cc35b99-5507-4da7-87b0-db344bba17dc','送無錫主簿王庾','宋祁','宋','宋诗','song-poetry','','[]','莫嘆東南遠，須榮試吏才。',72,'全唐诗/poet.song.12000.json','["莫嘆東南遠，須榮試吏才。", "客從梁苑至，家侍太邱來。", "木脫洲程迥，風長櫓意催。", "蟬知疁稻熟，鰌記海潮回。", "訟矢間鄉犴，糖螯佐壽杯。", "牛刀宜自愛，無及武城咍。"]'),
('36b62e67-3e3c-4f6e-9dc5-8c0c161e9c6c','兄長有計省之命','宋祁','宋','宋诗','song-poetry','','[]','長簡蓬山藏，婆娑試滿年。',96,'全唐诗/poet.song.12000.json','["長簡蓬山藏，婆娑試滿年。", "頻書對命笏，長負出休錢。", "運復光華旦，恩回咫尺天。", "罷披窮石訴，入佐計臺員。", "近對塗丹密，相趨委佩聯。", "太官供餌美，三服賜袍鮮。", "平進真如砥，孤飛舊惡弦。", "猶勝廣文客，摧擿獵塵編。"]'),
('666501b7-44f8-413e-8bbc-2f866c1eb783','昭文王相公出鎮青社','宋祁','宋','宋诗','song-poetry','','[]','西漢無雙彥，中興第一流。',288,'全唐诗/poet.song.12000.json','["西漢無雙彥，中興第一流。", "二篇應商夢，七聖首軒游。", "昔會光華旦，時當物色求。", "從容賜官筆，都穆潤緹油。", "芝押兼泥熟，鼇峰駕浪浮。", "捫天陪累䃭，敲鼎識掊鉤。", "帝欲中階正，公參九廟謀。", "危言天下事，坐勝幄中籌。", "斤斤宣嘉績，巖巖樹壯猷。", "異時思大冶，此日詠崇邱。", "承弼圖勳盛，蕃宣席寵優。", "均勞九州伯，重序富民侯。", "真廟方憑几，祗宮奉委裘。", "扶天八柱正，披日五雲收。", "堯后除凶代，周王訪落秋。", "盡歸千里馬，無復少陽牛。", "熙縡官咸事，端朝茹不柔。", "兜烽閒塞警，財餌撫夷酋。", "再侍欽柴祭，仍賡築瓠謳。", "奉承湯恤祀，力贊禹勤溝。", "國頼蕭公畫，言無趙孟偷。", "深恩及行葦，和氣藹鳴球。", "幾欲辭名遂，何嘗爲智憂。", "屢居移病苦，連賜上尊醅。"]'),
('3ea96094-7f75-4746-bc31-87e9313c1fc2','應詔內苑牡丹三首 千葉','宋祁','宋','宋诗','song-poetry','','[]','一豫凝皇覽，千英薦瑞葩。',72,'全唐诗/poet.song.12000.json','["一豫凝皇覽，千英薦瑞葩。", "壓枝高下錦，斜蕊淺深霞。", "疊采晞陽媚，鮮苞照露斜。", "九莖休衒葉，五出浪言花。", "郁郁雲柯覆，蔥蔥氣瓣嘉。", "羣心識天意，成數佐皇家。"]'),
('0e7788dc-2a37-42ed-9f69-590484b97223','應詔內苑牡丹三首 雙頭','宋祁','宋','宋诗','song-poetry','','[]','化工憑協氣，花品效尤祥。',72,'全唐诗/poet.song.12000.json','["化工憑協氣，花品效尤祥。", "旖旎雙苞豔，氤氳一種香。", "參差迎夕露，左右傃朝陽。", "有意同緗幹，無言並絳房。", "萬靈天會帝，三月史書王。", "故此呈繁卉，還將助樂康。"]'),
('0dbfd1ca-5711-4f80-8d74-5517c8822c8a','應詔內苑牡丹三首 三花','宋祁','宋','宋诗','song-poetry','','[]','九城蕃瑞殖，三山儼英蕤。',72,'全唐诗/poet.song.12000.json','["九城蕃瑞殖，三山儼英蕤。", "巽采昭天造，同心奉帝嬉。", "繁疑交晝影，重欲亞晴枝。", "恩露方均泫，王風亦徧吹。", "併柯由內附，紛豔表重熙。", "幸覿由庚瑞，慚陪可嬉嗣。"]'),
('ab394f86-a9f5-4beb-a312-e672d98a98cb','皇太子誕慶','宋祁','宋','宋诗','song-poetry','','[]','軒祏深叢祐，文支此挺生。',96,'全唐诗/poet.song.12000.json','["軒祏深叢祐，文支此挺生。", "重輪當月滿，一索應乾成。", "瑞瓞昌綿緒，天弧仗左檠。", "海雖分幼潤，星已慶前名。", "緩带羣心洽，吹銅順氣迎。", "歡觴交秘幄，曲赦徧離京。", "漢祝昭禖貺，周篇記路聲。", "從茲詒翼永，斯萬見承平。"]'),
('74fd54e8-464a-4a24-9e7d-9a94a0c79c6d','皇子封建詩','宋祁','宋','宋诗','song-poetry','','[]','晬表歧姿茂，皇基慶祚融。',96,'全唐诗/poet.song.12000.json','["晬表歧姿茂，皇基慶祚融。", "玉圭先啟國，銀榜後題宮。", "茅襲封壇舊，金頒瑞節雄。", "恩添少海潤，歡激小山風。", "抱拜殊藏紐，敭言異戲桐。", "燕詒光祖烈，調護切宸衷。", "育德吾君子，庸親天下公。", "異時瞻出閣，綿瓞頌無窮。"]'),
('1cff1d10-b802-47c2-a79e-4e2b1ac696d5','寄獻揚州','宋祁','宋','宋诗','song-poetry','','[]','平昔懷親友，銷魂重遠辭。',72,'全唐诗/poet.song.12000.json','["平昔懷親友，銷魂重遠辭。", "于今急難地，那復別離時。", "脫木乾坤晚，窮途日月衰。", "憂餘曾得恤，涅罷返無緇。", "楚分多連澤，淮居止雜夷。", "持罇相望意，不減見瓊枝。"]'),
('aecbe478-035f-4449-9a5c-3d1eb0616ffb','對白髮自感寄揚州','宋祁','宋','宋诗','song-poetry','','[]','四十還添四，顛華鑷更新。',72,'全唐诗/poet.song.12000.json','["四十還添四，顛華鑷更新。", "應從多病日，遂作始衰人。", "毀積方銷骨，經窮先腐脣。", "竟誰憐種種，由此到諄諄。", "軒冕間關路，風波蹭蹬身。", "兄今又過二，何術耐蕭辰。"]'),
('7e0ab41a-f260-4a03-b3bb-72c2d2379e0c','憶舊言懷寄江寧道卿龍圖','宋祁','宋','宋诗','song-poetry','','[]','下蔡行差近，金陵路更東。',288,'全唐诗/poet.song.12000.json','["下蔡行差近，金陵路更東。", "忉忉成念遠，咄咄但書空。", "恩厚容藏疾，時亨遂諱窮。", "祿慚千石守，老謝一錢翁。", "憶昨趨陪日，仍緣班序同。", "我生真寡合，君量自旁通。", "散袠疑皆瑩，忘疲宴屢終。", "聯驂屬車後，數會未央中。", "禁樹排頭碧，衙旗曳尾紅。", "籠街接騶士，賜管鏤宮工。", "慈豆分堯箑，歌雲識沛風。", "斯文誠有屬，吾道豈常隆。", "泰市俄驚虎，鈞天亟駭熊。", "塵埃忽蒙自，桃李併來蟲。", "箕次橫長舌，飈輪走轉蓬。", "歇芳間鷤鴂，禦溼問芎藭。", "可笑矜疏節，私憐抱朴忠。", "望霄嗟墜雨，歛翼避虛弓。", "尚忝銀符密，貪誇隼旆雄。", "玉魚供晝啜，珠米報秋豐。", "病久衰還早，身閒意愈沖。", "虧全從月蚌，喜怒任狙公。", "急景沉歡緒，長波隔訊筒。", "南飛俱似鵻，北嚮未如鴻。"]'),
('21194aae-a063-422e-89ab-042dad7c2d5e','晚秋西園','宋祁','宋','宋诗','song-poetry','','[]','西園來最數，要是使君閒。',72,'全唐诗/poet.song.12000.json','["西園來最數，要是使君閒。", "塢有常眠石，臺無未識山。", "池光兼日動，楓影带林殷。", "鳥沒蒼茫外，天垂摇落閒。", "歸雲高杳杳，晚菊正斑斑。", "幸有齋中熟，無嫌向晦還。"]'),
('df47fc0a-b4a9-4636-aef0-7dd189bb5577','登清思堂寫望','宋祁','宋','宋诗','song-poetry','','[]','迢遞陟城隅，飛軒浩氣扶。',96,'全唐诗/poet.song.12000.json','["迢遞陟城隅，飛軒浩氣扶。", "春容來迥野，天脚入平蕪。", "暖吹時披拂，晴煙乍有無。", "耨痕經雨徧，村逕值林迂。", "長庌初休馬，荒陴稍集烏。", "水生蒲澤滿，林缺弩臺孤。", "客思紛難泊，愁襟愧自拘。", "久之成悵望，西北認皇都。"]'),
('241f53fc-1a9d-441a-9b3f-9d6fdd16ac5e','喜翟穎先輩至有感','宋祁','宋','宋诗','song-poetry','','[]','門下客逾落，胡爲君見從。',96,'全唐诗/poet.song.12000.json','["門下客逾落，胡爲君見從。", "墜餘仍顧甑，寒罷始知松。", "休計流光邁，聊欣此地逢。", "已甘漂似梗，寧止啞如鐘。", "仕路惟希退，鄉評幸見容。", "病偷它日壯，衰作長年慵。", "世態同波蕩，交情敵酒濃。", "好堅歸去約，相伴老三封。"]'),
('d6193d3d-4c64-4f36-aea6-278996b16d75','舒雁','宋祁','宋','宋诗','song-poetry','','[]','莊周悲殺雁，本爲不能鳴。',24,'全唐诗/poet.song.12000.json','["莊周悲殺雁，本爲不能鳴。", "寧識山陰誤，能鳴亦就烹。"]'),
('16158630-93d4-403e-8092-64f0c5ef1c35','游魚','宋祁','宋','宋诗','song-poetry','','[]','游魚川上樂，映藻復依蒲。',24,'全唐诗/poet.song.12000.json','["游魚川上樂，映藻復依蒲。", "須防裁密網，莫獨畏鵜鶘。"]'),
('8173fb73-7adf-468c-a5a0-a7b330bf1efa','驚鷗','宋祁','宋','宋诗','song-poetry','','[]','漁拽亂溪來，白鷗驚已屢。',24,'全唐诗/poet.song.12000.json','["漁拽亂溪來，白鷗驚已屢。", "不應畏機心，却下滄波去。"]'),
('6e07d11b-bbfd-406b-862c-8b9494800da3','題挽鄧亭','宋祁','宋','宋诗','song-poetry','','[]','鄧守挽不住，眷予番久留。',24,'全唐诗/poet.song.12000.json','["鄧守挽不住，眷予番久留。", "决非人所挽，胡不理歸舟。"]'),
('2e241b56-fac3-4265-81b0-e13a7d100cc9','酒胡','宋祁','宋','宋诗','song-poetry','','[]','誰刻優胡象，來爲飲席珍。',24,'全唐诗/poet.song.12000.json','["誰刻優胡象，來爲飲席珍。", "不因君屨指，幾作獨醒人。"]'),
('589a0c91-c820-414f-a7cc-44a97ab9486d','觀舞','宋祁','宋','宋诗','song-poetry','','[]','蝶躞趁繁會，婆娑無定妍。',24,'全唐诗/poet.song.12000.json','["蝶躞趁繁會，婆娑無定妍。", "心知吾地廣，長袖得回旋。"]'),
('0a3687ba-1105-409c-9224-ab838bdd8171','晚夏西園二首  其一','宋祁','宋','宋诗','song-poetry','','[]','道樾陰陰密，畦泉活活流。',24,'全唐诗/poet.song.12000.json','["道樾陰陰密，畦泉活活流。", "梨成津向潤，瓜熟子相鉤。"]'),
('f73d3a74-5458-4b08-beda-5bd6a669833c','晚夏西園二首  其二','宋祁','宋','宋诗','song-poetry','','[]','日晏坐中園，清襟注迥軒。',24,'全唐诗/poet.song.12000.json','["日晏坐中園，清襟注迥軒。", "輕飈逢葉動，小雨得荷喧。"]'),
('87ad3d5d-b18a-441b-bf54-24d6c881dc2a','過淝口二首  其一','宋祁','宋','宋诗','song-poetry','','[]','淝水縈如带，淮山崒似雲。',24,'全唐诗/poet.song.12000.json','["淝水縈如带，淮山崒似雲。", "此時聞鶴唳，無復畏官軍。"]'),
('13977c5e-9ed0-4059-a25d-4dd89ce319bb','過淝口二首  其二','宋祁','宋','宋诗','song-poetry','','[]','氐醜矜凶甚，臨流列萬幢。',24,'全唐诗/poet.song.12000.json','["氐醜矜凶甚，臨流列萬幢。", "由來不自項，何荷欲浮江。"]'),
('e9a148e3-ac36-412f-a891-18757dc29c16','直舍讎理律書呈同舍二首  其一','宋祁','宋','宋诗','song-poetry','','[]','舊文新札儼成行，柏燻微開帙氣香。',32,'全唐诗/poet.song.12000.json','["舊文新札儼成行，柏燻微開帙氣香。", "天下書多殊未見，顔生應笑下雌黄。"]'),
('e8dc96fa-0bc0-46be-8799-09a1d3fb8964','直舍讎理律書呈同舍二首  其二','宋祁','宋','宋诗','song-poetry','','[]','經筵敢倦力刊梓，國典將追鼎鑄書。',32,'全唐诗/poet.song.12000.json','["經筵敢倦力刊梓，國典將追鼎鑄書。", "靜對闕疑還閣筆，不知三古字爲魚。"]'),
('56b11e67-d131-410c-8cd0-2a20903d1ca9','月中嘲鵲','宋祁','宋','宋诗','song-poetry','','[]','月馭初明露掌西，翩翩猶伴夜烏啼。',32,'全唐诗/poet.song.12000.json','["月馭初明露掌西，翩翩猶伴夜烏啼。", "駕巢樹冷空三帀，却是鳴鳩得穩棲。"]'),
('216c3065-4683-422d-b73e-9f036197b65c','賦成中丞臨川侍郎西園雜題十首 雙假山','宋祁','宋','宋诗','song-poetry','','[]','佛螺雙髻矗層嵐，雲穴呀空蘚暈銜。',32,'全唐诗/poet.song.12000.json','["佛螺雙髻矗層嵐，雲穴呀空蘚暈銜。", "異日主公求肖像，居然認得傅溪巖。"]'),
('1f7e6afd-a960-476a-8a74-4c3b334b113e','賦成中丞臨川侍郎西園雜題十首 煙竹','宋祁','宋','宋诗','song-poetry','','[]','煙梢露葉貫冬榮，高出危牆近覆亭。',32,'全唐诗/poet.song.12000.json','["煙梢露葉貫冬榮，高出危牆近覆亭。", "聞道蘭臺有圖籍，故留春粉助蒸青。"]'),
('37a306b1-1edb-4673-ad61-4c83f2f28bd3','賦成中丞臨川侍郎西園雜題十首 牡丹','宋祁','宋','宋诗','song-poetry','','[]','上國名園買地栽，試知韓令是雄猜。',32,'全唐诗/poet.song.12000.json','["上國名園買地栽，試知韓令是雄猜。", "香根斸盡成何事，不識騷人託諷才。"]'),
('af68fafa-8ad0-4445-9a1f-5657e21a1cca','賦成中丞臨川侍郎西園雜題十首 酴醾架','宋祁','宋','宋诗','song-poetry','','[]','媚條無力倚風長，架作圓陰覆坐凉。',32,'全唐诗/poet.song.12000.json','["媚條無力倚風長，架作圓陰覆坐凉。", "露蘂一春清襲袂，有人知是令君香。"]'),
('1df67f51-cc57-4272-a961-83d7d7b810d0','賦成中丞臨川侍郎西園雜題十首 柳','宋祁','宋','宋诗','song-poetry','','[]','散漫飛綿阿娜枝，家家眺賞霽霜威。',32,'全唐诗/poet.song.12000.json','["散漫飛綿阿娜枝，家家眺賞霽霜威。", "盡將煙葉偷眉嫵，不爲章街走馬歸。"]'),
('decd4ff4-6d4e-4031-89e5-bcc9737a3d47','賦成中丞臨川侍郎西園雜題十首 射堋','宋祁','宋','宋诗','song-poetry','','[]','棲鵠雲侯迥勢開，主人留客侑金罍。',32,'全唐诗/poet.song.12000.json','["棲鵠雲侯迥勢開，主人留客侑金罍。", "欲知謝尚風流極，賭得將軍鼓吹來。"]'),
('01f13d87-276c-419e-84ff-2c7e30aa73f9','房陵舊第股引蔡水養魚於池敗日或有塞其水竇魚多涸矣','宋祁','宋','宋诗','song-poetry','','[]','後園平日引春渠，浴鳳翔鴛兩自如。',32,'全唐诗/poet.song.12000.json','["後園平日引春渠，浴鳳翔鴛兩自如。", "一旦繡衣來簿責，餘災猶得及池魚。"]'),
('e3c4db85-ae1b-498a-a7a5-64fba4cdff7b','偶作','宋祁','宋','宋诗','song-poetry','','[]','隼被鷃姿知有累，豺驚羊質固非真。',32,'全唐诗/poet.song.12000.json','["隼被鷃姿知有累，豺驚羊質固非真。", "謾誇魯國多儒士，敢到君門止一人。"]'),
