('06456763-edad-4d62-96a7-e6f42e1a37a7','曲水園','賈昌朝','宋','宋诗','song-poetry','','[]','畫船載酒及芳辰，丞相園林潩水濱。',32,'全唐诗/poet.song.12000.json','["畫船載酒及芳辰，丞相園林潩水濱。", "虎節麟符拋不得，却將清景付閑人。"]'),
('26e31b53-de81-4451-b2e9-b32fd11aae39','詠凌霄花','賈昌朝','宋','宋诗','song-poetry','','[]','披雲似有凌霄志，向日寧無捧日心。',32,'全唐诗/poet.song.12000.json','["披雲似有凌霄志，向日寧無捧日心。", "珍重青松好依托，直從平地起千尋。"]'),
('6a0fb277-fe97-4597-a6ce-b6b66d753471','繁城魏受禪臺','賈昌朝','宋','宋诗','song-poetry','','[]','服殷自古稱文王，幾見符膺把紂亡。',32,'全唐诗/poet.song.12000.json','["服殷自古稱文王，幾見符膺把紂亡。", "誰謂老奸亟篡事，禪臺空立在繁昌。"]'),
('67f7e791-84a3-430d-8bcb-11877f4170af','句','賈昌朝','宋','宋诗','song-poetry','','[]','坐憶蛟橋此日新。',8,'全唐诗/poet.song.12000.json','["坐憶蛟橋此日新。"]'),
('f71e26c6-2a34-4050-a323-011fe8a13e73','題招提院靜照堂','閻詢','宋','宋诗','song-poetry','','[]','浙右僧居盛，虛堂葺有功。',48,'全唐诗/poet.song.12000.json','["浙右僧居盛，虛堂葺有功。", "迷來隨萬化，凈後照三空。", "夜永松軒月，秋深竹岸風。", "我心閑已久，夢到水鄉中。"]'),
('4a288e33-e388-445c-b40c-bf90186838b8','興慶池禊宴','劉渙','宋','宋诗','song-poetry','','[]','清明佳節屬良辰，行樂東郊宴席賓。',64,'全唐诗/poet.song.12000.json','["清明佳節屬良辰，行樂東郊宴席賓。", "風柳不勝春氣力，露花無奈曉精神。", "管絲遠近青堤上，樓閣高低淥水濱。", "多少艤舟何所用，府公便是濟川人。"]'),
('00d91e84-5ea4-4a5a-882b-472e4b78c97f','句','崔暨','宋','宋诗','song-poetry','','[]','居占梅仙里。',6,'全唐诗/poet.song.12000.json','["居占梅仙里。"]'),
('3a278e01-4afb-46ab-aa53-c66d757f8e2f','宜春臺','劉嗣隆','宋','宋诗','song-poetry','','[]','一簇亭臺畫亦難，公餘到此暫盤桓。',64,'全唐诗/poet.song.12000.json','["一簇亭臺畫亦難，公餘到此暫盤桓。", "山多不似城中景，樹密偏宜雨後看。", "風送江聲穿郡郭，日推雲影下峰巒。", "當時吏部曾遊否，何事無文石上刊。"]'),
('7d2cba73-50b8-4e7f-a0b6-269da5751a1e','玉兔凈居詩','張仲尹','宋','宋诗','song-poetry','','[]','何事回真館，標名作凈坊。',120,'全唐诗/poet.song.12000.json','["何事回真館，標名作凈坊。", "金園存廢趾，玉兔效殊祥。", "躍漢勞罝網，環山瑩雪霜。", "來疑崑岫出，去訝月輪藏。", "隠顯經千載，薰修蔭一方。", "寶壇隳道祖，華榜耀空王。", "奧域居全晉，靈祠接慶唐。", "煙霞生四面，樓殿起中央。", "暎日杉陰合，飄空磬韵長。", "伊余聞勝槩，寧惜寄篇章。"]'),
('22aee0b1-5432-4ea7-b2bd-3a9e212e446c','句','李略','宋','宋诗','song-poetry','','[]','此身若得西歸去，猶勝開籠放雀兒。',16,'全唐诗/poet.song.12000.json','["此身若得西歸去，猶勝開籠放雀兒。"]'),
('670f2c03-c6f9-42d3-b861-c9afef130af3','存目','李略','宋','宋诗','song-poetry','','[]','詩題：嬉遊首句：我身豈比狂遊輩。',16,'全唐诗/poet.song.12000.json','["詩題：嬉遊首句：我身豈比狂遊輩。"]'),
('68c4dfab-ac6a-42ce-b20a-f619225e1cfd','縣齋十詠 思齊樓','寧參','宋','宋诗','song-poetry','','[]','高閈營層構，翬飛勢自伸。',48,'全唐诗/poet.song.12000.json','["高閈營層構，翬飛勢自伸。", "已聞能賦客，空憶带星人。", "彫檻凭秋迥，朱扉敞漢新。", "龜趺清刻在，誰共繼芳塵。"]'),
('a4692e61-efdd-4ab0-97b1-93133b71d156','縣齋十詠 永益池','寧參','宋','宋诗','song-poetry','','[]','唐賢遺勝地，天澤引初深。',48,'全唐诗/poet.song.12000.json','["唐賢遺勝地，天澤引初深。", "未起朝宗勢，先資濟衆心。", "凈惟涵寶剎，微或鄙蹄涔。", "爽氣何偏早，羣蛙一夜沉。"]'),
('27d393f2-8743-47b0-9c0c-0e57c9bf6693','縣齋十詠 惟勤閣','寧參','宋','宋诗','song-poetry','','[]','自責思前古，徒名是永懷。',48,'全唐诗/poet.song.12000.json','["自責思前古，徒名是永懷。", "善聲慚偃室，幽興類蕭齋。", "未報投虛刃，空防肆毒材。", "恪居知有地，僶俛競相諧。"]'),
('3f9d2900-5514-4e9c-babf-db1a63aca1ac','縣齋十詠 藏書閣署羣籍也','寧參','宋','宋诗','song-poetry','','[]','洞闢前軒峻，危梯趣若何。',48,'全唐诗/poet.song.12000.json','["洞闢前軒峻，危梯趣若何。", "綠苔生未遍，縹帙聚還多。", "曉幌吞清旭，秋欄拂靜柯。", "猶憐鉛筆在，公外獨頻過。"]'),
('ca82451c-8dd0-4f7f-8cbf-b84ec92072e8','縣齋十詠 習射亭','寧參','宋','宋诗','song-poetry','','[]','危亭當旅進，飛鏑共星鳴。',48,'全唐诗/poet.song.12000.json','["危亭當旅進，飛鏑共星鳴。", "才奏蘋蘩節，空聞霹靂聲。", "澤宮期並勝，相圃憶偕行。", "敏手無虛發，由來已鵠平。"]'),
('273b0441-a607-469d-b5b1-fa15c1860b33','縣齋十詠 古植槐','寧參','宋','宋诗','song-poetry','','[]','誰知深固久，根怪蟄龍形。',48,'全唐诗/poet.song.12000.json','["誰知深固久，根怪蟄龍形。", "自著三冬市，空懷八命庭。", "餘清蟬始噪，茂綠雨初經。", "未便慚羣木，猶憐桂有馨。"]'),
('4755122c-26c3-4efc-b908-310249a791e2','縣齋十詠 載榮桐','寧參','宋','宋诗','song-poetry','','[]','幾年惟悴質，一旦類生稊。',48,'全唐诗/poet.song.12000.json','["幾年惟悴質，一旦類生稊。", "玉甃青初滿，銀牀綠乍齊。", "雅勝玄雨潤，高稱嶧陽低。", "況有蒼姬葉，還當副剪圭。"]'),
('53bc04ce-71f7-4fec-bc03-a93c50845f5a','縣齋十詠 小庭松','寧參','宋','宋诗','song-poetry','','[]','挺質依雕檻，盤根似舊峰。',48,'全唐诗/poet.song.12000.json','["挺質依雕檻，盤根似舊峰。", "美材高並接，强榦直相容。", "度夕寒聲細，凌秋翠影重。", "當軒何鬰鬰，應只待秦封。"]'),
('d46ff916-54ce-46b3-9993-8a746c1bba32','縣齋十詠 波紋石','寧參','宋','宋诗','song-poetry','','[]','何必觀春渚，他山質自奇。',48,'全唐诗/poet.song.12000.json','["何必觀春渚，他山質自奇。", "危層分蕩漾，峭碧認逶迤。", "禁陛宜相接，星機好共支。", "高空如有闕，一補未爲遲。"]'),
('92b0c0ca-7255-44f5-a62e-44b6a4a4b4ef','縣齋十詠 石席','寧參','宋','宋诗','song-poetry','','[]','結粹從天匠，周方出翠巒。',48,'全唐诗/poet.song.12000.json','["結粹從天匠，周方出翠巒。", "寧知磨琢易，須信卷舒難。", "角枕清同置，藜床雅並觀。", "公餘聊偃息，空覺病膚寒。"]'),
('3096929a-5d14-4482-b28d-62283b38acda','春集東園詩','楊儀','宋','宋诗','song-poetry','','[]','芳節未晼晚，名園好澄霽。',72,'全唐诗/poet.song.12000.json','["芳節未晼晚，名園好澄霽。", "停車沒徑苔，移席傍叢筀。", "蝶粉留紅房，蜂鬚抱香蔕。", "微波生酒杯，輕吹拂衣袂。", "何當名教樂，況復昌時世。", "歸鞍惜餘歡，陽鳥不可繫。"]'),
('2ae7b081-12ba-4962-a2cd-403e4e2f06e0','句  其一','施元長','宋','宋诗','song-poetry','','[]','我觀招提境，古檜何蒼奇。',24,'全唐诗/poet.song.12000.json','["我觀招提境，古檜何蒼奇。", "白蟻巢其根，青虬嚙其枝。"]'),
('04f616d2-9c58-4c9b-be0f-45efab85f8e0','句  其二','施元長','宋','宋诗','song-poetry','','[]','寖歷歲年久，靡受霜雪欺。',36,'全唐诗/poet.song.12000.json','["寖歷歲年久，靡受霜雪欺。", "落落梁棟材，矯矯松柏姿。", "明當構廊廟，匠石良汝資。"]'),
('e3883a6b-ab6b-4924-a58c-969c6a37d8fe','謝梵才惠茶','石待舉','宋','宋诗','song-poetry','','[]','郡園名荈製猶新，分惠眠雲跂石人。',64,'全唐诗/poet.song.12000.json','["郡園名荈製猶新，分惠眠雲跂石人。", "色鬭瓊瑶因地勝，香殊蘭茝得天真。", "開時好對稜稜月，碾處應飛瑟瑟塵。", "寄語高僧宜鄭重，能詩方遣雨前春。"]'),
('3fc94dd1-ff80-4292-a4f2-2b965cf745b2','贈王山人','熊知至','宋','宋诗','song-poetry','','[]','閑拄瘦筇枝，衣冠半異時。',48,'全唐诗/poet.song.12000.json','["閑拄瘦筇枝，衣冠半異時。", "入城人不識，賣藥俗長疑。", "飲酒難逢醉，餐松自止饑。", "華峰千嶂裏，常與白雲期。"]'),
('f1a50096-04ec-4358-9705-b88b9a27182f','句  其一','熊知至','宋','宋诗','song-poetry','','[]','岸上猶哀懼，舟中爭得安。',12,'全唐诗/poet.song.12000.json','["岸上猶哀懼，舟中爭得安。"]'),
('cd5ccc24-2a82-45a5-8b75-a2cd5355c59d','句  其二','熊知至','宋','宋诗','song-poetry','','[]','樓臺上下火照火，車馬往來人看人。',16,'全唐诗/poet.song.12000.json','["樓臺上下火照火，車馬往來人看人。"]'),
('21e80ac4-5a8a-427f-b671-fce353170b01','詩二首  其一','余翼','宋','宋诗','song-poetry','','[]','偶閒如到女媧天，深入何殊葛稚川。',32,'全唐诗/poet.song.12000.json','["偶閒如到女媧天，深入何殊葛稚川。", "何必東山隨謝守，盡遊終日恣陶然。"]'),
('9412008b-e143-4771-9a8a-ed453ba282aa','詩二首  其二','余翼','宋','宋诗','song-poetry','','[]','□幾□□□□□，□□依舊向陽開。',32,'全唐诗/poet.song.12000.json','["□幾□□□□□，□□依舊向陽開。", "神僊究竟歸何處，駐馬多時望不回。"]'),
('510cd921-8e5e-4ed6-8b32-2741d947e392','送僧','釋可士','宋','宋诗','song-poetry','','[]','一鉢即生涯，隨緣度歲華。',48,'全唐诗/poet.song.12000.json','["一鉢即生涯，隨緣度歲華。", "是山皆有寺，何處不爲家。", "笠重吳天雪，鞋香楚地花。", "他年訪禪室，寧憚路岐賒。"]'),
('2ae815ea-4129-4686-a361-6e3cd6f93060','句','釋惟慎','宋','宋诗','song-poetry','','[]','敢言知己少，性本類孤雲。',12,'全唐诗/poet.song.12000.json','["敢言知己少，性本類孤雲。"]'),
('153a4669-1696-4d53-9f55-2ba8e270a9b0','知足','濮肅','宋','宋诗','song-poetry','','[]','知足自不辱，古人乃患辱。',36,'全唐诗/poet.song.12000.json','["知足自不辱，古人乃患辱。", "但安童叟嬉，寧與紛華觸。", "白日一卷書，興來還秉燭。"]'),
('aadaf6b7-70cc-4b81-a3e8-d6a2878060e3','述懷','濮肅','宋','宋诗','song-poetry','','[]','人生天地間，自顧一何小。',48,'全唐诗/poet.song.12000.json','["人生天地間，自顧一何小。", "寧同避釣魚，敢學驚弓鳥。", "物理自悠悠，世情多擾擾。", "桃源眼底是，何必尋雲表。"]'),
('d875f714-9db4-4d3b-a27e-331912fc296e','詩三首  其一','李氏','宋','宋诗','song-poetry','','[]','囊裏真香誰見竊，鮫綃滴血染成紅。',32,'全唐诗/poet.song.12000.json','["囊裏真香誰見竊，鮫綃滴血染成紅。", "殷勤遺下輕綃意，好與才郎懷袖中。"]'),
('2605e10c-545b-4ecd-a42b-7af80a15c3e1','詩三首  其二','李氏','宋','宋诗','song-poetry','','[]','金珠富貴吾家事，常渴佳期乃寂寥。',32,'全唐诗/poet.song.12000.json','["金珠富貴吾家事，常渴佳期乃寂寥。", "偶用至誠求雅合，良媒未必勝紅綃。"]'),
('c43f250e-5d5a-4c89-b498-0fb6941ff168','詩三首  其三','李氏','宋','宋诗','song-poetry','','[]','門前畫戟尋常設，堂上犀簪取次看。',32,'全唐诗/poet.song.12000.json','["門前畫戟尋常設，堂上犀簪取次看。", "最是惱人情亂處，鳳凰樓上月華寒。"]'),
('997e93e2-9413-4042-b5b2-177b4c6397b5','書紅帕','李氏','宋','宋诗','song-poetry','','[]','囊香著郎衣，經綃著郎手。',24,'全唐诗/poet.song.12000.json','["囊香著郎衣，經綃著郎手。", "此意不及綃，共郎永長久。"]'),
('cb3c7b21-cd6f-4421-8064-043928a023fb','和遺綃女子  其一','張資','宋','宋诗','song-poetry','','[]','濃麝應同瓊體織，輕綃料比杏腮紅。',32,'全唐诗/poet.song.12000.json','["濃麝應同瓊體織，輕綃料比杏腮紅。", "雖然未近來春約，已勝襄王魂夢中。"]'),
('71c509c0-872d-4244-b102-1ab419cc6c14','和遺綃女子  其二','張資','宋','宋诗','song-poetry','','[]','自得佳人遺贈物，書窗終自獨無寥。',32,'全唐诗/poet.song.12000.json','["自得佳人遺贈物，書窗終自獨無寥。", "未能得會真仙面，時賞香囊與絳綃。"]'),
('31ff3756-d7de-40c2-8883-0d84c33062a6','應約訪遺綃女子','張資','宋','宋诗','song-poetry','','[]','何人遺下一紅綃，暗遣情懷意氣饒。',64,'全唐诗/poet.song.12000.json','["何人遺下一紅綃，暗遣情懷意氣饒。", "勒馬住時金𩍐脫，亞身親用寶燈挑。", "輕輕滴滴深深染，慢慢尋尋緊緊□。", "料想佳人初失却，幾回纖手摸裙腰。"]'),
('b883a68d-0403-489b-a246-a19d55a3f6f1','和遺綃女子','張資','宋','宋诗','song-poetry','','[]','香來著吾懷，先想纖纖手。',24,'全唐诗/poet.song.12000.json','["香來著吾懷，先想纖纖手。", "果遇贈香人，經年何恨久。"]'),
('3c1f755f-b359-4bcd-8ede-8c2259223f4a','過黄花渡','姜迪','宋','宋诗','song-poetry','','[]','回首瀟湘二十春，江南投老未安身。',32,'全唐诗/poet.song.12000.json','["回首瀟湘二十春，江南投老未安身。", "如今再過黄花渡，遥想湘山是故人。"]'),
('87921bc5-ae23-463c-993c-72e4830481af','澄心軒','丁天錫','宋','宋诗','song-poetry','','[]','高館含秋溪水平，白雲一榻臨空清。',96,'全唐诗/poet.song.12000.json','["高館含秋溪水平，白雲一榻臨空清。", "雲影天光入懷抱，玉樓銀闕無人行。", "滔滔活水源頭落，却笑奔流爭萬壑。", "雪照梅檐坐月明，露瀉荷盤見魚躍。", "長安車馬多富兒，汗流浹背塵滿衣。", "誰識君心有真樂，沙頭白鳥猶忘機。"]'),
('c31130eb-823c-49db-8782-038f7d2803bf','夏晝','章望之','宋','宋诗','song-poetry','','[]','一日常百刻，轉若車輪忙。',144,'全唐诗/poet.song.12000.json','["一日常百刻，轉若車輪忙。", "千日十萬刻，百年能幾長。", "達人齊古今，一生甚微茫。", "夏日豈爲永，而足以較量。", "人世不足惜，行善乃自彰。", "無及閑暇時，般樂爲淫荒。", "夷齊餓人者，顔閔非公王。", "其人品孰亞，周氏與虞唐。", "亦用仁義積，豈今身未亡。", "富貴無可恃，莫與公道强。", "夜思晝以力，四序皆流光。", "示君夏晝誦，惕惕其自傷。"]'),
('0a79ebf0-90b6-4825-9769-5678a0caa0da','和陳述古仙居巖老堂詩','章望之','宋','宋诗','song-poetry','','[]','巖前未老客，期在老樵漁。',48,'全唐诗/poet.song.12000.json','["巖前未老客，期在老樵漁。", "撫俗多閒暇，開軒適起居。", "讀詩明治亂，學易體盈虛。", "頻許相從否，吾將當故廬。"]'),
('29bcbb95-d211-483b-8b05-0078aff19a9b','一人泉','章望之','宋','宋诗','song-poetry','','[]','一人泉在此山顛，萬人可飲聞舊言。',32,'全唐诗/poet.song.12000.json','["一人泉在此山顛，萬人可飲聞舊言。", "顧我無人試此水，盛夏獨飲南風前。"]'),
('8589b85d-1182-45ce-a50a-fee7d70879b2','明智寺','章望之','宋','宋诗','song-poetry','','[]','重複青山裏，雙峰鎖寺門。',24,'全唐诗/poet.song.12000.json','["重複青山裏，雙峰鎖寺門。", "樓聳排雲閣，松盤過路根。"]'),
('84f77c32-63b8-466e-b23f-b7fcfe3e4b54','句','章望之','宋','宋诗','song-poetry','','[]','是水爲佳境，中城枕碧湖。',24,'全唐诗/poet.song.12000.json','["是水爲佳境，中城枕碧湖。", "樓臺萬室近，物象幾州無。"]'),
('f0d5ff58-ed21-4439-8978-ad6c595d5851','金山寺','蘇紳','宋','宋诗','song-poetry','','[]','九派分流涌化城，登臨潜覺骨毛清。',64,'全唐诗/poet.song.12000.json','["九派分流涌化城，登臨潜覺骨毛清。", "僧依玉鑑光中住，人踏金鰲背上行。", "鍾阜雲開春雨霽，海門雷吼夜潮生。", "因思絕頂高秋夜，四面雲濤浸月明。"]'),
('45b67193-0807-496e-aaa1-1127c75028e3','長生檜','蘇紳','宋','宋诗','song-poetry','','[]','幾年飛錫倦尋芳，雲衲斕斑掩竹房。',96,'全唐诗/poet.song.12000.json','["幾年飛錫倦尋芳，雲衲斕斑掩竹房。", "一榻夜禪蒲座穩，滿盂春供藥苗香。", "汲泉巖畔驚猿飲，裁葦池邊引鷺翔。", "像室霧昏燈焰小，石樓風度磐聲長。", "攀蘿別嶺衝寒霧，掃葉前林趁曉霜。", "大抵僧居遺俗慮，此中身世更清凉。"]'),
('7e22131c-ba49-433a-b104-2b3c1bba34c9','膠山寺','蘇紳','宋','宋诗','song-poetry','','[]','驅馬款禪扉，松風冷拂衣。',48,'全唐诗/poet.song.12000.json','["驅馬款禪扉，松風冷拂衣。", "紅塵不到處，青嶂此忘歸。", "鳥望生臺下，雲侵講座飛。", "楞伽味真趣，轉覺俗緣稀。"]'),
('7681d1af-eff7-4db5-9e9c-f6d350627056','惠山寺并簡竇公','蘇紳','宋','宋诗','song-poetry','','[]','綺塍行盡入松門，暫拂塵纓袖惹雲。',64,'全唐诗/poet.song.12000.json','["綺塍行盡入松門，暫拂塵纓袖惹雲。", "海月未升樓上見，湖波初起坐中聞。", "寶扉膜拜青蓮相，石案傍行白㲲紋。", "促榻偶隨居士語，煮茶燒栗到宵分。"]'),
('acee8cc7-5f3d-4ba2-b156-55df28bfc1cb','句  其一','蘇紳','宋','宋诗','song-poetry','','[]','游人漢女投珠路，野火荆山出獵朝。',16,'全唐诗/poet.song.12000.json','["游人漢女投珠路，野火荆山出獵朝。"]'),
('da28caa1-8564-419e-bb94-8d2284826862','句  其二','蘇紳','宋','宋诗','song-poetry','','[]','城郭依然鄖子國，山川分得楚王臺。',16,'全唐诗/poet.song.12000.json','["城郭依然鄖子國，山川分得楚王臺。"]'),
('3b52a928-9e01-4e87-975f-96dae2ee0c69','句  其三','蘇紳','宋','宋诗','song-poetry','','[]','一篇此日摛鴻藻，五色它年浴鳳文。',16,'全唐诗/poet.song.12000.json','["一篇此日摛鴻藻，五色它年浴鳳文。"]'),
('2938998c-c631-485e-99c4-2376125222d3','句  其四','蘇紳','宋','宋诗','song-poetry','','[]','它年躍馬相逢處，記得先生舊姓名。',16,'全唐诗/poet.song.12000.json','["它年躍馬相逢處，記得先生舊姓名。"]'),
('5d64d3dc-709c-4834-b502-83b1e02dd50f','負暄閑眠','仲訥','宋','宋诗','song-poetry','','[]','茅簷晴日暖於春，一枕鈞天樂事新。',32,'全唐诗/poet.song.12000.json','["茅簷晴日暖於春，一枕鈞天樂事新。", "滿眼繁花皆得意，午眠安穩却無人。"]'),
('926d6111-c7c5-4d72-ad07-758b9d9de5e7','送唐御史','仲訥','宋','宋诗','song-poetry','','[]','力犯雷霆衆共危，遠投魑魅獨爲宜。',64,'全唐诗/poet.song.12000.json','["力犯雷霆衆共危，遠投魑魅獨爲宜。", "忠州學業真無負，高廟神靈固有知。", "自倚聖明容直道，未甘憔悴死荒陲。", "滿朝卿相多公議，莫把文章作楚辭。"]'),
('33dcc450-88bd-466e-acc7-05a2c7a627b8','長橋  其一','張亢','宋','宋诗','song-poetry','','[]','雲收霧霽水風高，百丈虹橋氣勢豪。',32,'全唐诗/poet.song.12000.json','["雲收霧霽水風高，百丈虹橋氣勢豪。", "疑是玉龍藏爪距，潜來江上看波濤。"]'),
('2b62c3cd-e84d-4ca2-98bf-4f3de36201ab','長橋  其二','張亢','宋','宋诗','song-poetry','','[]','萬頃平湖水接天，湖光水色遠相連。',32,'全唐诗/poet.song.12000.json','["萬頃平湖水接天，湖光水色遠相連。", "虹蜺截雨未歸得，橫在波心幾十年。"]'),
('44332c3d-cef9-4751-9974-0867539199e5','長橋  其三','張亢','宋','宋诗','song-poetry','','[]','記得當年過此橋，月明江上暑風消。',32,'全唐诗/poet.song.12000.json','["記得當年過此橋，月明江上暑風消。", "而今重到經行處，空有湖光伴寂寥。"]'),
('49343070-28e1-44a9-9d38-04f0cbe066c3','句','張亢','宋','宋诗','song-poetry','','[]','張亢觸牆成八字，王琪望月叫三聲。',16,'全唐诗/poet.song.12000.json','["張亢觸牆成八字，王琪望月叫三聲。"]'),
('2320a93e-77f7-4c2a-8bc0-e1af988a7ad3','書端州郡齋壁','包拯','宋','宋诗','song-poetry','','[]','清心爲治本，直道是身謀。',48,'全唐诗/poet.song.12000.json','["清心爲治本，直道是身謀。", "秀幹終成棟，精鋼不作鈎。", "倉充鼠雀喜，草盡兔狐愁。", "史冊有遺訓，毋貽來者羞。"]'),
('6432d48b-01cd-4553-97a7-f491b5b11847','弔曹覲','曾公亮','宋','宋诗','song-poetry','','[]','款軍樵門日再晡，空弮猶自把戈鈇。',64,'全唐诗/poet.song.12000.json','["款軍樵門日再晡，空弮猶自把戈鈇。", "身垂虎口方安坐，命若鴻毛竟敗呼。", "柱下杲卿曾斷骨，袴中杵臼得遺孤。", "可憐三尺英雄氣，不怕山西士大夫。"]');
